// ---- ui.js ----
const uiSystem = {
  id: 'ui',
  owns: ['render scheduling', 'tooltips', 'modals', 'masonry layout', 'accessibility labels', 'device classes'],
  qualityRule: 'UI helpers may read simulation state but should not advance gameplay.'
};

function normalizeNativeTooltips(root = document) {
  root.querySelectorAll('[title]').forEach(el => {
    const value = el.getAttribute('title');
    if (!value) return;
    el.dataset.uiTip = el.dataset.uiTip || value;
    el.removeAttribute('title');
    if (!el.getAttribute('aria-label') && ['BUTTON', 'SELECT'].includes(el.tagName)) {
      el.setAttribute('aria-label', (el.textContent || el.value || value).trim().replace(/\s+/g, ' '));
    }
  });
}

function createRenderScheduler(renderers) {
  let lastActiveTab = '';
  let lastSecond = -1;
  return function schedule({ activeTab, time, dropdownActive }) {
    const activeChanged = activeTab !== lastActiveTab;
    const secondChanged = time !== lastSecond;
    lastActiveTab = activeTab;
    lastSecond = time;
    if (dropdownActive) return { fullTab: false, hud: true };
    if (activeChanged) return { fullTab: true, hud: true };
    if (['Military', 'Trade', 'Population'].includes(activeTab)) return { fullTab: false, hud: secondChanged };
    return { fullTab: true, hud: true };
  };
}


// ---- simulation.js ----
const simulationSystem = {
  id: 'simulation',
  owns: ['pacing harness', 'population milestone smoke tests', 'balance reports'],
  qualityRule: 'Simulation tests should be deterministic enough to compare milestones before and after balance changes.'
};

function createPacingHarness({ game, tick, snapshot, prepareMilestone }) {
  const milestones = [10, 50, 200, 500, 2000];
  return {
    milestones,
    run({ maxTicksPerMilestone = 20000 } = {}) {
      const results = [];
      for (const target of milestones) {
        if (prepareMilestone) prepareMilestone(target);
        let ticks = 0;
        while ((game.population || 0) < target && ticks < maxTicksPerMilestone) {
          tick();
          ticks++;
        }
        results.push({ target, reached: (game.population || 0) >= target, ticks, snapshot: snapshot ? snapshot() : null });
      }
      return results;
    }
  };
}


