const tradeRouteDefs={grainRoad:{name:'Grain Road',desc:'Exports surplus food for steady gold.',cost:{food:30,wood:20},gold:.04,requires:()=>buildingCount('market')>0},timberExchange:{name:'Timber Exchange',desc:'Organized lumber contracts increase gold income.',cost:{wood:45,stone:10},gold:.05,requires:()=>buildingCount('market')>0&&buildingCount('lumberyard')>0},stoneCaravan:{name:'Stone Caravan',desc:'Quarry caravans trade stone at distant keeps.',cost:{stone:45,wood:25},gold:.06,requires:()=>buildingCount('market')>0&&buildingCount('quarry')>0},pilgrimMarket:{name:'Pilgrim Market',desc:'Faith traffic creates donations and commerce.',cost:{faith:40,wood:20},gold:.05,requires:()=>buildingCount('market')>0&&buildingCount('shrine')>0},roadTolls:{name:'Road Tolls',desc:'Road traffic produces reliable gold.',cost:{wood:35,stone:45},gold:.045,requires:()=>buildingCount('roads')>0},bakeryStalls:{name:'Bakery Stalls',desc:'Prepared food sells well in nearby settlements.',cost:{food:50,wood:30,gold:15},gold:.055,requires:()=>buildingCount('bakery')>0&&buildingCount('market')>0},healerCircuit:{name:'Healer Circuit',desc:'Clinics and medics sell services to caravans.',cost:{faith:25,food:45,gold:25},gold:.05,requires:()=>buildingCount('clinic')>0&&game.jobs.medic>0},scribeCourier:{name:'Scribe Courier',desc:'Schools and roads create paid courier contracts.',cost:{wood:60,stone:35,gold:35},gold:.065,requires:()=>buildingCount('school')>0&&buildingCount('roads')>0},charteredCaravans:{name:'Chartered Caravans',desc:'Trade posts coordinate high-value regional routes.',cost:{wood:90,stone:70,gold:85},gold:.09,requires:()=>buildingCount('tradePost')>0&&upgrades.tradeScales?.purchased}};
const achievementDefs={firstShelter:{name:'First Shelter',group:'Thorp',desc:'Build your first Hut.',check:()=>buildingCount('hut')>=1,progress:()=>buildingCount('hut')+'/1'},smallHamlet:{name:'Early Hands',group:'Thorp',desc:'Reach 10 population.',check:()=>game.population>=10,progress:()=>game.population+'/10'},fullHouse:{name:'Sheltered Start',group:'Thorp',desc:'Reach 25 housing.',check:()=>game.housing>=25,progress:()=>game.housing+'/25'},firstWorkshop:{name:'Workshop Age',group:'Hamlet',desc:'Build a Workshop.',check:()=>buildingCount('workshop')>=1,progress:()=>buildingCount('workshop')+'/1'},marketDay:{name:'Market Day',group:'Town',desc:'Build a Market.',check:()=>buildingCount('market')>=1,progress:()=>buildingCount('market')+'/1'},tradeNetwork:{name:'Trade Network',group:'Town',desc:'Open 2 trade routes.',check:()=>Object.values(game.trade.routes).filter(Boolean).length>=2,progress:()=>Object.values(game.trade.routes).filter(Boolean).length+'/2'},goldHoard:{name:'Gold Hoard',group:'Town',desc:'Store 100 gold.',check:()=>game.resources.gold>=100,progress:()=>Math.floor(game.resources.gold)+'/100'},chosenFaith:{name:'Chosen Faith',group:'Kingdom',desc:'Choose a religious law.',check:()=>game.policies.religion!=='neutral',progress:()=>game.policies.religion==='neutral'?'0/1':'1/1'},patronDeity:{name:'Patron Deity',group:'Kingdom',desc:'Choose a deity.',check:()=>!!game.deity,progress:()=>game.deity?'1/1':'0/1'},doctrineKeeper:{name:'Doctrine Keeper',group:'Kingdom',desc:'Buy any doctrine.',check:()=>Object.values(game.doctrine).some(Boolean),progress:()=>Object.values(game.doctrine).filter(Boolean).length+'/1'},raidReady:{name:'Raid Ready',group:'Fortified Town',desc:'Build a Barracks.',check:()=>buildingCount('barracks')>=1,progress:()=>buildingCount('barracks')+'/1'},veteranGuard:{name:'Veteran Guard',group:'Fortified Town',desc:'Win a raid and gain a veteran.',check:()=>game.veterans>=1,progress:()=>game.veterans+'/1'},stableTown:{name:'Stable Town',group:'Village',desc:'Reach 70 overall stability with at least 10 people.',check:()=>game.population>=10&&getNeedMetrics().overall>=70,progress:()=>getNeedMetrics().overall+'/70'},busyHands:{name:'Busy Hands',group:'Village',desc:'Assign 10 workers to jobs.',check:()=>Object.entries(game.jobs).filter(([k])=>k!=='idle').reduce((a,[,v])=>a+v,0)>=10,progress:()=>Object.entries(game.jobs).filter(([k])=>k!=='idle').reduce((a,[,v])=>a+v,0)+'/10'}};
Object.assign(achievementDefs,{firstWinter:{name:'First Winter',group:'Thorp',desc:'Survive into the spring after your first winter.',check:()=>game.year>1&&game.month>=3,progress:()=>game.year>1&&game.month>=3?'1/1':'0/1'},hamletBreakthrough:{name:'Hamlet Breakthrough',group:'Hamlet',desc:'Reach 50 population.',check:()=>game.population>=50,progress:()=>game.population+'/50'},smallVillageRise:{name:'Small Village',group:'Village',desc:'Reach 101 population.',check:()=>game.population>=101,progress:()=>game.population+'/101'},organizedVillage:{name:'Organized Labor',group:'Village',desc:'Have 2 farmers and a workshop.',check:()=>game.jobs.farmer>=2&&buildingCount('workshop')>0,progress:()=>Math.min(game.jobs.farmer,2)+'/2 farmers'},fortifiedFirst:{name:'First Fortification',group:'Fortified Town',desc:'Build a barracks and any fortification.',check:()=>buildingCount('barracks')>0&&(buildingCount('wall')>0||buildingCount('watchtower')>0||buildingCount('palisade')>0),progress:()=>buildingCount('barracks')>0?'1/2':'0/2'},firstConquest:{name:'First Conquest',group:'City',desc:'Hold one outside area.',check:()=>ownedConquestCells().length>=1,progress:()=>ownedConquestCells().length+'/1'},sectorHolder:{name:'Sector Holder',group:'City',desc:'Secure an entire conquest sector.',check:()=>completedConquestSectors()>=1,progress:()=>completedConquestSectors()+'/1'},kingdomAuthority:{name:'Royal Authority',group:'Kingdom',desc:'Reach 100 authority.',check:()=>game.resources.authority>=100,progress:()=>formatWhole(game.resources.authority||0)+'/100'}});
