function renderCrisisStrip(){const items=[];const p=getJobProduction(),foodNet=p.food-getFoodConsumption()-getFoodSpoilage();if(!foodBackgrounded()&&foodNet<0)items.push(['Food','bad','Losing '+formatRate(Math.abs(foodNet))+'/s']);if(game.housing<game.population)items.push(['Housing','bad',game.population-game.housing+' over']);if(game.raidIncoming)items.push(['Raid','bad','Respond now']);else if(game.raidAwakened&&game.threat>70)items.push(['Raid','bad',Math.round(game.threat)+'%']);activeDisasterEntries().forEach(([k,t])=>items.push([disasterDefs[k].name,'bad',t+'s']));if(!items.length)return'';return'<div class="crisis-strip">'+items.map(([l,k,v])=>'<span class="crisis-chip '+k+'"><b>'+l+'</b> '+v+'</span>').join('')+'</div>'}
function renderMiniGoals(){if(game.options.guidance===false||progressionAtLeast('village'))return'';const goals=[['Build 3 huts',buildingCount('hut')>=3,buildingCount('hut')+'/3'],['Assign 2 farmers',game.jobs.farmer>=2,game.jobs.farmer+'/2'],['Survive first winter',game.year>1&&game.month>=3,(game.year>1&&game.month>=3)?'1/1':'0/1'],['Reach 50 population',game.population>=50,game.population+'/50']];if(goals.every(([,done])=>done))return'';return'<div class="mini-goals">'+goals.map(([label,done,prog])=>'<span class="mini-goal '+(done?'done':'')+'">'+(done?'Done ':'')+label+' <b>'+prog+'</b></span>').join('')+'</div>'}
function renderEffectsEnhanced(){if(!$('effectsContent'))return;const labor=isTabUnlocked('Population')?'<div class="effect-row"><span>Labor Policy</span><span>'+game.policies.labor+'</span></div><div class="effect-row"><span>Who Works</span><span>'+workAgePolicyLabel(game.policies.workAge)+'</span></div>':'',stage=getSocialStage(),social=stage==='early'?'':'<div class="effect-row"><span>Crime</span><span class="bad">'+Math.round(game.crime)+'%</span></div><div class="effect-row"><span>Disorder</span><span class="bad">'+Math.round(game.disorder)+'%</span></div>',months=breakthroughMonthsLeft(),breakthrough=months>0?'<div class="effect-row"><span>Breakthrough</span><span class="good">-10% costs · '+months+' mo</span></div>':'',disasters=activeDisasterEntries().map(([k,t])=>'<div class="effect-row" title="'+disasterCounterText(k).replace(/"/g,'&quot;')+'"><span>'+disasterDefs[k].name+'</span><span class="bad">'+t+'s · '+Math.round(disasterCounterScore(k)*100)+'% counter</span></div><div class="box-sub always-info">'+disasterCounterText(k)+'</div>'+disasterChoiceHtml(k)).join(''),suggestions='<div class="rule"></div>'+nextActionSuggestions().map(s=>'<div class="effect-row"><span>Next</span><span>'+s+'</span></div>').join(''),owned=ownedConquestCells().length,complete=completedConquestSectors(),expansion=owned?'<div class="effect-row"><span>Expansion</span><span class="good">+'+Math.round((getExpansionProductionMultiplier()-1)*100)+'% ('+owned+' areas, '+complete+' sectors)</span></div>':'',forecast=renderDisasterForecast();$('effectsContent').innerHTML=renderCrisisStrip()+renderGrowthGuidance()+renderEraRewardBanner()+renderMiniGoals()+renderResourceEraPanel()+renderSynergyEffectsPanel()+labor+breakthrough+disasters+forecast+expansion+'<div class="effect-row"><span>Fatigue</span><span class="bad">'+Math.round(game.fatigue)+'%</span></div>'+social+'<div class="effect-row"><span>Injuries</span><span class="bad">'+game.injuries+'</span></div>'+suggestions;document.querySelectorAll('[data-disaster-choice]').forEach(b=>b.onclick=()=>chooseDisasterResponse(b.dataset.disasterKey,b.dataset.disasterChoice));applyGrowthHighlight()}
renderEffects=renderEffectsEnhanced;
