function renderSettlementSummary(){if(!$('summaryContent'))return;const m=getPopulationMetrics(),land=getLandStats(),p=getJobProduction(),foodNet=p.food-getFoodConsumption()-getFoodSpoilage(),queue=(game.buildQueue||[]).length,stage=getProgressionStage(),workers=getAssignedWorkers(),soc=getSocietyMetrics(),activeDisasters=activeDisasterEntries().length,tradeRoutes=Object.values(game.trade?.routes||{}).filter(Boolean).length,activeLaws=Object.values(game.laws||{}).filter(Boolean).length,owned=ownedConquestCells().length,complete=completedConquestSectors(),rows=[];rows.push(summaryRow('Era',stage.label+' - '+stage.focus));rows.push(summaryRow('Population',game.population+' / '+game.housing,game.population>game.housing?'bad':''));rows.push(summaryRow('Food Net',(foodNet>=0?'+':'')+formatRate(foodNet)+'/s',foodNet>=0?'good':'bad'));rows.push(summaryRow('Workers Assigned',workers));rows.push(summaryRow('Build Queue',queue+' project'+(queue===1?'':'s'),queue?'gold':'muted'));rows.push(summaryRow('Injuries',game.injuries,game.injuries?'bad':'good'));if(progressionAtLeast('hamlet')){rows.push(summaryRow('Stability',m.needs.overall+'%',m.needs.overall>=70?'good':m.needs.overall>=45?'gold':'bad'));rows.push(summaryRow('Land',formatWhole(land.used)+' / '+formatWhole(land.cap)+(land.over?' +'+formatWhole(land.over)+' over':''),land.over?'bad':''));if(game.population>=25||game.fatigue>0)rows.push(summaryRow('Fatigue',Math.round(game.fatigue)+'%',game.fatigue>40?'bad':game.fatigue>15?'gold':'muted'))}if(progressionAtLeast('village')){rows.push(summaryRow('Health',Math.round(soc.health)+'%',soc.health>=70?'good':soc.health>=45?'gold':'bad'));rows.push(summaryRow('Loyalty',Math.round(soc.loyalty)+'%',soc.loyalty>=65?'good':soc.loyalty>=40?'gold':'bad'));if(buildingCount('workshop')>0||buildingCount('school')>0)rows.push(summaryRow('Education',Math.round(soc.education)+'%',soc.education>=55?'good':'muted'));rows.push(summaryRow('Disasters',activeDisasters,activeDisasters?'bad':'muted'))}if(progressionAtLeast('mediumVillage')){rows.push(summaryRow('Crime',Math.round(game.crime)+'%',game.crime>45?'bad':game.crime>18?'gold':'muted'));rows.push(summaryRow('Disorder',Math.round(game.disorder)+'%',game.disorder>45?'bad':game.disorder>18?'gold':'muted'))}if(progressionAtLeast('smallTown')||game.hasMarket){rows.push(summaryRow('Gold Income','+'+formatRate(getTradeGoldIncome())+'/s','gold'));rows.push(summaryRow('Trade Routes',tradeRoutes));rows.push(summaryRow('Active Laws',activeLaws,activeLaws?'gold':'muted'))}if(getProgressionStage().key==='fortifiedTown'||game.raidAwakened||buildingCount('barracks')>0){rows.push(summaryRow('Raid Threat',game.raidIncoming?'RESPOND':(game.raidAwakened?Math.round(game.threat)+'%':'Dormant'),game.raidIncoming||game.threat>70?'bad':game.threat>35?'gold':'muted'));rows.push(summaryRow('Defense',Math.round(getDefensePower()),getDefensePower()>0?'good':'muted'))}if(progressionAtLeast('smallCity')||owned>0){rows.push(summaryRow('Held Areas',owned+' / sectors '+complete,owned?'good':'muted'));rows.push(summaryRow('Expansion Bonus','+'+Math.round((getExpansionProductionMultiplier()-1)*100)+'%',owned?'good':'muted'))}if(progressionAtLeast('smallKingdom')||buildingCount('temple')>0||buildingCount('shrine')>0){rows.push(summaryRow('Faith Income','+'+formatRate(getFaithProduction())+'/s','faith'));rows.push(summaryRow('Obedience',Math.round(soc.obedience)+'%',soc.obedience>=65?'good':soc.obedience>=40?'gold':'bad'));rows.push(summaryRow('Religion',game.policies.religion||game.religiousLaw||'neutral'))}let html=renderCrisisStrip()+renderGrowthGuidance()+rows.join('')+renderMiniGoals();$('summaryContent').innerHTML=html;applyGrowthHighlight()}
function lawEffectSummary(k){return{curfew:'-10 crime, +5 disorder, +6 fear, -5 happiness, slower births',policing:'-14 crime, -2 disorder, +4 fear, -2 happiness, -3% gold',taxRelief:'+7 happiness, +4% births, -6 disorder, -12% gold, -3% build speed',publicWorks:'+20% build speed, +2 happiness, -4 disorder, +2 crime, -8% gold'}[k]||k}
function renderActiveEffectsOnly(){if(!$('effectsContent'))return;const labor=isTabUnlocked('Population')?'<div class="effect-row"><span>Labor Policy</span><span>'+game.policies.labor+'</span></div><div class="effect-row"><span>Who Works</span><span>'+workAgePolicyLabel(game.policies.workAge)+'</span></div>':'',stage=getSocialStage(),social=stage==='early'?'':'<div class="effect-row"><span>Crime</span><span class="bad">'+Math.round(game.crime)+'%</span></div><div class="effect-row"><span>Disorder</span><span class="bad">'+Math.round(game.disorder)+'%</span></div>',months=breakthroughMonthsLeft(),breakthrough=months>0?'<div class="effect-row"><span>Breakthrough</span><span class="good">-10% costs - '+months+' mo</span></div>':'',disasters=activeDisasterEntries().map(([k,t])=>'<div class="effect-row" title="'+disasterCounterText(k).replace(/"/g,'&quot;')+'"><span>'+disasterDefs[k].name+'</span><span class="bad">'+t+'s - '+Math.round(disasterCounterScore(k)*100)+'% counter</span></div><div class="box-sub always-info">'+disasterCounterText(k)+'</div>'+disasterChoiceHtml(k)).join(''),owned=ownedConquestCells().length,complete=completedConquestSectors(),expansion=owned?'<div class="effect-row"><span>Expansion</span><span class="good">+'+Math.round((getExpansionProductionMultiplier()-1)*100)+'% ('+owned+' areas, '+complete+' sectors)</span></div>':'',forecast=renderDisasterForecast(),laws=Object.entries(game.laws||{}).filter(([,v])=>v).map(([k])=>'<div class="effect-row" title="'+lawEffectSummary(k)+'"><span>Law</span><span>'+k+' - '+lawEffectSummary(k)+'</span></div>').join('');$('effectsContent').innerHTML=breakthrough+disasters+forecast+expansion+renderResourceEraPanel()+renderSynergyEffectsPanel()+labor+laws+'<div class="effect-row"><span>Fatigue</span><span class="'+(game.fatigue?'bad':'muted')+'">'+Math.round(game.fatigue)+'%</span></div>'+social;document.querySelectorAll('[data-disaster-choice]').forEach(b=>b.onclick=()=>chooseDisasterResponse(b.dataset.disasterKey,b.dataset.disasterChoice))}
renderEffects=renderActiveEffectsOnly;
function getJobRows(){const p=getJobProduction(),b=buildingCount('barracks')>0;return[{key:'farmer',name:'Farmers',note:'+'+formatNum(p.food)+' food/s',show:true},{key:'woodcutter',name:'Woodcutters',note:'+'+formatNum(p.wood)+' wood/s',show:true},{key:'miner',name:'Miners',note:'+'+formatNum(p.stone)+' stone/s',show:true},{key:'builder',name:'Builders',note:'Build speed +'+Math.round(p.build*100)+'%',show:true},{key:'priest',name:'Priests',note:'+'+formatNum(p.faith)+' faith/s',show:buildingCount('shrine')>0},{key:'grunt',name:'Grunts',note:'Emergency fighters, half as strong as soldiers',show:!b&&earlyRaidConditionMet()},{key:'guard',name:'Guards',note:'Security, crime control, defense',show:b},{key:'soldier',name:'Soldiers',note:'Frontline defense power',show:b},{key:'archer',name:'Archers',note:'Ranged defense power',show:b},{key:'scout',name:'Scouts',note:'Scout targets and reduce threat',show:b},{key:'sapper',name:'Sappers',note:'Break enemy walls during conquest',show:b},{key:'medic',name:'Medics',note:'Heal injuries faster',show:b}]}
function getJobAgeBreakdown(job){ensureJobAges();if(game.jobAges?.[job])return Object.assign({adults:0,children:0,elders:0},game.jobAges[job]);const e=getWorkAgeEligibility(),pool=getWorkforceCapacity(),out={adults:0,children:0,elders:0},order=['medic','sapper','scout','archer','soldier','guard','grunt','priest','builder','miner','woodcutter','farmer'];let adults=pool.adults,elders=e.elders?pool.elders:0,children=e.children?pool.children:0;for(const k of order){let need=game.jobs[k]||0,used={adults:0,elders:0,children:0},take=Math.min(adults,need);used.adults=take;adults-=take;need-=take;take=Math.min(elders,need);used.elders=take;elders-=take;need-=take;take=Math.min(children,need);used.children=take;children-=take;need-=take;if(k===job)return used}return out}
function classKeys(){return['peasants','skilled','elites']}
function ensureClassJobs(){const keys=Object.keys(game.jobs);if(!game.classJobs)game.classJobs={};keys.forEach(job=>{if(!game.classJobs[job])game.classJobs[job]={};classKeys().forEach(c=>{if(!Number.isFinite(game.classJobs[job][c]))game.classJobs[job][c]=0})});const hasTracked=keys.some(j=>classKeys().some(c=>(game.classJobs[j]?.[c]||0)>0));if(!hasTracked&&keys.some(j=>(game.jobs[j]||0)>0)){const total=Math.max(1,Object.values(game.classes).reduce((a,v)=>a+(v||0),0));keys.forEach(job=>{let count=game.jobs[job]||0,skilled=Math.min(count,Math.round(count*((game.classes.skilled||0)/total))),elites=Math.min(count-skilled,Math.round(count*((game.classes.elites||0)/total)));game.classJobs[job].skilled=skilled;game.classJobs[job].elites=elites;game.classJobs[job].peasants=Math.max(0,count-skilled-elites)})}keys.forEach(job=>{const sum=classKeys().reduce((a,c)=>a+(game.classJobs[job][c]||0),0),target=game.jobs[job]||0;if(sum<target)game.classJobs[job].peasants+=target-sum;if(sum>target){let over=sum-target;['elites','skilled','peasants'].forEach(c=>{const take=Math.min(over,game.classJobs[job][c]||0);game.classJobs[job][c]-=take;over-=take})}});return game.classJobs}
function ensureJobAges(){const keys=Object.keys(game.jobs);game.jobAges=game.jobAges||{};keys.forEach(job=>{game.jobAges[job]=Object.assign({adults:0,children:0,elders:0},game.jobAges[job]||{})});const hasTracked=keys.some(j=>['adults','children','elders'].some(a=>(game.jobAges[j]?.[a]||0)>0));if(!hasTracked){keys.forEach(job=>{game.jobAges[job].adults=game.jobs[job]||0})}keys.forEach(job=>{const sum=(game.jobAges[job].adults||0)+(game.jobAges[job].children||0)+(game.jobAges[job].elders||0),target=game.jobs[job]||0;if(sum<target)game.jobAges[job].adults+=target-sum;if(sum>target){let over=sum-target;['children','elders','adults'].forEach(a=>{const take=Math.min(over,game.jobAges[job][a]||0);game.jobAges[job][a]-=take;over-=take})}});return game.jobAges}
function getJobClassBreakdown(job){ensureClassJobs();return{peasants:game.classJobs[job]?.peasants||0,skilled:game.classJobs[job]?.skilled||0,elites:game.classJobs[job]?.elites||0}}
function canUseClass(c){return c==='peasants'||c==='skilled'&&buildingCount('workshop')>0||c==='elites'&&eliteUnlocked()}
function moveClassBetweenJobs(from,to,c,amount){ensureClassJobs();if(!canUseClass(c)||!game.classJobs[from]||!game.classJobs[to])return 0;const moved=Math.min(Math.max(0,amount),game.classJobs[from][c]||0);if(moved<=0)return 0;game.classJobs[from][c]-=moved;game.classJobs[to][c]+=moved;game.jobs[from]=Math.max(0,(game.jobs[from]||0)-moved);game.jobs[to]=(game.jobs[to]||0)+moved;return moved}
function moveAnyClasses(from,to,amount){ensureClassJobs();let left=Math.max(0,amount),moved=0;for(const c of classKeys()){if(left<=0)break;const n=moveClassBetweenJobs(from,to,c,left);moved+=n;left-=n}return moved}
function assignJobClass(job,c,amount){syncPopulationAccounting();if(!Object.prototype.hasOwnProperty.call(game.jobs,job)||job==='idle')return;if(amount==='max')amount=game.classJobs?.idle?.[c]||0;if(amount==='-max')amount=-(game.classJobs?.[job]?.[c]||0);amount=Number(amount);if(!Number.isFinite(amount)||amount===0)return;if(job==='builder'&&amount<0)game.builderAutoReplace=false;if(job==='builder'&&amount>0)game.builderAutoReplace=true;let moved=0;if(amount>0){const age=game.jobAssignAge||'adults',idle=getIdleAgeCounts();moved=assignWorkerRecords(game,{from:'idle',to:job,age,classType:c,count:Math.min(amount,idle[age]||0)})}else{moved=assignWorkerRecords(game,{from:job,to:'idle',classType:c,count:Math.abs(amount)})}if(moved>0)game.logs.unshift(eventStamp()+' Moved '+moved+' '+c+' '+(amount>0?'to ':'from ')+job+'.');game.patrols=clamp(game.patrols,0,game.jobs.guard+game.jobs.scout);refreshAll();showJobDetails(job)}
function classControlRows(job){const cls=getJobClassBreakdown(job),idle=getJobClassBreakdown('idle'),row=(c,label,unlocked,lock)=>unlocked?'<div class="storage-row"><span>'+label+'</span><span>'+cls[c]+' assigned / '+idle[c]+' idle</span></div><div class="controls"><button class="mini-btn" data-job-class="'+c+'" data-class-amount="-1">-1</button><button class="mini-btn" data-job-class="'+c+'" data-class-amount="-max">-Max</button><button class="mini-btn" data-job-class="'+c+'" data-class-amount="1">+1</button><button class="mini-btn" data-job-class="'+c+'" data-class-amount="5">+5</button><button class="mini-btn" data-job-class="'+c+'" data-class-amount="max">+Max</button></div>':'<div class="storage-row"><span>Undiscovered Class</span><span class="muted">'+lock+'</span></div>';return row('peasants','Peasants',true,'')+row('skilled','Skilled Workers',buildingCount('workshop')>0,'Build Workshop')+row('elites','Elites',eliteUnlocked(),'Build Mansion')}
function showJobDetails(job){ensureClassJobs();const row=getJobRows().find(j=>j.key===job),age=getJobAgeBreakdown(job),count=game.jobs[job]||0,eligible=getWorkAgeEligibility();if(!row)return;showModal(row.name+' Details','<div class="storage-row"><span>Assigned</span><span>'+count+'</span></div><div class="storage-row"><span>Current Output</span><span class="good">'+row.note+'</span></div><div class="storage-row"><span>Who Works Policy</span><span>'+workAgePolicyLabel(game.policies.workAge)+'</span></div><div class="rule"></div><div class="storage-row"><span>Adults Working</span><span>'+age.adults+'</span></div><div class="storage-row"><span>Children Working</span><span>'+age.children+(eligible.children?'':' (not eligible)')+'</span></div><div class="storage-row"><span>Elders Working</span><span>'+age.elders+(eligible.elders?'':' (not eligible)')+'</span></div><div class="rule"></div>'+jobSynergyDetails(job)+'<div class="rule"></div>'+classControlRows(job)+'<div class="box-sub">Use these controls to move specific classes between idle labor and this job.</div>');document.querySelectorAll('[data-job-class][data-class-amount]').forEach(btn=>btn.onclick=()=>assignJobClass(job,btn.dataset.jobClass,btn.dataset.classAmount))}
let lastModalFocus=null;
function closeModal(){const overlay=$('resourceDetailOverlay');if(!overlay)return;overlay.classList.remove('show');if(lastModalFocus&&document.contains(lastModalFocus))lastModalFocus.focus();lastModalFocus=null}
function showModal(title,html){const overlay=$('resourceDetailOverlay'),modal=overlay?.querySelector('.detail-modal');lastModalFocus=document.activeElement;$('resourceDetailTitle').textContent=title;$('resourceDetailBody').innerHTML=html;overlay.classList.add('show');setTimeout(()=>{const first=modal?.querySelector('button,[href],input,select,textarea,[tabindex]:not([tabindex="-1"])');(first||modal)?.focus()},0)}
function trapModalFocus(e){const overlay=$('resourceDetailOverlay');if(!overlay?.classList.contains('show'))return;if(e.key==='Escape'){e.preventDefault();closeModal();return}if(e.key!=='Tab')return;const modal=overlay.querySelector('.detail-modal'),items=Array.from(modal.querySelectorAll('button,[href],input,select,textarea,[tabindex]:not([tabindex="-1"])')).filter(el=>!el.disabled&&el.offsetParent!==null);if(!items.length){e.preventDefault();modal.focus();return}const first=items[0],last=items[items.length-1];if(e.shiftKey&&document.activeElement===first){e.preventDefault();last.focus()}else if(!e.shiftKey&&document.activeElement===last){e.preventDefault();first.focus()}}
function showResourceDetails(type){const names=Object.assign({food:'Food',wood:'Wood',stone:'Stone',gold:'Gold',faith:'Faith'},Object.fromEntries(Object.entries(resourceDefs).map(([k,d])=>[k,d.name]))),p=getJobProduction(),use=getFoodConsumption(),spoil=getFoodSpoilage(),goldRate=getTradeGoldIncome(),extraRate=resourceDefs[type]?getProgressionResourceIncome(type):0,rates={food:p.food-use-spoil,wood:p.wood,stone:p.stone,gold:goldRate,faith:p.faith},prod={food:p.food,wood:p.wood,stone:p.stone,gold:goldRate,faith:p.faith},rateText=v=>type==='gold'||resourceDefs[type]?formatRate(v):formatNum(v),queue=buildQueueResourceTotals()[type]||{needed:0,paid:0,demolish:0};if(resourceDefs[type]){rates[type]=extraRate;prod[type]=extraRate}let extra='';if(type==='food')extra='<div class="storage-row"><span>Produced</span><span class="good">+'+formatNum(p.food)+'/s</span></div><div class="storage-row"><span>Consumed</span><span class="bad">-'+formatNum(use)+'/s</span></div><div class="storage-row"><span>Spoilage</span><span class="bad">-'+formatNum(spoil)+'/s</span></div><div class="box-sub">Food is the main pressure early, then infrastructure and trade reduce its importance. Disasters can still make it matter.</div>';else extra='<div class="storage-row"><span>Produced</span><span class="good">+'+rateText(prod[type]||0)+'/s</span></div>'+(resourceDefs[type]?'<div class="box-sub">'+resourceDefs[type].desc+'</div>':'');const cap=hasInfiniteStorage(type)?'Infinite':formatWhole(game.storage[type]),full=hasInfiniteStorage(type)?'':'<div class="storage-row"><span>Storage Full</span><span>'+Math.floor((game.resources[type]||0)/Math.max(1,game.storage[type]||1)*100)+'%</span></div>',queueRows='<div class="rule"></div><div class="storage-row"><span>Queued Build Need</span><span>'+formatWhole(queue.needed||0)+'</span></div><div class="storage-row"><span>Already Used In Queue</span><span>'+formatWhole(queue.paid||0)+'</span></div>'+(queue.demolish?'<div class="storage-row"><span>Demolition Left</span><span>'+formatWhole(queue.demolish)+'</span></div>':'');showModal((names[type]||type)+' Details','<div class="storage-row"><span>Stored</span><span>'+formatWhole(game.resources[type])+'/'+cap+'</span></div><div class="storage-row"><span>Net Rate</span><span class="'+((rates[type]||0)>=0?'good':'bad')+'">'+((rates[type]||0)>=0?'+':'')+rateText(rates[type]||0)+'/s</span></div>'+extra+full+queueRows)}
function detailSection(title,html,open=true){return'<details '+(open?'open':'')+'><summary>'+title+'</summary><div class="detail-body">'+html+'</div></details>'}
function foodConsumptionBreakdown(){const adultUse=BALANCE.population.adultFoodUse,childUse=adultUse*BALANCE.population.childFoodRatio,elderUse=adultUse*BALANCE.population.elderFoodRatio,adults=game.ages.adults||0,children=game.ages.children||0,elders=game.ages.elders||0,untracked=Math.max(0,game.population-adults-children-elders),ageBase=adults*adultUse+children*childUse+elders*elderUse+untracked*adultUse,policy=getPolicyEffects().foodUse+getWorkAgePolicyEffects().foodUse,stage=getStageBalance().foodUse,elite=getClassEffects().eliteFoodUse,reduction=clamp((game.modifiers.foodUseReduction||0)+buildingCount('bakery')*.035,0,.55);return'<div class="storage-row"><span>Overall Consumption</span><span class="bad">'+formatNum(getFoodConsumption())+'/s</span></div><div class="rule"></div><div class="storage-row"><span>Adults</span><span>'+adults+' x '+formatNum(adultUse)+' = '+formatNum(adults*adultUse)+'/s</span></div><div class="storage-row"><span>Children</span><span>'+children+' x '+formatNum(childUse)+' = '+formatNum(children*childUse)+'/s</span></div><div class="storage-row"><span>Elders</span><span>'+elders+' x '+formatNum(elderUse)+' = '+formatNum(elders*elderUse)+'/s</span></div><div class="storage-row"><span>Untracked Adults</span><span>'+untracked+' x '+formatNum(adultUse)+' = '+formatNum(untracked*adultUse)+'/s</span></div><div class="rule"></div><div class="storage-row"><span>Age Base</span><span>'+formatNum(ageBase)+'/s</span></div><div class="storage-row"><span>Policy Multiplier</span><span>'+formatNum(policy)+'x</span></div><div class="storage-row"><span>Stage Multiplier</span><span>'+formatNum(stage)+'x</span></div><div class="storage-row"><span>Elite Extra Use</span><span>'+formatNum(elite)+'/s</span></div><div class="storage-row"><span>Bakery/Upgrade Reduction</span><span class="good">-'+Math.round(reduction*100)+'%</span></div>'}
showResourceDetails=function(type){const names=Object.assign({food:'Food',wood:'Wood',stone:'Stone',gold:'Gold',faith:'Faith'},Object.fromEntries(Object.entries(resourceDefs).map(([k,d])=>[k,d.name]))),p=getJobProduction(),gold=getTradeGoldBreakdown(),queue=buildQueueResourceTotals()[type]||{needed:0,paid:0,demolish:0},cap=hasInfiniteStorage(type)?'Infinite':formatWhole(game.storage[type]),stored='<div class="storage-row"><span>Stored</span><span>'+formatWhole(game.resources[type])+'/'+cap+'</span></div>'+(hasInfiniteStorage(type)?'':'<div class="storage-row"><span>Storage Full</span><span>'+Math.floor((game.resources[type]||0)/Math.max(1,game.storage[type]||1)*100)+'%</span></div>'),queueRows='<div class="storage-row"><span>Queued Build Need</span><span>'+formatWhole(queue.needed||0)+'</span></div><div class="storage-row"><span>Already Used In Queue</span><span>'+formatWhole(queue.paid||0)+'</span></div>'+(queue.demolish?'<div class="storage-row"><span>Demolition Left</span><span>'+formatWhole(queue.demolish)+'</span></div>':''),prodRows=type==='food'?'<div class="storage-row"><span>Farmer + Infrastructure</span><span class="good">+'+formatNum(p.food)+'/s</span></div><div class="storage-row"><span>Spoilage</span><span class="bad">-'+formatNum(getFoodSpoilage())+'/s</span></div>':type==='wood'?'<div class="storage-row"><span>Woodcutters</span><span class="good">+'+formatNum(p.wood)+'/s</span></div>':type==='stone'?'<div class="storage-row"><span>Miners</span><span class="good">+'+formatNum(p.stone)+'/s</span></div>':type==='faith'?'<div class="storage-row"><span>Priests, Shrines, Temples</span><span class="good">+'+formatNum(p.faith)+'/s</span></div>':type==='gold'?'<div class="storage-row"><span>Market</span><span>'+formatRate(gold.market)+'/s</span></div><div class="storage-row"><span>Warehouse</span><span>'+formatRate(gold.warehouse)+'/s</span></div><div class="storage-row"><span>Routes</span><span>'+formatRate(gold.routes)+'/s</span></div><div class="storage-row"><span>Faith Economy</span><span>'+formatRate(gold.faith)+'/s</span></div>':resourceDefs[type]?'<div class="storage-row"><span>'+resourceDefs[type].desc+'</span><span class="good">+'+formatRate(getProgressionResourceIncome(type))+'/s</span></div>':'';let html=detailSection('Storage',stored,true)+detailSection('Production',prodRows,true);if(type==='food')html+=detailSection('Consumption Breakdown',foodConsumptionBreakdown(),true);html+=detailSection('Build Queue Use',queueRows,true);showModal((names[type]||type)+' Details',html)}
function showPopulationDetails(){const m=getPopulationMetrics();showModal('Population Details','<div class="storage-row"><span>Total Population</span><span>'+game.population+'</span></div><div class="storage-row"><span>Housing</span><span>'+game.population+'/'+game.housing+'</span></div><div class="storage-row"><span>Idle Adults</span><span>'+game.jobs.idle+'</span></div><div class="storage-row"><span>Idle Children</span><span>'+(game.ages.children||0)+'</span></div><div class="storage-row"><span>Idle Elders</span><span>'+(game.ages.elders||0)+'</span></div><div class="storage-row"><span>Birth / Migration In</span><span class="good">+'+(getBirthRate()+m.migrationToTown/100).toFixed(2)+'/s</span></div><div class="storage-row"><span>Mortality / Migration Out</span><span class="bad">-'+(getMortalityRate()+m.migrationFromTown/100).toFixed(2)+'/s</span></div><div class="storage-row"><span>Food Need</span><span>'+m.needs.food+'%</span></div><div class="storage-row"><span>Housing Need</span><span>'+m.needs.housing+'%</span></div><div class="storage-row"><span>Overall Stability</span><span>'+m.needs.overall+'%</span></div>')}
function bindInfoButtons(){document.querySelectorAll('[data-resource-eye]').forEach(btn=>btn.onclick=e=>{e.stopPropagation();showResourceDetails(btn.dataset.resourceEye)});if($('populationEye'))$('populationEye').onclick=e=>{e.stopPropagation();showPopulationDetails()};if($('seasonEye'))$('seasonEye').onclick=e=>{e.stopPropagation();showSeasonDetails()};if($('happinessEye'))$('happinessEye').onclick=e=>{e.stopPropagation();showHappinessDetails()};if($('fearEye'))$('fearEye').onclick=e=>{e.stopPropagation();showFearDetails()}}
function showSeasonDetails(){const s=currentSeason(),sm=seasonModifiers();showModal('Season Effects: '+s,'<div class="storage-row"><span>Current Season</span><span>'+s+'</span></div><div class="storage-row"><span>Season Type</span><span>'+sm.label+'</span></div><div class="storage-row"><span>Base Food Production</span><span class="'+(sm.production>=0?'good':'bad')+'">'+(sm.production>=0?'+':'')+(sm.production*100).toFixed(0)+'%</span></div><div class="storage-row"><span>Food Use Modifier</span><span class="'+(sm.foodUse<=0?'good':'bad')+'">'+(sm.foodUse>=0?'+':'')+(sm.foodUse*100).toFixed(0)+'%</span></div><div class="box-sub">'+sm.desc+'</div>')}
function showHappinessDetails(){const m=getPopulationMetrics();showModal('Happiness Effects','<div class="storage-row"><span>Base Happiness</span><span>'+game.happiness+'%</span></div><div class="storage-row"><span>Effective Happiness</span><span>'+Math.round(getEffectiveHappiness())+'%</span></div><div class="storage-row"><span>Growth Impact</span><span class="good">+'+(getBirthRate()+m.migrationToTown/100).toFixed(2)+'/s</span></div><div class="box-sub">Higher happiness improves growth, migration, and stability.</div>')}
function showFearDetails(){const m=getPopulationMetrics(),stage=getSocialStage(),note=stage==='early'?'<div class="box-sub">Crime and disorder are hidden until 50 population. The full social system unlocks at 100 population.</div>':stage==='mid'?'<div class="box-sub">Crime and disorder are emerging lightly. The full system unlocks at 100 population.</div>':'<div class="box-sub">Late game social pressure is fully dynamic and reacts to fear, religion, military, and laws.</div>',rows=stage==='early'?'':'<div class="storage-row"><span>Crime Pressure</span><span class="bad">'+m.crimePressure+'%</span></div><div class="storage-row"><span>Disorder Pressure</span><span class="bad">'+m.disorderPressure+'%</span></div>';showModal('Fear Effects','<div class="storage-row"><span>Base Fear</span><span>'+game.fear+'%</span></div><div class="storage-row"><span>Effective Fear</span><span>'+Math.round(getEffectiveFear())+'%</span></div><div class="storage-row"><span>Social Stage</span><span>'+stage+'</span></div>'+rows+note)}
function buildingCategory(k){const map={hut:'Housing & Population',house:'Housing & Population',cottage:'Housing & Population',mansion:'Housing & Population',familyPlot:'Housing & Population',gatheringCenter:'Storage',woodPile:'Storage',storehouse:'Storage',smokehouse:'Food',well:'Infrastructure',footpath:'Infrastructure',foragerCamp:'Food',huntingLodge:'Food',fishery:'Food',mill:'Food',farm:'Food',granary:'Storage',lumberyard:'Storage',quarry:'Storage',warehouse:'Storage',market:'Trade & Gold',tradePost:'Trade & Gold',bank:'Trade & Gold',customsHouse:'Trade & Gold',taxOffice:'Trade & Gold',merchantGuild:'Trade & Gold',tradeDistrict:'Trade & Gold',imperialMint:'Trade & Gold',roads:'Trade & Gold',tavern:'Happiness & Society',bakery:'Happiness & Society',commons:'Happiness & Society',theater:'Happiness & Society',herbalist:'Happiness & Society',meetingHall:'Happiness & Society',shrine:'Faith & Religion',chapel:'Faith & Religion',temple:'Faith & Religion',barracks:'Military & Defense',militiaYard:'Military & Defense',watchPost:'Military & Defense',palisade:'Military & Defense',militaryDistrict:'Military & Defense',arsenal:'Military & Defense',armory:'Military & Defense',trainingGround:'Military & Defense',fortress:'Military & Defense',wall:'Military & Defense',watchtower:'Military & Defense',workshop:'Infrastructure',carpenter:'Infrastructure',charcoalPit:'Infrastructure',blacksmith:'Infrastructure',school:'Infrastructure',clinic:'Infrastructure',sewer:'Infrastructure',townHall:'Infrastructure',guildHall:'Infrastructure',university:'Infrastructure',foundry:'Infrastructure',foodWorkshop:'Infrastructure',woodWorkshop:'Infrastructure',stoneWorkshop:'Infrastructure',goldWorkshop:'Infrastructure',faithWorkshop:'Infrastructure',grandRoadNetwork:'Infrastructure',courthouse:'Governance',jail:'Governance',senate:'Governance',vassalOffice:'Governance',embassy:'Governance',censusBureau:'Governance',imperialPalace:'Governance'};return map[k]||'Infrastructure'}
function buildingObsolete(k){return(k==='hut'&&progressionAtLeast('village'))||(k==='palisade'&&progressionAtLeast('village'))||(['gatheringCenter','woodPile','foragerCamp','smokehouse','familyPlot'].includes(k)&&progressionAtLeast('mediumVillage'))||(['well','huntingLodge','watchPost','footpath'].includes(k)&&progressionAtLeast('smallTown'))||(['storehouse'].includes(k)&&progressionAtLeast('bigVillage'))||(['charcoalPit','house','carpenter'].includes(k)&&progressionAtLeast('smallCity'))}
function destroyBuilding(k){if(!buildingDefs[k]||buildingCount(k)<=0)return;const cost=buildingDefs[k].removeCost||{wood:1};game.buildQueue=game.buildQueue||[];game.buildQueue.push({id:Date.now()+Math.random(),key:k,type:'remove',cost,paid:Object.fromEntries(Object.entries(cost).map(([r,a])=>[r,a]))});game.logs.unshift(eventStamp()+' Queued demolition: '+buildingDefs[k].name+'. Builders will dismantle it over time.');refreshAll();showLandUseDetails();if(activeTab==='Buildings')renderBuildingsTab()}
function showLandUseDetails(){const land=getLandStats(),built=Object.entries(buildingDefs).filter(([k])=>buildingCount(k)>0);const rows=built.map(([k,d])=>'<div class="upgrade-row"><div class="upgrade-top"><div class="upgrade-name"><span>'+d.name+'</span></div><div>'+buildingCount(k)+' built</div></div><div class="box-sub">'+d.desc+' '+d.effects+'</div><div class="storage-row"><span>Land Each</span><span>'+(buildingLand[k]??1)+'</span></div><div class="controls"><button class="mini-btn" data-destroy-building="'+k+'" title="Queue demolition for this building. Builders reduce the demolition bar until it reaches zero.">Destroy 1</button></div></div>').join('')||'<div class="box-sub">No buildings have been built yet.</div>';showModal('Land Use','<div class="storage-row"><span>Land Used</span><span>'+land.used+' / '+land.cap+'</span></div><div class="storage-row"><span>Overcrowding</span><span class="'+(land.over?'bad':'good')+'">'+land.over+'</span></div><div class="box-sub">Destroying a building now goes through the build queue. The bar drains down as builders dismantle it.</div><div class="rule"></div>'+rows);document.querySelectorAll('[data-destroy-building]').forEach(b=>b.onclick=()=>destroyBuilding(b.dataset.destroyBuilding))}
function ensureUiState(){game.ui=game.ui||{};game.ui.collapsed=game.ui.collapsed||{};game.ui.collapsed.buildings=game.ui.collapsed.buildings||{};game.ui.collapsed.upgrades=game.ui.collapsed.upgrades||{};game.ui.collapsed.population=game.ui.collapsed.population||{}}
function isPanelCollapsed(scope,key){ensureUiState();return !!game.ui.collapsed[scope]?.[key]}
function togglePanelCollapsed(scope,key){ensureUiState();game.ui.collapsed[scope][key]=!game.ui.collapsed[scope][key];if(activeTab==='Buildings')renderBuildingsTab();else if(activeTab==='Upgrades')renderUpgradesTab();else if(activeTab==='Population')renderPopulationTab()}
function panelHtml(scope,key,title,content,extraClass=''){const collapsed=isPanelCollapsed(scope,key),safeTitle=String(title).replace(/"/g,'&quot;');return'<div class="panel '+extraClass+(collapsed?' collapsed-panel':'')+'"><h3><button class="panel-toggle" data-collapse-scope="'+scope+'" data-collapse-key="'+key+'" aria-label="Toggle '+safeTitle+'" title="Collapse or expand this box">'+(collapsed?'+':'-')+'</button><span class="panel-title">'+title+'</span></h3><div class="content" '+(collapsed?'style="display:none"':'')+'>'+content+'</div></div>'}
function bindCollapseToggles(root=document){root.querySelectorAll('[data-collapse-scope][data-collapse-key]').forEach(btn=>btn.onclick=e=>{e.stopPropagation();togglePanelCollapsed(btn.dataset.collapseScope,btn.dataset.collapseKey)})}
function renderBuildingsTab(){activeTab='Buildings';game.progression.buildingsUnlocked=true;$('mainArea').classList.remove('population-mode');$('mainArea').classList.add('buildings-mode','masonry-mode');const land=getLandStats(),hasBuilder=game.jobs.builder>=1,landPanel='<div class="panel raid-threat-clickable" id="landUsePanel"><h3><span class="panel-title">Land Use</span></h3><div class="content"><div class="storage-row"><span>Settlement Age</span><span>'+getSettlementAge()+'</span></div><div class="storage-row"><span>Active Builders</span><span class="'+(hasBuilder?'good':'bad')+'">'+game.jobs.builder+'</span></div><div class="storage-row"><span>Land Used</span><span>'+land.used+' / '+land.cap+'</span></div><div class="storage-row"><span>Land Overcrowding</span><span class="'+(land.over?'bad':'good')+'">'+land.over+'</span></div><div class="box-sub always-info">Click this panel to inspect built structures or queue demolition.</div>'+renderBuildQueuePanel()+'</div></div>';const cats=['Housing & Population','Storage','Food','Trade & Gold','Faith & Religion','Military & Defense','Happiness & Society','Infrastructure','Governance'],filter=game.ui?.buildingFilter||'all';const visible=Object.entries(buildingDefs).filter(([k])=>(!buildingObsolete(k)||buildingCount(k)>0)&&(k!=='workshop'||buildingCount('workshop')<1)&&(buildingCategory(k)!=='Faith & Religion'||progressionAtLeast('village')||buildingCount(k)>0)&&(missingPrereqs(k).length===0||buildingCount(k)>0));const sections=cats.filter(cat=>filter==='all'||filter===cat).map(cat=>{const rows=visible.filter(([k])=>buildingCategory(k)===cat).map(([k,d])=>{const cost=getQueuedBuildingCost(k),pr=missingPrereqs(k),canBuild=hasBuilder&&pr.length===0&&!buildingObsolete(k),label=!hasBuilder?'Need Builder':buildingObsolete(k)?'Obsolete':pr.length?'Locked':'Queue',deep=buildingDeepDescription(k),conv=buildingConversions[k],convOk=canConvertBuilding(k),convCost=conv?conversionCost(k):null,showConv=conv&&conversionVisible(k),convertButton=showConv?'<button class="mini-btn" data-convert-building="'+k+'" '+(convOk?'':'disabled')+' title="Queue conversion into '+(buildingDefs[conv.to]?.name||conv.to)+'. Cost: '+formatCost(convCost||{})+'">'+conv.label+'</button>':'';return'<div class="building-card" title="'+deep.replace(/"/g,'&quot;')+'"><div class="building-title"><span>'+d.name+'</span><span>'+buildingCount(k)+(getQueuedBuildingCount(k)?' +'+getQueuedBuildingCount(k)+' queued':'')+'</span></div><div class="building-desc">'+d.desc+'</div><div class="building-effects">'+d.effects+'</div><div class="building-cost">Cost to complete: '+formatCost(cost)+' - Land '+(buildingLand[k]??1)+'</div>'+(buildingObsolete(k)?'<div class="building-cost muted">Obsolete in the current era. Existing copies still function, but new copies cannot be built.</div>':'')+(showConv?'<div class="building-cost good">Conversion: '+(buildingDefs[k]?.name||k)+' -> '+(buildingDefs[conv.to]?.name||conv.to)+' for '+formatCost(convCost||{})+'</div>':'')+(pr.length?'<div class="building-cost bad">Requires: '+pr.join(', ')+'</div>':'')+'<div class="building-actions"><button class="mini-btn" data-build="'+k+'" data-build-count="1" '+(canBuild?'':'disabled')+' title="Queue 1 '+d.name+'.">'+label+'</button><button class="mini-btn" data-build="'+k+'" data-build-count="10" '+(canBuild?'':'disabled')+' title="Queue 10 copies.">10x</button><button class="mini-btn" data-build="'+k+'" data-build-count="100" '+(canBuild?'':'disabled')+' title="Queue 100 copies.">100x</button><button class="mini-btn" data-build="'+k+'" data-build-count="max" '+(canBuild?'':'disabled')+' title="Queue as many as current resources can fully fund, capped at 100.">Max</button>'+convertButton+'</div></div>'}).join('');return rows?panelHtml('buildings',cat,cat,rows):''}).join('')||panelHtml('buildings','buildings-empty','Buildings','<div class="box-sub">No buildings in this category are currently visible.</div>');$('mainArea').innerHTML=landPanel+sections;applyMasonryLayout($('mainArea'));bindCollapseToggles($('mainArea'));document.querySelectorAll('[data-build]').forEach(b=>b.onclick=e=>{e.stopPropagation();buildBuilding(b.dataset.build,b.dataset.buildCount)});document.querySelectorAll('[data-convert-building]').forEach(b=>b.onclick=e=>{e.stopPropagation();convertBuilding(b.dataset.convertBuilding)});document.querySelectorAll('[data-cancel-build]').forEach(b=>b.onclick=e=>{e.stopPropagation();cancelBuildProject(b.dataset.cancelBuild)});document.querySelectorAll('[data-cancel-all-builds]').forEach(b=>b.onclick=e=>{e.stopPropagation();cancelAllBuildProjects()});document.querySelectorAll('[data-rush-build]').forEach(b=>b.onclick=e=>{e.stopPropagation();rushBuildProject(b.dataset.rushBuild,b.dataset.rushMode)});if($('landUsePanel'))$('landUsePanel').onclick=showLandUseDetails}
function buildingDeepDescription(k){const d=buildingDefs[k]||{};const details={hut:'+4 housing. Low land use. Best first shelter.',gatheringCenter:'+10 food, wood, and stone storage. Core thorp supply building.',smokehouse:'+10 food storage, passive food preservation, and less early spoilage through upgrades.',footpath:'+2% build production per path. Phases out once roads matter.',familyPlot:'+happiness and family growth support, but slightly increases food use.',house:'+8 housing. Houses reduce fatigue slightly once fatigue exists.',cottage:'+12 housing. Stronger family housing and stability.',mansion:'+20 housing. Unlocks elites and gold-tier society pressure.',well:'+health and +5 food storage. Helps early settlement health.',woodPile:'+15 wood storage for early construction pushes.',storehouse:'+20 food, wood, and stone storage before warehouse logistics.',foragerCamp:'+passive food. Useful before farms dominate food.',huntingLodge:'+passive food and early resilience.',fishery:'+passive food from water sources and a food production bonus.',mill:'+food production and passive grain processing. A key village food milestone.',carpenter:'+builder speed and wood economy.',charcoalPit:'+tools support and future steel chain support.',watchPost:'+1 defense and early raid warning without using land.',palisade:'+2 defense each, no land use, early threat reduction.',blacksmith:'+tools and construction output.',herbalist:'+health before clinics.',commons:'+loyalty, happiness, and civic stability.',meetingHall:'+loyalty and civic stability.',townHall:'+civic order and construction coordination for towns.',courthouse:'Reduces crime and disorder through formal justice.',jail:'Sharper crime control and obedience, but socially harsher than civic policies.',bank:'+gold income and better town wealth handling.',taxOffice:'+gold income from taxation with a small happiness cost.',customsHouse:'+trade route value and caravan economy.',merchantGuild:'+trade route value, gold, and market identity.',guildHall:'+skilled productivity and city specialization.',university:'+knowledge and education.',sewer:'+health, lower death pressure, and less city disorder.',theater:'+happiness, loyalty, culture, and influence.',foundry:'+steel and industrial output.',arsenal:'+defense, steel/tool output, and stronger sappers.',foodDistrict:'+city food logistics.',tradeDistrict:'+gold and influence from dense trade.',militaryDistrict:'+defense and conquest strength.',senate:'+loyalty and governance for empire factions.',vassalOffice:'+tribute from conquered land.',embassy:'+diplomacy, authority, and lower raid pressure.',censusBureau:'+knowledge, obedience, and governance efficiency.',grandRoadNetwork:'+trade and conquest logistics.',imperialMint:'+gold and imperial authority.',imperialPalace:'+authority, loyalty, and empire-scale control.',workshop:'Unlocks upgrades, tools income, skilled workers, and specialized workshops.',farm:'Improves farmer value and pushes food away from clicking.',granary:'+30 food storage and +0.1 food per harvest click.',lumberyard:'+25 wood storage and +0.1 wood per chop click.',quarry:'+25 stone storage and +0.1 stone per mine click.',market:'Unlocks gold, trade routes, caravans, exchange, and mercenaries.',barracks:'Unlocks trained military roles. Before this, only Grunts are available during threat.',shrine:'Unlocks faith and priests after Village stage.',temple:'Improves faith, doctrine, and religious stability.',wall:'+5 passive defense and no land use.',watchtower:'+3 defense, reduces threat, no land use.'};return (d.name||k)+': '+(details[k]||((d.desc||'')+' '+(d.effects||'')))}
function upgradeCost(u){if(!u.level)return applyCostMultiplier(u.cost);const c={};Object.entries(u.cost).forEach(([r,a])=>c[r]=Math.ceil(a*Math.pow(u.scaling||1.4,u.level)));return applyCostMultiplier(c)}
function upgradeCategory(k,u){const map={farmingEfficiency:'Food',fallSurplus:'Food',winterStores:'Food',granaryFarms:'Food',cropRotation:'Food',irrigationDitches:'Food',irrigationChannels:'Food',seedVaults:'Food',rootCellars:'Food',communalPlows:'Food',seedSelection:'Food',villageBakery:'Food',fishPonds:'Food',orchards:'Food',preservationSalt:'Food',windmill:'Food',cropCalendar:'Food',communalOvens:'Food',soilSurvey:'Food',beekeeping:'Food',expandedFields:'Food',cropRows:'Food',millstones:'Food',betterTools:'Wood',carpenterGuild:'Wood',masonGuild:'Stone',deepMines:'Stone',storageUpgrade:'Storage',sealedStorehouses:'Storage',marketWarehouse:'Storage',handBaskets:'Storage',fireKeptStores:'Storage',organizedLabor:'Labor & Population',comfortableHomes:'Labor & Population',apprenticeships:'Labor & Population',childhoodApprenticeship:'Labor & Population',fieldMedicine:'Labor & Population',healersHall:'Labor & Population',scribeSchools:'Labor & Population',villagePlanning:'Labor & Population',publicHygiene:'Labor & Population',townCharter:'Labor & Population',builderHauling:'Labor & Population',parallelCrews:'Labor & Population',foremanPlanning:'Labor & Population',kinshipLabor:'Labor & Population',timberFraming:'Labor & Population',apprenticeshipCharters:'Labor & Population',localHealers:'Labor & Population',civilRegistry:'Labor & Population',sanitationNetwork:'Labor & Population',districtPlanning:'Labor & Population',weaponQuality:'Military',armorTraining:'Military',battlefieldTactics:'Military',logistics:'Military',fortifiedWalls:'Military',militiaStandards:'Military',archeryRanges:'Military',armoredCompanies:'Military',fortressLogistics:'Military',veteranCadres:'Military',communalDefense:'Military',paidWatch:'Military',professionalArmy:'Military',stoneRoads:'Trade & Gold',merchantCharters:'Trade & Gold',pilgrimRoads:'Trade & Gold',tradeGuilds:'Trade & Gold',tradeScales:'Trade & Gold',caravanGuards:'Trade & Gold',lettersOfCredit:'Trade & Gold',coinStandards:'Trade & Gold',vassalTaxation:'Trade & Gold',grandLogistics:'Trade & Gold',monasticLedgers:'Faith & Religion',imperialLaw:'Faith & Religion',diplomaticCorps:'Faith & Religion'};return map[k]||(/faith|priest|monastic/i.test(k+u.name+u.desc)?'Faith & Religion':'General')}
const upgradeCategoryCore=upgradeCategory;
upgradeCategory=function(k,u){if(['grainReserves','fireBrigade','floodworks','quarantineWards','dragonWatch'].includes(k))return'Disaster';return upgradeCategoryCore(k,u)}
function isUpgradeOwned(u){return u.infinite?false:u.maxLevel?u.level>=u.maxLevel:!!u.purchased}
function renderUpgradeCard(k,u,ownedView=false){const cost=upgradeCost(u),owned=isUpgradeOwned(u),canBuy=!owned&&canAfford(cost),levelText=u.infinite?'Lv '+(u.level||0):u.maxLevel?'Lv '+(u.level||0)+'/'+u.maxLevel:owned?'Owned':formatCost(cost),state=owned?'Owned':canBuy?'Buy':'Need '+formatCost(missingCost(cost)),tip=(u.name+': '+u.desc+' Cost: '+formatCost(cost)+(u.unlockText?' Unlock: '+u.unlockText:'')).replace(/"/g,'&quot;');return'<div class="upgrade-row" title="'+tip+'"><div class="upgrade-top"><div class="upgrade-name"><span>'+u.name+'</span></div><div>'+levelText+'</div></div><div class="box-sub">'+u.desc+'</div>'+(ownedView?'<div class="muted">Purchased</div>':'<div class="controls"><button class="mini-btn" data-upgrade="'+k+'" '+(canBuy?'':'disabled')+' title="'+tip+'">'+state+'</button><span>'+formatCost(cost)+'</span></div>')+'</div>'}
function renderUpgradesList(){const el=$('upgradesContent');if(!el)return;const cats=['Food','Wood','Stone','Storage','Disaster','Labor & Population','Military','Trade & Gold','Faith & Religion','General'],visible=Object.entries(upgrades).filter(([,u])=>!(u.requires&&!u.requires())),available=visible.filter(([,u])=>!isUpgradeOwned(u)),purchased=visible.filter(([,u])=>isUpgradeOwned(u));const availableSection=available.length?cats.map(cat=>{const rows=available.filter(([k,u])=>upgradeCategory(k,u)===cat).map(([k,u])=>renderUpgradeCard(k,u,false)).join('');return rows?panelHtml('upgrades','available-'+cat,'Available Upgrades - '+cat,rows):''}).join(''):panelHtml('upgrades','available-empty','Available Upgrades','<div class="box-sub">None.</div>');const purchasedRows=purchased.map(([k,u])=>renderUpgradeCard(k,u,true)).join('');const purchasedSection=panelHtml('upgrades','purchased','Purchased Upgrades',purchasedRows||'<div class="box-sub">None.</div>');el.innerHTML=availableSection+purchasedSection;applyMasonryLayout(el);bindCollapseToggles(el);el.querySelectorAll('[data-upgrade]').forEach(b=>b.onclick=()=>buyUpgrade(b.dataset.upgrade))}
function renderUpgradesTab(){activeTab='Upgrades';$('mainArea').classList.remove('population-mode','buildings-mode');$('mainArea').classList.add('masonry-mode');$('mainArea').innerHTML='<div id="upgradesContent"></div>';renderUpgradesList()}
function renderInfinite(){renderUpgradesList()}
function buyUpgrade(k){const u=upgrades[k],cost=u?upgradeCost(u):null;if(!u||(u.requires&&!u.requires())||(!u.infinite&&u.maxLevel&&u.level>=u.maxLevel)||(!u.infinite&&!u.maxLevel&&u.purchased)||!canAfford(cost))return;payCost(cost);if(u.infinite||u.maxLevel)u.level=(u.level||0)+1;else u.purchased=true;u.apply();refreshAll();if(activeTab==='Upgrades')renderUpgradesTab()}
function setVillageIdentity(id){game.identity=id;game.logs.unshift(eventStamp()+' Village identity set: '+id+'.');refreshAll();if(activeTab==='Trade')renderTradeTab()}
function getTradePrice(resource,mode){const season=currentSeason();let buy={food:8,wood:10,stone:12,faith:15,tools:18,influence:24,steel:32,knowledge:28,authority:42}[resource]||10,sell={food:5,wood:6,stone:7,tools:10,influence:14,steel:18,knowledge:16,authority:24}[resource]||0;const stored=game.resources[resource]||0,cap=hasInfiniteStorage(resource)?100:Math.max(1,game.storage[resource]||100),scarcity=stored/cap;if(resource==='food'){if(season==='Summer'){buy*=.75;sell*=.75}if(season==='Winter'){buy*=1.55;sell*=1.35}}if(resource==='stone'&&scarcity<.25){buy*=1.45;sell*=1.25}if(resource==='wood'&&scarcity<.25){buy*=1.25;sell*=1.15}if(game.identity==='agrarian'&&resource==='food'){buy*=.85;sell*=1.2}if(game.identity==='industrial'&&(resource==='wood'||resource==='stone'||resource==='tools'||resource==='steel')){buy*=.9;sell*=1.18}if(game.identity==='spiritual'&&(resource==='faith'||resource==='authority'))buy*=.8;return{buy:Math.max(1,Math.round(buy)),sell:Math.max(0,Math.round(sell))}}
function tradeExchange(resource,mode){const amounts={food:20,wood:15,stone:12,faith:10,tools:5,influence:4,steel:3,knowledge:4,authority:2},amount=amounts[resource]||10,price=getTradePrice(resource,mode);if(mode==='sell'&&resource==='faith')return;if(mode==='buy'){if(game.resources.gold<price.buy)return;game.resources.gold-=price.buy;addResource(resource,amount);game.logs.unshift(eventStamp()+' Trade: bought '+amount+' '+resource+' for '+price.buy+' gold.')}else{if(game.resources[resource]<amount)return;game.resources[resource]-=amount;addResource('gold',price.sell);game.logs.unshift(eventStamp()+' Trade: sold '+amount+' '+resource+' for '+price.sell+' gold.')}game.trade.deals++;refreshAll();if(activeTab==='Trade')renderTradeTab()}
function sellPeople(amount){ensureClassJobs();amount=Math.min(Number(amount)||0,game.jobs.idle||0,game.ages.adults||0);if(amount<=0)return;game.jobs.idle-=amount;game.ages.adults-=amount;game.population=Math.max(0,game.population-amount);let left=amount;['peasants','skilled','elites'].forEach(c=>{const take=Math.min(left,game.classJobs.idle?.[c]||0);if(take>0){game.classJobs.idle[c]-=take;game.classes[c]=Math.max(0,(game.classes[c]||0)-take);left-=take}});if(left>0)game.classes.peasants=Math.max(0,(game.classes.peasants||0)-left);addResource('gold',amount*12);game.trade.deals++;game.logs.unshift(eventStamp()+' Trade: '+amount+' idle adults left with a labor caravan.');refreshAll();if(activeTab==='Trade')renderTradeTab()}
function activateTradeRoute(key){const r=tradeRouteDefs[key];if(!r||game.trade.routes[key]||!r.requires()||!canAfford(r.cost))return;payCost(r.cost);game.trade.routes[key]=true;game.trade.lastEvent='Opened route: '+r.name;game.logs.unshift(eventStamp()+' Trade route opened: '+r.name+'.');refreshAll();if(activeTab==='Trade')renderTradeTab()}
function nextCaravanDelay(){const routeCount=Object.values(game.trade.routes||{}).filter(Boolean).length,base=BALANCE.trade.baseCaravanDelay-routeCount*BALANCE.trade.routeDelayReduction-buildingCount('tradePost')*BALANCE.trade.tradePostDelayReduction-buildingCount('roads')*BALANCE.trade.roadDelayReduction,speed=1-clamp(game.modifiers.caravanSpeedBonus||0,0,.5);return Math.max(BALANCE.trade.minCaravanDelay,Math.round(base*speed))}
function setTradeTariff(mode){if(!['low','balanced','high'].includes(mode))return;game.trade.tariff=mode;game.logs.unshift(eventStamp()+' Trade tariff set: '+mode+'.');refreshAll();if(activeTab==='Trade')renderTradeTab()}
function tariffEffects(){if(game.trade.tariff==='low')return{gold:.9,standing:.04,threat:-.015,label:'Low tariffs: less gold, better standing, lower threat.'};if(game.trade.tariff==='high')return{gold:1.2,standing:-.05,threat:.025,label:'High tariffs: more gold, worse standing, more threat.'};return{gold:1,standing:.01,threat:0,label:'Balanced tariffs: steady trade standing.'}}
function triggerCaravan(){if(!game.hasMarket)return;const rolls=['merchant','surplus','shortage','toll','specialist','festival'],roll=rolls[Math.floor(Math.random()*rolls.length)],tariff=tariffEffects();if(roll==='merchant'){const gold=(8+buildingCount('market')*4+Object.values(game.trade.routes).filter(Boolean).length*3+buildingCount('tradePost')*5)*tariff.gold;addResource('gold',gold);game.trade.lastEvent='Merchant caravan paid '+Math.round(gold)+' gold.'}else if(roll==='surplus'){addResource('food',12+buildingCount('bakery')*4);addResource('wood',8);game.trade.lastEvent='Caravan brought food and wood.'}else if(roll==='shortage'){const loss=game.trade.standing>65?2:5;game.resources.gold=Math.max(0,game.resources.gold-loss);game.trade.lastEvent='Market shortage cost '+loss+' gold.'}else if(roll==='specialist'){if(buildingCount('school')>0&&game.resources.gold>=8){game.resources.gold-=8;addAdultToJob('idle','skilled');game.trade.lastEvent='A skilled specialist settled for 8 gold.'}else{addResource('stone',10);game.trade.lastEvent='A specialist caravan traded useful stone.'}}else if(roll==='festival'){game.happiness=clamp(game.happiness+2,0,100);addResource('gold',3);game.trade.lastEvent='A festive caravan raised happiness and paid small tolls.'}else{const gold=4*tariff.gold;addResource('gold',gold);if(raidPrereqMet()&&game.raidAwakened)game.threat=clamp(game.threat+Math.max(0,2+(tariff.threat*100)-(game.modifiers.caravanThreatReduction?1:0)),0,100);game.trade.lastEvent=raidPrereqMet()&&game.raidAwakened?'Collected caravan tolls, but threat rose.':'Collected caravan tolls.'}game.trade.standing=clamp((game.trade.standing||50)+tariff.standing*100,0,100);game.logs.unshift(eventStamp()+' '+game.trade.lastEvent);game.trade.caravanTimer=nextCaravanDelay()}
function updateTrade(){if(!game.hasMarket)return;game.trade.caravanTimer=Math.max(0,Math.ceil(game.trade.caravanTimer||nextCaravanDelay())-1);if(game.trade.caravanTimer<=0)triggerCaravan()}
function hireMercenary(job='random',amount=1){if(!game.hasMarket)return;ensureClassJobs();const jobs=['guard','soldier','archer','scout','sapper','medic'],n=Math.max(1,Number(amount)||1),cost=BALANCE.trade.mercenaryCost*n;if((game.resources.gold||0)<cost){game.logs.unshift(eventStamp()+' Not enough gold to hire mercenaries.');renderEvents();return}game.resources.gold-=cost;for(let i=0;i<n;i++){const target=jobs.includes(job)?job:jobs[Math.floor(Math.random()*jobs.length)];addAdultToJob(target,'peasants')}game.logs.unshift(eventStamp()+' Hired '+n+' mercenar'+(n===1?'y':'ies')+' for '+cost+' gold.');refreshAll();if(activeTab==='Trade')renderTradeTab()}
function renderTradeTab(){
  activeTab='Trade';
  $('mainArea').classList.remove('population-mode','buildings-mode');
  $('mainArea').classList.add('masonry-mode');
  const routeRows=Object.entries(tradeRouteDefs).filter(([k,r])=>game.trade.routes[k]||r.requires()).map(([k,r])=>{const open=!!game.trade.routes[k],ready=r.requires(),afford=canAfford(r.cost);return `<div class="upgrade-row"><div class="upgrade-top"><div class="upgrade-name"><span>${r.name}</span></div><div>${open?'Active':'+'+formatRate(r.gold)+' gold/s'}</div></div><div class="box-sub">${r.desc}</div><div class="controls"><span>${formatCost(r.cost)}</span><button class="mini-btn" data-trade-route="${k}" ${open||!ready||!afford?'disabled':''}>${open?'Active':ready?'Open Route':'Missing building'}</button></div></div>`}).join('')||'<div class="box-sub">Build trade infrastructure to reveal routes.</div>';
  const exchangeList=['food','wood','stone','faith'].concat(unlockedProgressionResources());
  const exchangeRows=exchangeList.map(r=>{const price=getTradePrice(r),amount={food:20,wood:15,stone:12,faith:10,tools:5,influence:4,steel:3,knowledge:4,authority:2}[r]||10,sellable=r!=='faith',sellButton=sellable?`<button class="mini-btn" data-trade-sell="${r}" ${(game.resources[r]||0)<amount?'disabled':''}>Sell ${amount}</button>`:'<span class="muted">Cannot sell faith</span>';return `<div class="storage-row"><span>${r.charAt(0).toUpperCase()+r.slice(1)}</span><span>${formatWhole(game.resources[r])}${hasInfiniteStorage(r)?'':'/'+formatWhole(game.storage[r])}</span></div><div class="storage-row"><span>Price</span><span>Buy ${price.buy}${sellable?' / Sell '+price.sell:''}</span></div><div class="controls"><button class="mini-btn" data-trade-buy="${r}" ${(game.resources.gold||0)<price.buy?'disabled':''}>Buy ${amount}</button>${sellButton}</div>`}).join('<div class="rule"></div>');
  const identityPanel=`<div class="panel"><h3>Village Identity</h3><div class="content"><div class="storage-row"><span>Current</span><span>${game.identity}</span></div><div class="controls"><button class="mini-btn" data-identity="balanced">Balanced</button><button class="mini-btn" data-identity="agrarian">Agrarian</button><button class="mini-btn" data-identity="industrial">Industrial</button><button class="mini-btn" data-identity="spiritual">Spiritual</button></div><div class="box-sub">Identity adjusts market prices and nudges the village toward a specialty.</div></div></div>`;
  const mercJobs=['random','guard','soldier','archer','scout','sapper','medic'],mercRows=mercJobs.map(j=>'<button class="mini-btn" data-merc-job="'+j+'">'+(j==='random'?'Random Military Job':j.charAt(0).toUpperCase()+j.slice(1))+'</button>').join('');
  const tariffPanel=`<div class="panel"><h3>Tariffs</h3><div class="content"><div class="storage-row"><span>Policy</span><span>${game.trade.tariff||'balanced'}</span></div><div class="storage-row"><span>Standing</span><span>${Math.round(game.trade.standing||50)}%</span></div><div class="box-sub">${tariffEffects().label}</div><div class="controls"><button class="mini-btn" data-tariff="low">Low</button><button class="mini-btn" data-tariff="balanced">Balanced</button><button class="mini-btn" data-tariff="high">High</button></div></div></div>`;
  $('mainArea').innerHTML=`<div class="panel"><h3>Market Ledger</h3><div class="content"><div class="storage-row"><span>Gold Income</span><span class="gold">+${formatRate(getTradeGoldIncome())}/s</span></div><div class="storage-row"><span>Trade Deals</span><span>${game.trade.deals}</span></div><div class="storage-row"><span>Trade Standing</span><span>${Math.round(game.trade.standing||50)}%</span></div><div class="storage-row"><span>Next Caravan</span><span>${Math.ceil(game.trade.caravanTimer||0)}s</span></div><div class="box-sub">${game.trade.lastEvent}</div></div></div>${identityPanel}${tariffPanel}<div class="panel"><h3>Resource Exchange</h3><div class="content">${exchangeRows}</div></div><div class="panel"><h3>Mercenary Contracts</h3><div class="content"><div class="storage-row"><span>Cost</span><span>${BALANCE.trade.mercenaryCost} Gold each</span></div><div class="box-sub">Mercenaries are hired with gold and immediately join military jobs. Choose a role or hire randomly.</div><div class="controls">${mercRows}</div><div class="controls"><button class="mini-btn" data-merc-random="5" ${(game.resources.gold||0)<BALANCE.trade.mercenaryCost*5?'disabled':''}>Hire 5 Random</button></div></div></div><div class="panel"><h3>Labor Contracts</h3><div class="content"><div class="storage-row"><span>Idle Adults</span><span>${game.jobs.idle}</span></div><div class="box-sub">Selling people removes idle adults from the hamlet and pays 12 gold each.</div><div class="controls"><button class="mini-btn" data-sell-people="1" ${game.jobs.idle<1?'disabled':''}>Sell 1</button><button class="mini-btn" data-sell-people="5" ${game.jobs.idle<5?'disabled':''}>Sell 5</button></div></div></div><div class="panel"><h3>Trade Routes</h3><div class="content">${routeRows}</div></div><div class="panel"><h3>Caravans</h3><div class="content"><div class="box-sub">Caravans tick down once per second. Routes and trade posts shorten the interval after each caravan arrives.</div><button class="mini-btn" id="callCaravanBtn" ${(game.resources.gold||0)<10?'disabled':''}>Call Caravan - 10 Gold</button></div></div>`;
  document.querySelectorAll('[data-identity]').forEach(b=>b.onclick=()=>setVillageIdentity(b.dataset.identity));
  document.querySelectorAll('[data-tariff]').forEach(b=>b.onclick=()=>setTradeTariff(b.dataset.tariff));
  document.querySelectorAll('[data-trade-buy]').forEach(b=>b.onclick=()=>tradeExchange(b.dataset.tradeBuy,'buy'));
  document.querySelectorAll('[data-trade-sell]').forEach(b=>b.onclick=()=>tradeExchange(b.dataset.tradeSell,'sell'));
  document.querySelectorAll('[data-trade-route]').forEach(b=>b.onclick=()=>activateTradeRoute(b.dataset.tradeRoute));
  document.querySelectorAll('[data-sell-people]').forEach(b=>b.onclick=()=>sellPeople(b.dataset.sellPeople));
  document.querySelectorAll('[data-merc-job]').forEach(b=>b.onclick=()=>hireMercenary(b.dataset.mercJob,1));
  document.querySelectorAll('[data-merc-random]').forEach(b=>b.onclick=()=>hireMercenary('random',b.dataset.mercRandom));
  if($('callCaravanBtn'))$('callCaravanBtn').onclick=()=>{if((game.resources.gold||0)<10)return;game.resources.gold-=10;triggerCaravan();refreshAll();renderTradeTab()};
  applyMasonryLayout($('mainArea'));
}
function updateAchievements(){Object.entries(achievementDefs).forEach(([k,a])=>{if(!game.achievements[k]&&a.check()){game.achievements[k]=true;game.logs.unshift(eventStamp()+' Achievement unlocked: '+a.name+'.')}})}
function renderAchievementsTab(){activeTab='Achievements';$('mainArea').classList.remove('population-mode','buildings-mode');updateAchievements();const entries=Object.entries(achievementDefs),unlocked=entries.filter(([k])=>game.achievements[k]),locked=entries.filter(([k])=>!game.achievements[k]),groups=[...new Set(entries.map(([,a])=>a.group))];const summary='<div class="panel"><h3>Achievement Summary</h3><div class="content"><div class="storage-row"><span>Unlocked</span><span>'+unlocked.length+'/'+entries.length+'</span></div><div class="storage-row"><span>Completion</span><span>'+Math.round(unlocked.length/entries.length*100)+'%</span></div><div class="box-sub">Achievements unlock automatically as your hamlet reaches milestones.</div></div></div>';const groupRows=groups.map(g=>{const total=entries.filter(([,a])=>a.group===g).length,done=entries.filter(([k,a])=>a.group===g&&game.achievements[k]).length;return'<div class="storage-row"><span>'+g+'</span><span>'+done+'/'+total+'</span></div>'}).join('');const groupsPanel='<div class="panel"><h3>Categories</h3><div class="content">'+groupRows+'</div></div>';const card=([k,a])=>'<div class="upgrade-row"><div class="upgrade-top"><div class="upgrade-name"><span>'+a.name+'</span></div><div>'+(game.achievements[k]?'Unlocked':a.progress())+'</div></div><div class="box-sub">'+a.desc+'</div></div>';const unlockedPanel='<div class="panel"><h3>Unlocked</h3><div class="content">'+(unlocked.length?unlocked.map(card).join(''):'<div class="box-sub">No achievements unlocked yet.</div>')+'</div></div>';const lockedPanel='<div class="panel"><h3>In Progress</h3><div class="content">'+(locked.length?locked.map(card).join(''):'<div class="box-sub">All achievements complete.</div>')+'</div></div>';$('mainArea').innerHTML=summary+groupsPanel+unlockedPanel+lockedPanel}
function chooseDeity(key){if(!deityDefs[key])return;if(game.deity&&game.deity!==key){game.deityFavor[game.deity]=Math.max(0,game.deityFavor[game.deity]-20);game.resources.faith=Math.max(0,game.resources.faith-25);game.logs.unshift(eventStamp()+' Changing deities cost 25 faith and favor.')}game.deity=key;game.logs.unshift(eventStamp()+' Chosen deity: '+deityDefs[key].name);refreshAll();if(activeTab==='Deities')renderDeityTab()}
function spendFaith(cost){if(game.resources.faith<cost){game.logs.unshift(eventStamp()+' Not enough faith. Need '+cost+'.');renderEvents();return false}game.resources.faith-=cost;return true}
function divineAction(type){let used=false;if(type==='bless'&&spendFaith(25)){game.divineBuffs.blessCrops=30;used=true;game.logs.unshift(eventStamp()+' Divine power: crops are blessed.')}if(type==='calm'&&spendFaith(20)){game.disorder=Math.max(0,game.disorder-20);used=true;game.logs.unshift(eventStamp()+' Divine power: the people are calmed.')}if(type==='protect'&&spendFaith(30)){game.divineBuffs.divineProtection=45;game.threat=Math.max(0,game.threat-20);used=true;game.logs.unshift(eventStamp()+' Divine power: protection surrounds the hamlet.')}if(type==='inspire'&&spendFaith(20)){game.divineBuffs.inspireWorkers=30;game.fatigue=Math.max(0,game.fatigue-20);used=true;game.logs.unshift(eventStamp()+' Divine power: workers are inspired.')}if(type==='convert'&&spendFaith(35)){game.religiousPopulation.conversionProgress+=55;used=true;game.logs.unshift(eventStamp()+' Divine power: missionaries converted more villagers.')}if(type==='heal'&&spendFaith(30)){const healed=Math.min(game.injuries||0,Math.max(1,Math.ceil(game.population*.08)));game.injuries=Math.max(0,(game.injuries||0)-healed);game.injuryQueue=(game.injuryQueue||[]).map(q=>Object.assign(q,{count:Math.max(0,q.count-healed)})).filter(q=>q.count>0);used=true;game.logs.unshift(eventStamp()+' Divine power: '+healed+' injuries were healed.')}if(type==='tithe'&&spendFaith(45)){addResource('gold',Math.max(8,Math.round(game.population*.8)));used=true;game.logs.unshift(eventStamp()+' Divine power: offerings filled the treasury.')}if(used){refreshAll();if(activeTab==='Deities')renderDeityTab()}}
function startRitual(type){let used=false;if(type==='harvest'&&spendFaith(60)){game.rituals.harvestRitual=90;used=true;game.logs.unshift(eventStamp()+' Ritual begun: Harvest Ritual.')}if(type==='war'&&spendFaith(60)){game.rituals.warChant=90;used=true;game.logs.unshift(eventStamp()+' Ritual begun: War Chant.')}if(type==='purify'&&spendFaith(50)){game.rituals.purification=90;used=true;game.logs.unshift(eventStamp()+' Ritual begun: Purification.')}if(used){refreshAll();if(activeTab==='Deities')renderDeityTab()}}
function buyDoctrine(key){const costs={efficientWorship:{faith:100,wood:40},holyDiscipline:{faith:120,stone:50},divineEconomy:{faith:150,gold:50},missionaryOrders:{faith:130,food:60},sacredArchives:{faith:160,wood:90,stone:70},charitableHospices:{faith:140,food:90,gold:30}};if(!costs[key]||game.doctrine[key]||!canAfford(costs[key]))return;payCost(costs[key]);game.doctrine[key]=true;if(key==='divineEconomy')game.modifiers.faithToGold=1;if(key==='missionaryOrders')game.modifiers.conversionBonus=.45;if(key==='sacredArchives')game.modifiers.priestFaithBonus=(game.modifiers.priestFaithBonus||0)+.15;if(key==='charitableHospices')game.modifiers.mortalityReduction=(game.modifiers.mortalityReduction||0)+.15;game.logs.unshift(eventStamp()+' Doctrine purchased: '+key+'.');refreshAll();if(activeTab==='Deities')renderDeityTab()}
function buyDeityUpgrade(key){if(!game.deity)return;const def=deityUpgradeDefs[game.deity]?.[key];if(!def||game.deityUpgrades[game.deity]?.[key]||!canAfford(def.cost))return;payCost(def.cost);game.deityUpgrades[game.deity][key]=true;game.logs.unshift(eventStamp()+' Deity upgrade purchased: '+def.name+'.');refreshAll();if(activeTab==='Deities')renderDeityTab()}
function setPolicy(type,value){if(!Object.prototype.hasOwnProperty.call(game.policies,type))return;game.policies[type]=value;if(type==='religion')game.religiousLaw=value==='neutral'?'none':value;if(type==='workAge')rebalanceWorkforce();game.logs.unshift(eventStamp()+' Policy changed: '+type+' -> '+value);refreshAll();if(activeTab==='Population')renderPopulationTab();if(activeTab==='Deities')renderDeityTab()}
function toggleLaw(law){if(!Object.prototype.hasOwnProperty.call(game.laws,law))return;game.laws[law]=!game.laws[law];game.logs.unshift(eventStamp()+' Law '+(game.laws[law]?'enabled: ':'disabled: ')+law);refreshAll();if(activeTab==='Population')renderPopulationTab()}
function startEdict(edict){const costs={rationing:{food:0},festival:{food:40,gold:10},forcedLabor:{faith:10}},durations={rationing:60,festival:90,forcedLabor:60};if(!durations[edict])return;if(costs[edict]&&!canAfford(costs[edict])){game.logs.unshift(eventStamp()+' Not enough resources for edict: '+edict+'.');renderEvents();return}if(costs[edict])payCost(costs[edict]);game.edicts[edict]=durations[edict];game.logs.unshift(eventStamp()+' Edict started: '+edict);refreshAll();if(activeTab==='Population')renderPopulationTab()}
function addPolicyTooltips(){const tips={focus:{balanced:'No major production changes.',agrarian:'+20% food production.',industrial:'+15% wood and stone, -10% food, -5 happiness.',spiritual:'+5 happiness, +10% faith, -5% food.'},labor:{balanced:'Normal work and fatigue.',hard:'+10% production/building, -8 happiness, +6 fear.',relaxed:'-10% production/building, +8 happiness.'},growth:{balanced:'Normal birth and food use.',encourage:'+20% birth, +10% food use, +2 happiness.',restrict:'-20% birth, -5% food use, -3 happiness.'},migration:{controlled:'Normal migration.',open:'+3 happiness, -2 fear.',closed:'-4 happiness, +5 fear.'},religion:{neutral:'No religious policy modifiers.',mandatory:'+35% faith, +7 fear, -8 happiness.',freedom:'-25% faith, +8 happiness, -3 fear.',state:'+18% faith, +4 fear.'},workAge:{everyone:'Adults, children, and elders can work.',noElders:'Adults and children can work; elders rest.',noKids:'Adults and elders can work; children rest.',onlyAdults:'Only adults work.'},law:{curfew:'-10 crime, +5 disorder, +6 fear, -5 happiness, slight birth penalty.',policing:'-14 crime, -2 disorder, +4 fear, -2 happiness, -3% gold income.',taxRelief:'+7 happiness, +4% birth, -6 disorder, -12% gold income, -3% build speed.',publicWorks:'+20% build speed, +2 happiness, -4 disorder, +2 crime, -8% gold income, +2% food use.'},edict:{rationing:'60s: -15% food use, -10 happiness.',festival:'90s: +12 happiness.',forcedLabor:'60s: +15% production/building, +15 fear, -12 happiness.'}};document.querySelectorAll('[data-policy]').forEach(b=>{const t=tips[b.dataset.policy]?.[b.dataset.value];if(t)b.title=t});document.querySelectorAll('[data-law]').forEach(b=>{const t=tips.law[b.dataset.law];if(t)b.title=t});document.querySelectorAll('[data-edict]').forEach(b=>{const t=tips.edict[b.dataset.edict];if(t)b.title=t})}
function setReligiousLaw(law){game.religiousLaw=law;game.policies.religion=law==='none'?'neutral':law;game.logs.unshift(eventStamp()+' Religious law changed: '+law+'.');refreshAll();if(activeTab==='Deities')renderDeityTab();if(activeTab==='Population')renderPopulationTab()}
function updateReligion(){const income=getFaithIncome();if(game.population>0&&buildingCount('shrine')+buildingCount('temple')+buildingCount('chapel')>0){game.religiousPopulation.conversionProgress+=(income*8+buildingCount('temple')*.25+buildingCount('chapel')*.18)*(1+(game.modifiers.conversionBonus||0));while(game.religiousPopulation.conversionProgress>=100&&game.religiousPopulation.converted<game.population){game.religiousPopulation.conversionProgress-=100;game.religiousPopulation.converted++}}if(game.religiousPopulation.converted>game.population)game.religiousPopulation.converted=game.population;Object.keys(game.deityFavor).forEach(key=>{let delta=-.005;if(game.deity===key){delta=.02+game.jobs.priest*.005+income*.01;if(key==='harvest'&&game.jobs.farmer>=game.jobs.soldier+game.jobs.archer)delta+=.015;if(key==='war'&&game.jobs.guard+game.jobs.soldier+game.jobs.archer>=Math.max(1,game.population*.2))delta+=.015;if(key==='order'&&game.crime<20&&game.disorder<20)delta+=.015;if(key==='joy'&&getEffectiveHappiness()>70)delta+=.015;if(game.resources.faith<5)delta-=.04}game.deityFavor[key]=clamp(game.deityFavor[key]+delta,0,100)});const favor=game.deity?game.deityFavor[game.deity]:50;if(game.deity&&favor>85&&Math.random()<.002){const roll=Math.random();if(roll<.45){game.resources.food=clamp(game.resources.food+Math.max(8,game.population*3),0,game.storage.food);game.logs.unshift(eventStamp()+' Divine Event: Blessed Harvest filled the stores.')}else if(roll<.75){addAdultToJob('idle','peasants');game.logs.unshift(eventStamp()+' Divine Event: Pilgrims arrived.')}else{game.happiness=clamp(game.happiness+4,0,100);game.logs.unshift(eventStamp()+' Divine Event: The people feel blessed.')}}if(game.deity&&favor<15&&Math.random()<.002){game.disorder=clamp(game.disorder+8,0,100);game.happiness=clamp(game.happiness-3,0,100);game.logs.unshift(eventStamp()+' Divine Event: Divine Anger unsettles the hamlet.')}}
function renderPopulationTab(){activeTab='Population';$('mainArea').classList.remove('buildings-mode');$('mainArea').classList.add('population-mode');const m=getPopulationMetrics();$('mainArea').innerHTML='<div class="panel"><h3>Population Overview</h3><div class="content"><div class="storage-row"><span>Total Population</span><span>'+game.population+'</span></div><div class="storage-row"><span>Housing</span><span>'+game.population+'/'+game.housing+'</span></div><div class="storage-row"><span>Idle Adults</span><span>'+game.jobs.idle+'</span></div><div class="storage-row"><span>Idle Children</span><span>'+(game.ages.children||0)+'</span></div><div class="storage-row"><span>Idle Elders</span><span>'+(game.ages.elders||0)+'</span></div><div class="storage-row"><span>Total Adults</span><span>'+(game.ages.adults||0)+'</span></div><div class="storage-row"><span>Injured Adults</span><span class="bad">'+game.injuries+'</span></div></div></div><div class="panel"><h3>Needs & Stability</h3><div class="content"><div class="storage-row"><span>Food Need</span><span>'+m.needs.food+'%</span></div><div class="storage-row"><span>Housing Need</span><span>'+m.needs.housing+'%</span></div><div class="storage-row"><span>Morale</span><span>'+m.needs.morale+'%</span></div><div class="storage-row"><span>Overall Stability</span><span>'+m.needs.overall+'%</span></div><div class="storage-row"><span>Crime Pressure</span><span class="bad">'+m.crimePressure+'%</span></div><div class="storage-row"><span>Disorder Pressure</span><span class="bad">'+m.disorderPressure+'%</span></div><div class="storage-row"><span>Security Need</span><span>'+m.securityNeed+'%</span></div></div></div><div class="panel"><h3>Policies</h3><div class="content"><div class="storage-row"><span>Economic Focus</span><span>'+game.policies.focus+'</span></div><div class="controls"><button class="mini-btn" data-policy="focus" data-value="balanced">Balanced</button><button class="mini-btn" data-policy="focus" data-value="agrarian">Agrarian</button><button class="mini-btn" data-policy="focus" data-value="industrial">Industrial</button><button class="mini-btn" data-policy="focus" data-value="spiritual">Spiritual</button></div><div class="rule"></div><div class="storage-row"><span>Labor Policy</span><span>'+game.policies.labor+'</span></div><div class="controls"><button class="mini-btn" data-policy="labor" data-value="balanced">Balanced</button><button class="mini-btn" data-policy="labor" data-value="hard">Hard Labor</button><button class="mini-btn" data-policy="labor" data-value="relaxed">Relaxed</button></div><div class="rule"></div><div class="storage-row"><span>Growth Policy</span><span>'+game.policies.growth+'</span></div><div class="controls"><button class="mini-btn" data-policy="growth" data-value="balanced">Balanced</button><button class="mini-btn" data-policy="growth" data-value="encourage">Encourage</button><button class="mini-btn" data-policy="growth" data-value="restrict">Restrict</button></div><div class="rule"></div><div class="storage-row"><span>Migration Policy</span><span>'+game.policies.migration+'</span></div><div class="controls"><button class="mini-btn" data-policy="migration" data-value="controlled">Controlled</button><button class="mini-btn" data-policy="migration" data-value="open">Open</button><button class="mini-btn" data-policy="migration" data-value="closed">Closed</button></div><div class="rule"></div><div class="storage-row"><span>Religion Policy</span><span>'+game.policies.religion+'</span></div><div class="controls"><button class="mini-btn" data-policy="religion" data-value="neutral">Neutral</button><button class="mini-btn" data-policy="religion" data-value="mandatory">Mandatory Worship</button><button class="mini-btn" data-policy="religion" data-value="freedom">Religious Freedom</button><button class="mini-btn" data-policy="religion" data-value="state">State Religion</button></div></div></div><div class="panel"><h3>Laws</h3><div class="content"><div class="controls"><button class="mini-btn" data-law="curfew">Curfew: '+(game.laws.curfew?'ON':'OFF')+'</button><button class="mini-btn" data-law="policing">Policing: '+(game.laws.policing?'ON':'OFF')+'</button><button class="mini-btn" data-law="taxRelief">Tax Relief: '+(game.laws.taxRelief?'ON':'OFF')+'</button><button class="mini-btn" data-law="publicWorks">Public Works: '+(game.laws.publicWorks?'ON':'OFF')+'</button></div></div></div><div class="panel"><h3>Edicts</h3><div class="content"><div class="storage-row"><span>Rationing</span><span>'+game.edicts.rationing+'s</span></div><button class="mini-btn" data-edict="rationing">Start Rationing</button><div class="storage-row"><span>Festival</span><span>'+game.edicts.festival+'s</span></div><button class="mini-btn" data-edict="festival" '+(!canAfford({food:40,gold:10})?'disabled':'')+'>Hold Festival</button><div class="storage-row"><span>Forced Labor</span><span>'+game.edicts.forcedLabor+'s</span></div><button class="mini-btn" data-edict="forcedLabor" '+(!canAfford({faith:10})?'disabled':'')+'>Enforce Forced Labor</button></div></div><div class="panel"><h3>Social Classes</h3><div class="content"><div class="storage-row"><span>Peasants</span><span>'+(game.classes.peasants||0)+'</span></div><div class="storage-row"><span>Skilled Workers</span><span>'+(game.classes.skilled||0)+'</span></div><div class="storage-row"><span>Elites</span><span>'+(game.classes.elites||0)+'</span></div><div class="box-sub">Skilled workers increase productivity. Elites increase happiness but consume more food.</div></div></div>';document.querySelectorAll('[data-policy]').forEach(btn=>btn.onclick=()=>setPolicy(btn.dataset.policy,btn.dataset.value));document.querySelectorAll('[data-law]').forEach(btn=>btn.onclick=()=>toggleLaw(btn.dataset.law));document.querySelectorAll('[data-edict]').forEach(btn=>btn.onclick=()=>startEdict(btn.dataset.edict))}
function workAgePolicyLabel(v){return{everyone:'Everyone Works',noElders:'Respect Your Elders',noKids:'Let Them Be Kids',onlyAdults:'Only Adults Work'}[v]||'Only Adults Work'}
function beginReligiousLawChange(){game.policies.religion='neutral';game.religiousLaw='none';game.deity=null;game.logs.unshift(eventStamp()+' Religious law opened for change.');refreshAll();if(activeTab==='Deities')renderDeityTab();if(activeTab==='Population')renderPopulationTab()}
function chooseReligiousLaw(law){if(!['mandatory','state','freedom'].includes(law))return;game.policies.religion=law;game.religiousLaw=law;if(law==='freedom')game.deity=null;game.logs.unshift(eventStamp()+' Religious law chosen: '+law+'.');refreshAll();if(activeTab==='Deities')renderDeityTab();if(activeTab==='Population')renderPopulationTab()}
function renderDeityTab(){
  activeTab='Deities';
  $('mainArea').classList.remove('population-mode','buildings-mode');
  const law=game.policies.religion||'neutral';
  const needsDeity=law==='mandatory'||law==='state';
  const current=getDeity();
  const favor=game.deity?game.deityFavor[game.deity]:0;
  const converted=game.religiousPopulation.converted;
  const convPct=game.population?Math.round(converted/game.population*100):0;

  if(law==='neutral'){
    $('mainArea').innerHTML='<div class="panel"><h3>Choose Religious Law</h3><div class="content"><div class="box-sub">Choose how religion is organized before assigning divine authority.</div><div class="controls"><button class="mini-btn" data-religion-law="mandatory">Mandatory Worship</button><button class="mini-btn" data-religion-law="state">State Worship</button><button class="mini-btn" data-religion-law="freedom">Free Worship</button></div></div></div>';
    document.querySelectorAll('[data-religion-law]').forEach(b=>b.onclick=()=>chooseReligiousLaw(b.dataset.religionLaw));
    return;
  }

  const lawName=law==='freedom'?'Free Worship':law==='state'?'State Worship':'Mandatory Worship';
  const lawPanel='<div class="panel"><h3>Religious Law</h3><div class="content"><div class="storage-row"><span>Current Law</span><span>'+lawName+'</span></div><div class="storage-row"><span>Chosen Deity</span><span>'+(current?current.name:'None')+'</span></div><div class="storage-row"><span>Favor</span><span>'+Math.round(favor)+'/100</span></div><button class="mini-btn" id="changeReligiousLawBtn">Change Religious Law</button></div></div>';
  const deityCards=Object.entries(deityDefs).map(([key,d])=>'<div class="upgrade-row"><div class="upgrade-top"><div class="upgrade-name"><span>'+d.name+'</span></div><div>'+(game.deity===key?'Chosen':'Favor: '+Math.round(game.deityFavor[key]))+'</div></div><div class="box-sub">'+d.desc+'</div><button class="mini-btn" data-deity="'+key+'" '+(game.deity===key?'disabled':'')+'>'+(game.deity===key?'Chosen':'Choose')+'</button></div>').join('');
  const choosePanel=needsDeity?'<div class="panel"><h3>Choose Deity</h3><div class="content">'+deityCards+'</div></div>':'';

  if(needsDeity&&!game.deity){
    $('mainArea').innerHTML=lawPanel+choosePanel;
    if($('changeReligiousLawBtn'))$('changeReligiousLawBtn').onclick=beginReligiousLawChange;
    document.querySelectorAll('[data-deity]').forEach(b=>b.onclick=()=>chooseDeity(b.dataset.deity));
    return;
  }

  const divineActions=[
    ['bless','Bless Crops','25','+50% food production for 30s'],
    ['calm','Calm People','20','Instantly reduces disorder'],
    ['protect','Divine Protection','30','Reduces raid threat and danger'],
    ['inspire','Inspire Workers','20','Reduces fatigue and boosts work'],
    ['convert','Send Missionaries','35','Adds conversion progress'],
    ['heal','Healing Prayer','30','Heals a portion of current injuries'],
    ['tithe','Call for Offerings','45','Turns faith into a burst of gold']
  ].map(([key,name,cost,desc])=>'<div class="upgrade-row"><div class="upgrade-top"><div class="upgrade-name"><span>'+name+'</span></div><div>'+cost+' Faith</div></div><div class="box-sub">'+desc+'</div><button class="mini-btn" data-divine="'+key+'" '+(game.resources.faith<Number(cost)?'disabled':'')+'>Invoke</button></div>').join('');
  const divinePanel='<div class="panel"><h3>Divine Power</h3><div class="content"><div class="storage-row"><span>Faith</span><span>'+formatNum(game.resources.faith)+'</span></div>'+divineActions+'</div></div>';

  const ritualDefs=[['harvest','Harvest Ritual','60',game.rituals.harvestRitual,'+30% food production for 90s'],['war','War Chant','60',game.rituals.warChant,'+military strength and fear for 90s'],['purify','Purification','50',game.rituals.purification,'-crime and -disorder for 90s']];
  const ritualRows=ritualDefs.map(([key,name,cost,time,desc])=>'<div class="upgrade-row"><div class="upgrade-top"><div class="upgrade-name"><span>'+name+'</span></div><div>'+(time>0?time+'s active':cost+' Faith')+'</div></div><div class="box-sub">'+desc+'</div><button class="mini-btn" data-ritual="'+key+'" '+(time>0||game.resources.faith<Number(cost)?'disabled':'')+'>'+(time>0?'Active':'Begin')+'</button></div>').join('');
  const ritualPanel='<div class="panel"><h3>Rituals</h3><div class="content">'+ritualRows+'</div></div>';

  const doctrineDefs=[['efficientWorship','Efficient Worship',{faith:100,wood:40},'Priests produce 50% more faith'],['holyDiscipline','Holy Discipline',{faith:120,stone:50},'Priests suppress crime and disorder better'],['divineEconomy','Divine Economy',{faith:150,gold:50},'Faith generates gold over time'],['missionaryOrders','Missionary Orders',{faith:130,food:60},'Conversion progresses faster'],['sacredArchives','Sacred Archives',{faith:160,wood:90,stone:70},'Priests produce more faith and support education'],['charitableHospices','Charitable Hospices',{faith:140,food:90,gold:30},'Reduces mortality and supports the sick']];
  const doctrineRows=doctrineDefs.map(([key,name,cost,desc])=>'<div class="upgrade-row"><div class="upgrade-top"><div class="upgrade-name"><span>'+name+'</span></div><div>'+(game.doctrine[key]?'Owned':formatCost(cost))+'</div></div><div class="box-sub">'+desc+'</div><button class="mini-btn" data-doctrine="'+key+'" '+(game.doctrine[key]||!canAfford(cost)?'disabled':'')+'>'+(game.doctrine[key]?'Owned':'Buy')+'</button></div>').join('');
  const doctrinePanel='<div class="panel"><h3>Doctrine</h3><div class="content"><div class="storage-row"><span>Converted</span><span>'+converted+'/'+game.population+' ('+convPct+'%)</span></div><div class="storage-row"><span>Conversion Progress</span><span>'+Math.floor(game.religiousPopulation.conversionProgress)+'%</span></div>'+doctrineRows+'</div></div>';

  const deityUpgradeRows=current?Object.entries(deityUpgradeDefs[game.deity]||{}).map(([key,u])=>'<div class="upgrade-row"><div class="upgrade-top"><div class="upgrade-name"><span>'+u.name+'</span></div><div>'+(game.deityUpgrades[game.deity][key]?'Owned':formatCost(u.cost))+'</div></div><div class="box-sub">'+u.desc+'</div><button class="mini-btn" data-deity-upgrade="'+key+'" '+(game.deityUpgrades[game.deity][key]||!canAfford(u.cost)?'disabled':'')+'>'+(game.deityUpgrades[game.deity][key]?'Owned':'Buy')+'</button></div>').join(''):'<div class="box-sub">Free worship does not require a patron deity, so deity upgrades are unavailable.</div>';
  const deityUpgradePanel='<div class="panel"><h3>Deity Upgrades</h3><div class="content">'+deityUpgradeRows+'</div></div>';

  $('mainArea').innerHTML=lawPanel+choosePanel+divinePanel+ritualPanel+doctrinePanel+deityUpgradePanel;
  if($('changeReligiousLawBtn'))$('changeReligiousLawBtn').onclick=beginReligiousLawChange;
  document.querySelectorAll('[data-deity]').forEach(b=>b.onclick=()=>chooseDeity(b.dataset.deity));
  document.querySelectorAll('[data-divine]').forEach(b=>b.onclick=()=>divineAction(b.dataset.divine));
  document.querySelectorAll('[data-ritual]').forEach(b=>b.onclick=()=>startRitual(b.dataset.ritual));
  document.querySelectorAll('[data-doctrine]').forEach(b=>b.onclick=()=>buyDoctrine(b.dataset.doctrine));
  document.querySelectorAll('[data-deity-upgrade]').forEach(b=>b.onclick=()=>buyDeityUpgrade(b.dataset.deityUpgrade));
}
function renderPopulationClassRows(){return'<div class="storage-row"><span>Peasants</span><span>'+(game.classes.peasants||0)+'</span></div>'+(buildingCount('workshop')>0?'<div class="storage-row"><span>Skilled Workers</span><span>'+(game.classes.skilled||0)+'</span></div>':'<div class="storage-row"><span>Undiscovered Class</span><span class="muted">Build Workshop</span></div>')+(eliteUnlocked()?'<div class="storage-row"><span>Elites</span><span>'+(game.classes.elites||0)+'</span></div>':'<div class="storage-row"><span>Undiscovered Class</span><span class="muted">Build Mansion</span></div>')+'<div class="box-sub">Skilled workers increase productivity. Elites increase happiness but consume more food.</div>'}
function renderAgeControlsPanel(){const ratio=BALANCE.population.childSupportPerAdult,maxKids=Math.max(0,(game.ages.adults||0)*ratio),excess=Math.max(0,(game.ages.children||0)-maxKids),s=getSocietyMetrics(),land=getLandStats(),opts=['peasants','skilled','elites'].filter(c=>c==='peasants'||(c==='skilled'&&buildingCount('workshop')>0)||(c==='elites'&&eliteUnlocked())).map(c=>'<option value="'+c+'">'+c+'</option>').join(''),buttons=age=>['1','5','10','100','custom'].map(a=>'<button class="mini-btn" data-remove-age="'+age+'" data-age-amount="'+a+'">Remove '+a+'</button>').join('');return'<div class="panel"><h3>Age Controls</h3><div class="content"><div class="storage-row"><span>Remove Class</span><span><select class="select-control" id="ageRemoveClass">'+opts+'</select></span></div><div class="storage-row"><span>Adults</span><span>'+(game.ages.adults||0)+'</span></div><div class="controls">'+buttons('adults')+'</div><div class="storage-row"><span>Children</span><span>'+(game.ages.children||0)+' / supported '+maxKids+'</span></div><div class="controls">'+buttons('children')+'</div><div class="storage-row"><span>Elders</span><span>'+(game.ages.elders||0)+'</span></div><div class="controls">'+buttons('elders')+'</div><div class="box-sub">'+(excess>0?'Too many children for the adult population. Excess children will come of age early or be lost automatically.':'Children are within the 1 adult per '+ratio+' children support ratio.')+'</div></div></div><div class="panel"><h3>Society</h3><div class="content"><div class="storage-row society-metric" data-society-tip="loyalty"><span>Loyalty</span><span>'+Math.round(s.loyalty)+'%</span></div><div class="storage-row society-metric" data-society-tip="obedience"><span>Obedience</span><span>'+Math.round(s.obedience)+'%</span></div><div class="storage-row society-metric" data-society-tip="education"><span>Education</span><span>'+Math.round(s.education)+'%</span></div><div class="storage-row society-metric" data-society-tip="health"><span>Health</span><span>'+Math.round(s.health)+'%</span></div><div class="storage-row"><span>Land</span><span>'+land.used+'/'+land.cap+'</span></div><div class="storage-row"><span>Age</span><span>'+getSettlementAge()+'</span></div><div class="box-sub">High fear raises obedience but can lower loyalty. Education improves productivity but can increase social tension.</div></div></div>'}
const renderPopulationTabCore=renderPopulationTab;
renderPopulationTab=function(){renderPopulationTabCore();$('mainArea').classList.add('masonry-mode');const panels=Array.from(document.querySelectorAll('#mainArea .panel')),social=panels.find(p=>p.querySelector('h3')?.textContent==='Social Classes');if(social&&social.querySelector('.content'))social.querySelector('.content').innerHTML=renderPopulationClassRows();$('mainArea').insertAdjacentHTML('beforeend',renderAgeControlsPanel());document.querySelectorAll('[data-remove-age]').forEach(btn=>btn.onclick=()=>removeSpecificAge(btn.dataset.removeAge,btn.dataset.ageAmount,$('ageRemoveClass')?.value||'peasants'));makePopulationPanelsCollapsible();applyMasonryLayout($('mainArea'))}
const worldSectorDefs={north:{name:'Northern Pines',base:16,theme:'wood'},east:{name:'River March',base:22,theme:'food'},south:{name:'Sunken Fields',base:28,theme:'food'},west:{name:'Stone Marches',base:34,theme:'stone'},ridge:{name:'Iron Ridge',base:46,theme:'stone'},coast:{name:'Salt Coast',base:54,theme:'gold'},moor:{name:'Red Moor',base:64,theme:'gold'},crown:{name:'Crownhold Border',base:78,theme:'mixed'},wilds:{name:'Outer Wilds',base:92,theme:'mixed'}};
function currentMonthIndex(){return (game.year-1)*12+game.month}
function ensureBreakthroughState(){game.breakthrough=game.breakthrough||{};if(!game.breakthrough.stageKey)game.breakthrough.stageKey=getProgressionStage().key;if(!Number.isFinite(game.breakthrough.discountUntilMonth))game.breakthrough.discountUntilMonth=0}
function breakthroughMonthsLeft(){ensureBreakthroughState();return Math.max(0,game.breakthrough.discountUntilMonth-currentMonthIndex())}
function getBreakthroughCostMultiplier(){return breakthroughMonthsLeft()>0?.9:1}
function applyCostMultiplier(cost,mult=getBreakthroughCostMultiplier()){const out={};Object.entries(cost||{}).forEach(([r,a])=>out[r]=Math.max(1,Math.ceil(a*mult)));return out}
function checkProgressionBreakthrough(){ensureBreakthroughState();const stage=getProgressionStage();if(stage.key===game.breakthrough.stageKey)return;const old=game.breakthrough.stageKey;game.breakthrough.stageKey=stage.key;game.breakthrough.discountUntilMonth=currentMonthIndex()+24;const reward=eraRewardInfo(stage.key).reward;game.logs.unshift(eventStamp()+' Breakthrough: '+stage.label+' reached. All major costs are reduced by 10% for 2 in-game years.');game.logs.unshift(eventStamp()+' Milestone Reward: '+reward);game.logs.unshift(eventStamp()+' Progression advanced from '+old+' to '+stage.key+'.');showEraRewardPopup(old,stage)}
function validWorldSectorKey(k){return Object.prototype.hasOwnProperty.call(worldSectorDefs,k)}
function safeWorldSectorKey(k){return validWorldSectorKey(k)?k:'north'}
function normalizeCellIndex(i){i=Number(i);return Number.isInteger(i)&&i>=0&&i<25?i:null}
function parseConquestKeyRaw(key){const parts=String(key||'').split(':'),sectorKey=safeWorldSectorKey(parts[0]),index=normalizeCellIndex(parts[1]);return index==null?null:{sectorKey,index,key:sectorKey+':'+index}}
function parseConquestKey(key){initWorldMap();const parsed=parseConquestKeyRaw(key);if(!parsed)return null;const sector=game.world.sectors?.[parsed.sectorKey],cell=sector?.cells?.[parsed.index];return sector&&cell?Object.assign(parsed,{sector,cell}):null}
function conquestRankForCell(sectorKey,i){const s=worldSectorDefs[safeWorldSectorKey(sectorKey)],score=s.base+i*3;if(i===24)return'Empire';if(score>=140)return'Empire';if(score>=112)return'Kingdom';if(score>=88)return'City';if(score>=64)return'Town';if(i%7===0||score>=44)return'Fortified Town';if(i%5===0||score>=28)return'Village';return'Thorp'}
function conquestLandForRank(rank){return{Thorp:100,Village:250,'Fortified Town':400,Town:650,City:1200,Kingdom:2500,Empire:5000}[rank]||100}
function conquestRewardForRank(rank,resource,boss){const mult={Thorp:1,Village:2.2,'Fortified Town':3.4,Town:5.5,City:9,Kingdom:16,Empire:28}[rank]||1,reward={};reward[resource]=Math.round(45*mult);if(['Town','City','Kingdom','Empire'].includes(rank)||boss)reward.gold=Math.round(18*mult);if(rank==='Kingdom'||rank==='Empire')reward.influence=Math.round(6*mult);return reward}
function createNationCell(sectorKey,i){sectorKey=safeWorldSectorKey(sectorKey);const s=worldSectorDefs[sectorKey],boss=i===24,row=Math.floor(i/5)+1,col=i%5+1,rank=conquestRankForCell(sectorKey,i),theme=s.theme,resource=theme==='mixed'?['food','wood','stone','gold'][i%4]:theme,land=conquestLandForRank(rank),reward=conquestRewardForRank(rank,resource,boss);return{name:(boss?'Seat of ':'')+s.name+' '+row+'-'+col,rank,land,reward,owner:'neutral',boss,scout:null,lastLossMonth:-999,mapVersion:2}}
function recalcConqueredLand(){game.land=game.land||{base:100,bonus:0,conquered:0};game.land.conquered=Object.values(game.world?.sectors||{}).flatMap(sec=>sec.cells||[]).filter(c=>c.owner==='player').reduce((a,c)=>a+(c.land||0),0);return game.land.conquered}
function initWorldMap(){game.world=game.world&&typeof game.world==='object'?game.world:{};game.world.sectors=game.world.sectors&&typeof game.world.sectors==='object'&&!Array.isArray(game.world.sectors)?game.world.sectors:{};Object.keys(game.world.sectors).forEach(k=>{if(!validWorldSectorKey(k))delete game.world.sectors[k]});Object.keys(worldSectorDefs).forEach(k=>{const existing=game.world.sectors[k]&&typeof game.world.sectors[k]==='object'?game.world.sectors[k]:{},source=existing.cells&&typeof existing.cells==='object'?existing.cells:{},cells=Array.from({length:25},(_,i)=>{const prior=(Array.isArray(source)?source[i]:source[i])||{},base=createNationCell(k,i),owner=['player','neutral','enemy'].includes(prior.owner)?prior.owner:'neutral';Object.assign(base,{owner,scout:prior.scout&&typeof prior.scout==='object'?prior.scout:null,lastLossMonth:Number.isFinite(prior.lastLossMonth)?prior.lastLossMonth:-999});['control','loyalty','garrison','output','rebellionRisk'].forEach(prop=>{if(Number.isFinite(prior[prop]))base[prop]=prior[prop]});return base});game.world.sectors[k]=Object.assign({},existing,{opened:!!existing.opened,cells})});if(!validWorldSectorKey(game.world.selectedSector))game.world.selectedSector='north';if(!['world','sector'].includes(game.world.view))game.world.view='world';const target=parseConquestKeyRaw(game.world.target);game.world.target=target?target.key:null;if(game.world.currentConquest){const c=game.world.currentConquest;if(!validWorldSectorKey(c.sectorKey)||normalizeCellIndex(c.index)==null)game.world.currentConquest=null}game.land=game.land||{base:100,bonus:0,conquered:0};recalcConqueredLand()}
function selectConquestSector(k){initWorldMap();k=safeWorldSectorKey(k);if(!game.world.sectors[k])return;game.world.selectedSector=k;game.world.view='sector';game.world.sectors[k].opened=true;renderMilitaryTab()}
function showWorldMap(){game.world.view='world';game.world.target=null;renderMilitaryTab()}
function targetConquestCell(key){const parsed=parseConquestKey(key);game.world.target=parsed?parsed.key:null;renderMilitaryTab()}
function getScoutingLevel(){return Math.max(0,game.modifiers.scoutingLevel||0)+(game.jobs.scout>0?1:0)+(buildingCount('watchtower')>0?1:0)}
function generateEnemyStats(sectorKey,index){const parsed=parseConquestKey(sectorKey+':'+index);if(!parsed)return{power:1,walls:0,units:{guards:0,soldiers:0,archers:0,cavalry:0,sappers:0},rank:'Thorp',lockedMonth:currentMonthIndex()};sectorKey=parsed.sectorKey;index=parsed.index;const s=worldSectorDefs[sectorKey],cell=parsed.cell,seed=(game.year*97+game.month*31+index*17+s.base)%23,rankMult={Thorp:.65,Village:1,'Fortified Town':1.35,Town:1.8,City:2.6,Kingdom:3.8,Empire:5.4}[cell.rank]||1,walls=Math.max(0,Math.round((s.base/22+seed%4+(cell.boss?5:0))*rankMult)),units={guards:Math.max(0,Math.round((s.base/18+seed%3)*rankMult)),soldiers:Math.max(0,Math.round((s.base/22+seed%4+(cell.boss?7:0))*rankMult)),archers:Math.max(0,Math.round((s.base/26+(seed+2)%4+(cell.boss?4:0))*rankMult)),cavalry:Math.max(0,Math.round(((seed+1)%3+(['Empire','Kingdom','City'].includes(cell.rank)?5:cell.rank==='Fortified Town'?2:0))*rankMult)),sappers:Math.max(0,Math.round((seed%2+(cell.boss?2:0)+(['Kingdom','Empire'].includes(cell.rank)?2:0))*rankMult))},power=Math.round(s.base*rankMult+walls*3+units.guards*1.2+units.soldiers*2+units.archers*1.5+units.cavalry*2.4+units.sappers*1.1);return{power,walls,units,rank:cell.rank,lockedMonth:currentMonthIndex()}}
function validScout(cell){return cell?.scout&&currentMonthIndex()-cell.scout.lockedMonth<24}
function getEnemyStats(sectorKey,index,lock=false){const parsed=parseConquestKey(sectorKey+':'+index);if(!parsed)return generateEnemyStats('north',0);const cell=parsed.cell;if(validScout(cell))return cell.scout;if(lock||!cell.scout){cell.scout=generateEnemyStats(parsed.sectorKey,parsed.index);return cell.scout}return cell.scout}
function scoutConquestTarget(){initWorldMap();const parsed=parseConquestKey(game.world.target);if(!parsed||parsed.cell.owner==='player')return;parsed.cell.scout=generateEnemyStats(parsed.sectorKey,parsed.index);game.logs.unshift(eventStamp()+' Scouts returned from '+parsed.cell.name+'. Report is reliable for 2 years unless battle changes it.');refreshAll();if(activeTab==='Military')renderMilitaryTab()}
function scoutReport(cell){if(!validScout(cell))return'<div class="box-sub">Unscouted: select this target and scout it to lock enemy stats.</div>';const level=getScoutingLevel(),s=cell.scout,rough=n=>Math.max(5,Math.round(n/(level>=1?10:25))*(level>=1?10:25)),unitTotal=Object.values(s.units).reduce((a,v)=>a+v,0);let html='<div class="storage-row"><span>Rank</span><span>'+s.rank+'</span></div><div class="storage-row"><span>Enemy Power</span><span>'+(level>=3?s.power:'about '+rough(s.power))+'</span></div><div class="storage-row"><span>Walls</span><span>'+(level>=1?s.walls:'about '+rough(s.walls))+'</span></div>';if(level>=2)html+='<div class="storage-row"><span>Units</span><span>'+(level>=3?'G '+s.units.guards+' / S '+s.units.soldiers+' / A '+s.units.archers+' / Cav '+(s.units.cavalry||0)+' / Sap '+s.units.sappers:'about '+rough(unitTotal)+' total')+'</span></div>';return html}
function conquestEnemyUnits(stats){const u=stats?.units||{};return{infantry:(u.guards||0)+(u.soldiers||0),archers:u.archers||0,cavalry:u.cavalry||0,sappers:u.sappers||0}}
function startConquest(){initWorldMap();if(!game.world.target)return;beginConquest(game.world.target)}
function beginConquest(key){initWorldMap();if(game.world.currentConquest){showConquestPanel();return}const parsed=parseConquestKey(key);if(!parsed||parsed.cell.owner==='player')return;const stats=getEnemyStats(parsed.sectorKey,parsed.index,true),enemyUnits=conquestEnemyUnits(stats),cell=parsed.cell;game.world.currentConquest={key:parsed.key,sectorKey:parsed.sectorKey,index:parsed.index,enemyPower:stats.power,enemyMax:stats.power,enemyUnits,walls:stats.walls,wallMax:stats.walls,round:0,loot:Object.assign({},cell.reward||{}),land:cell.land,name:cell.name,rank:cell.rank,boss:!!cell.boss};game.logs.unshift(eventStamp()+' Conquest started against '+cell.name+'.');refreshAll();showConquestPanel()}
function conquestRegion(key){beginConquest(key)}
function finishConquest(victory){initWorldMap();const c=game.world.currentConquest;if(!c)return;const sector=game.world.sectors?.[c.sectorKey],cell=sector?.cells?.[c.index];if(victory&&cell){cell.owner='player';cell.scout=null;cell.control=clamp(58+legacyTier('conquest','ironGarrisons')*8,0,100);cell.loyalty=48;cell.garrison=0;cell.output=100;cell.rebellionRisk=0;Object.entries(c.loot||{}).forEach(([res,a])=>addResource(res,a));recalcConqueredLand();if(cell.boss)game.world.hostileFactions=Math.max(0,(game.world.hostileFactions||0)-1);const completed=Array.isArray(sector?.cells)&&sector.cells.every(x=>x.owner==='player');game.logs.unshift(eventStamp()+' Conquered '+cell.name+', gaining '+formatWhole(cell.land)+' land and '+formatCost(c.loot)+'.'+(completed?' Sector secured: all production gets another +25%.':''))}else if(cell){cell.lastLossMonth=currentMonthIndex();cell.scout=null;game.threat=clamp(game.threat+(cell.boss?18:9),0,100);game.world.hostileFactions=(game.world.hostileFactions||0)+(cell.boss?2:1);game.logs.unshift(eventStamp()+' Conquest failed against '+cell.name+'. Border enemies are emboldened.')}game.world.currentConquest=null;if(typeof closeModal==='function'&&$('resourceDetailOverlay')?.classList.contains('show'))closeModal();else if($('resourceDetailOverlay'))$('resourceDetailOverlay').classList.remove('show');refreshAll();if(activeTab==='Military')renderMilitaryTab()}
function conquestBattleRound(choice='attack'){const c=game.world.currentConquest;if(!c)return;const enemyStats={units:{guards:0,soldiers:c.enemyUnits.infantry||0,archers:c.enemyUnits.archers||0,cavalry:c.enemyUnits.cavalry||0,sappers:c.enemyUnits.sappers||0}},match=getMatchupModifier(c.enemyUnits||{});let attack=getDefensePower(c.enemyUnits||{}),lossMod=1;if(choice==='cautious'){attack*=.72;lossMod=.55}if(choice==='breach'){attack*=.45+(game.jobs.sapper||0)*.14;lossMod=1.2;c.walls=Math.max(0,c.walls-Math.max(1,Math.round((game.jobs.sapper||0)*3+attack*.05)))}if(c.walls>0)attack*=clamp(1-c.walls*.012,.35,1);const damage=Math.max(1,Math.round(attack*(choice==='cautious'?.22:.34)+Math.random()*5)),counter=Math.max(0,c.enemyPower-attack),loss=Math.min(game.population,Math.ceil((counter/22+Math.random()*1.2)*lossMod));c.round=(c.round||0)+1;c.enemyPower=Math.max(0,c.enemyPower-damage);if(loss>0){losePopulation(loss);addInjuries(Math.ceil(loss*.55),54)}game.logs.unshift(eventStamp()+' Conquest round '+c.round+': dealt '+damage+' damage, lost '+loss+' attackers'+(match.notes.length?' ('+match.notes[0]+')':'')+'.');if(c.enemyPower<=0)return finishConquest(true);if(loss>0&&game.population<=0)return finishConquest(false);refreshAll();showConquestPanel()}
function showConquestPanel(){const c=game.world.currentConquest;if(!c){showModal('Conquest','<div class="box-sub">Select a target on the military map, scout it, then start conquest.</div>');return}const pct=Math.max(0,Math.min(100,Math.round(c.enemyPower/Math.max(1,c.enemyMax)*100))),wallPct=Math.max(0,Math.min(100,Math.round(c.walls/Math.max(1,c.wallMax||c.walls||1)*100))),match=getMatchupModifier(c.enemyUnits||{}),loot=formatCost(c.loot||{});showModal('Conquest Battle','<div class="storage-row"><span>Target</span><span>'+c.name+'</span></div><div class="storage-row"><span>Rank</span><span>'+c.rank+'</span></div><div class="storage-row"><span>Land Reward</span><span class="good">'+formatWhole(c.land)+'</span></div><div class="storage-row"><span>Resource Spoils</span><span class="good">'+loot+'</span></div><div class="storage-row"><span>Enemy Force</span><span class="bad">'+formatWhole(c.enemyPower)+' / '+formatWhole(c.enemyMax)+' ('+pct+'%)</span></div><div class="bar"><div class="fill bad" style="width:'+pct+'%;background:linear-gradient(90deg,#d55959,#ff8585)"></div></div><div class="storage-row"><span>Walls</span><span>'+formatWhole(c.walls)+' / '+formatWhole(c.wallMax||c.walls)+'</span></div><div class="bar"><div class="fill stone" style="width:'+wallPct+'%"></div></div><div class="storage-row"><span>Your Attack</span><span class="good">'+Math.round(getDefensePower(c.enemyUnits||{}))+'</span></div><div class="storage-row"><span>Sappers</span><span>'+(game.jobs.sapper||0)+'</span></div><div class="storage-row"><span>Matchup</span><span class="'+(match.mod>=1?'good':'bad')+'">'+Math.round(match.mod*100)+'%</span></div>'+(match.notes.length?'<div class="box-sub always-info">'+match.notes.join(' ')+'</div>':'')+'<div class="storage-row"><span>Rounds</span><span>'+(c.round||0)+'</span></div><div class="rule"></div><div class="controls"><button class="mini-btn" data-conquest-round="attack">Attack Round</button><button class="mini-btn" data-conquest-round="cautious">Cautious Advance</button><button class="mini-btn" data-conquest-round="breach" '+((game.jobs.sapper||0)<=0?'disabled':'')+'>Breach Walls</button><button class="mini-btn" data-conquest-end="retreat">Retreat</button></div>');document.querySelectorAll('[data-conquest-round]').forEach(b=>b.onclick=()=>conquestBattleRound(b.dataset.conquestRound));document.querySelectorAll('[data-conquest-end]').forEach(b=>b.onclick=()=>finishConquest(false))}
function fortifyTown(){if(!canAfford({wood:25,stone:15}))return;payCost({wood:25,stone:15});game.divineBuffs.divineProtection=Math.max(game.divineBuffs.divineProtection||0,30);game.threat=Math.max(0,game.threat-8);game.logs.unshift(eventStamp()+' The town was fortified for the next raid.');refreshAll();if(activeTab==='Military')renderMilitaryTab()}
function mobilizeCivilians(){if(!game.raidIncoming)return;conscriptVillagers('max')}
function sacrificeDefenseResource(){const opts=['wood','stone','food'].filter(r=>game.resources[r]>=20),r=opts[0];if(!r)return;game.resources[r]-=20;game.threat=Math.max(0,game.threat-12);game.logs.unshift(eventStamp()+' Sacrificed 20 '+r+' to strengthen defenses and lower threat.');refreshAll();if(activeTab==='Military')renderMilitaryTab()}
function militaryQuickRow(job,label,note){const tip={grunt:'Grunts are emergency fighters available before Barracks. They count as half-strength soldiers.',guard:'Guards reduce crime and add steady defensive power.',soldier:'Soldiers are the main frontline defense and conquest force.',archer:'Archers add ranged defense with good efficiency.',scout:'Scouts slow raid threat and improve conquest reports.',sapper:'Sappers break enemy walls during conquest.',medic:'Medics heal injuries and reduce raid losses.'}[job]||note;return'<div class="worker-row" title="'+tip+'"><div class="worker-top"><span>'+label+'</span><span>'+(game.jobs[job]||0)+'</span></div><div class="controls"><button class="mini-btn" data-mil-job="'+job+'" data-mil-amount="-1" title="Remove one '+label.toLowerCase()+' from this role.">-1</button><button class="mini-btn" data-mil-job="'+job+'" data-mil-amount="1" title="Assign one idle adult to '+label.toLowerCase()+'.">+1</button><button class="mini-btn" data-mil-job="'+job+'" data-mil-amount="max" title="Assign all idle adults to '+label.toLowerCase()+'.">+Max</button><span class="muted">'+note+'</span></div></div>'}
function renderMilitaryTab(){activeTab='Military';initWorldMap();$('mainArea').classList.remove('population-mode','buildings-mode');const threatText=game.raidIncoming?'Respond in Raid Box':game.raidAwakened?Math.round(game.threat)+'%':'Dormant',defense=Math.round(getDefensePower()),target=game.world.target,view=game.world.view||'world',selected=game.world.selectedSector||'north',owned=ownedConquestCells().length,complete=completedConquestSectors(),units=militaryQuickRow('guard','Guards','crime control')+militaryQuickRow('soldier','Soldiers','frontline')+militaryQuickRow('archer','Archers','ranged')+militaryQuickRow('scout','Scouts','scouting and threat')+militaryQuickRow('sapper','Sappers','break enemy walls')+militaryQuickRow('medic','Medics','heal injuries'),planning='<div class="panel"><h3>Military Planning</h3><div class="content"><div class="storage-row"><span>Total Defense Power</span><span class="good">'+defense+'</span></div><div class="storage-row"><span>Sappers</span><span>'+(game.jobs.sapper||0)+'</span></div><div class="storage-row"><span>Raid Status</span><span class="bad">'+threatText+'</span></div><div class="storage-row"><span>Expansion Bonus</span><span class="good">+'+Math.round((getExpansionProductionMultiplier()-1)*100)+'%</span></div><div class="storage-row"><span>Held Areas</span><span>'+owned+' / Sectors '+complete+'</span></div><div class="storage-row"><span>Hostile Nations</span><span class="bad">'+(game.world.hostileFactions||0)+'</span></div><div class="storage-row"><span>Victories / Defeats</span><span>'+game.raidStats.victories+' / '+game.raidStats.defeats+'</span></div>'+(game.world.currentConquest?'<div class="controls"><button class="mini-btn save" id="openConquestBtn">Open Conquest Battle</button></div>':'')+'<div class="box-sub">Each held area grants +5% all production. A completed sector grants another +25%.</div></div></div>',assign='<div class="panel"><h3>Assign Units</h3><div class="content"><div class="storage-row"><span>Idle Adults Available</span><span>'+game.jobs.idle+'</span></div>'+units+'</div></div>',emergency='<div class="panel"><h3>Emergency Defense</h3><div class="content"><div class="controls"><button class="mini-btn" id="fortifyTownBtn" '+(!canAfford({wood:25,stone:15})?'disabled':'')+'>Fortify Town</button><button class="mini-btn" id="mobilizeCiviliansBtn" '+(!game.raidIncoming?'disabled':'')+'>Mobilize Civilians</button><button class="mini-btn" id="sacrificeDefenseBtn">Sacrifice Supplies</button></div></div></div>';let mapPanel='';if(view==='world'){const sectorRows=Object.entries(worldSectorDefs).map(([k,s])=>{const sec=game.world.sectors[k],held=sec.cells.filter(c=>c.owner==='player').length,land=sec.cells.filter(c=>c.owner==='player').reduce((a,c)=>a+(c.land||0),0);return'<button class="world-sector" data-sector="'+k+'"><b>'+s.name+'</b><br><span class="muted">'+held+'/25 held - '+formatWhole(land)+' land</span></button>'}).join('');mapPanel='<div class="panel"><h3>World Map</h3><div class="content"><div class="world-map">'+sectorRows+'</div><div class="box-sub">Click a region to zoom into its local 5x5 conquest map.</div></div></div>'}else{const cells=game.world.sectors[selected].cells.map((c,i)=>'<button class="nation-cell '+(c.owner==='player'?'held ':'')+(c.boss?'boss ':'')+(target===selected+':'+i?'active':'')+'" data-target-conquest="'+selected+':'+i+'"><b>'+c.rank+'</b><br>'+c.name.split(' ').slice(-1)[0]+'<br>Land '+formatWhole(c.land)+'</button>').join(''),targetCell=target?game.world.sectors[target.split(':')[0]]?.cells[Number(target.split(':')[1])]:null,targetPanel=targetCell?'<div class="panel"><h3>Target: '+targetCell.name+'</h3><div class="content"><div class="storage-row"><span>Status</span><span>'+(targetCell.owner==='player'?'Held':'Hostile')+'</span></div><div class="storage-row"><span>Land Reward</span><span class="good">'+formatWhole(targetCell.land)+'</span></div><div class="storage-row"><span>Spoils</span><span>'+formatCost(targetCell.reward||{})+'</span></div><div class="storage-row"><span>Scouting</span><span>Level '+getScoutingLevel()+'</span></div>'+scoutReport(targetCell)+'<div class="controls"><button class="mini-btn" id="scoutTargetBtn" '+(targetCell.owner==='player'?'disabled':'')+'>Scout Area</button><button class="mini-btn save" id="startConquestBtn" '+(targetCell.owner==='player'||game.world.currentConquest?'disabled':'')+'>Start Conquest</button></div><div class="box-sub">Scouted stats remain locked for 2 in-game years, or until victory/defeat changes the enemy.</div></div></div>':'<div class="panel"><h3>Target</h3><div class="content"><div class="box-sub">Select a nation, then scout or start conquest.</div></div></div>';mapPanel='<div class="panel"><h3>'+worldSectorDefs[selected].name+'</h3><div class="content"><button class="mini-btn" id="backWorldBtn">Back to World Map</button><div class="rule"></div><div class="nation-grid">'+cells+'</div></div></div>'+targetPanel}$('mainArea').innerHTML=planning+emergency+assign+mapPanel;document.querySelectorAll('[data-sector]').forEach(b=>b.onclick=()=>selectConquestSector(b.dataset.sector));document.querySelectorAll('[data-target-conquest]').forEach(b=>b.onclick=()=>targetConquestCell(b.dataset.targetConquest));if($('openConquestBtn'))$('openConquestBtn').onclick=showConquestPanel;if($('backWorldBtn'))$('backWorldBtn').onclick=showWorldMap;if($('scoutTargetBtn'))$('scoutTargetBtn').onclick=scoutConquestTarget;if($('startConquestBtn'))$('startConquestBtn').onclick=startConquest;if($('fortifyTownBtn'))$('fortifyTownBtn').onclick=fortifyTown;if($('mobilizeCiviliansBtn'))$('mobilizeCiviliansBtn').onclick=mobilizeCivilians;if($('sacrificeDefenseBtn'))$('sacrificeDefenseBtn').onclick=sacrificeDefenseResource;document.querySelectorAll('[data-mil-job][data-mil-amount]').forEach(b=>b.onclick=()=>{assignJob(b.dataset.milJob,b.dataset.milAmount);renderMilitaryTab()});applyMasonryLayout($('mainArea'))}
function masonryColumnCount(){const w=$('mainArea')?.clientWidth||window.innerWidth||1200;if(w<700)return 1;if(w<900)return 2;if(w<1200)return 3;return 4}
function estimatePanelHeight(panel){return 80+panel.textContent.length*.45+panel.querySelectorAll('.upgrade-row,.building-card,.storage-row,.controls').length*26}
function applyMasonryLayout(target){target=target||$('mainArea');if(!target||Array.from(target.children).some(el=>el.classList?.contains('masonry-layout')))return;const items=Array.from(target.children).filter(el=>el.classList?.contains('panel'));if(items.length<2)return;const count=Math.min(masonryColumnCount(),items.length),layout=document.createElement('div'),heights=Array(count).fill(0),cols=heights.map(()=>{const c=document.createElement('div');c.className='masonry-col';layout.appendChild(c);return c});layout.className='masonry-layout left-fill-layout';items.forEach((panel,idx)=>{const i=idx<count?idx:heights.indexOf(Math.min(...heights));cols[i].appendChild(panel);heights[i]+=estimatePanelHeight(panel)});target.appendChild(layout)}
function normalizeHeavyTabLayout(target){target=target||$('mainArea');if(!target)return;$('mainArea')?.classList.add('masonry-mode');applyMasonryLayout(target)}
function useMasonryAfter(renderFn){return function(){renderFn();normalizeHeavyTabLayout($('upgradesContent')||$('mainArea'))}}
renderAchievementsTab=useMasonryAfter(renderAchievementsTab);
renderDeityTab=useMasonryAfter(renderDeityTab);
renderMilitaryTab=useMasonryAfter(renderMilitaryTab);
function setActiveTab(name){tabs.forEach(t=>t.classList.toggle('active',(t.dataset.tab||t.textContent.trim())===name))}
function isTabUnlocked(name){if(name==='Main'||game.devUnlockTabs)return true;if(name==='Buildings'&&game.progression?.buildingsUnlocked)return true;if(name==='Population'&&game.progression?.populationUnlocked)return true;const r=tabRequirements[name];if(name==='Buildings'&&r?.check()){game.progression.buildingsUnlocked=true;return true}if(name==='Population'&&r?.check()){game.progression.populationUnlocked=true;return true}return r?!!r.check():true}
function showLockedBanner(req){const b=$('tabLockBanner');if(!b)return;b.setAttribute('role','status');b.setAttribute('aria-live','polite');b.textContent='LOCKED: You require '+req+' to unlock this.';b.classList.add('show');if(tabLockTimer)clearTimeout(tabLockTimer);tabLockTimer=setTimeout(()=>b.classList.remove('show'),5000)}
function updateTabStates(){tabs.forEach(tab=>{const n=tab.dataset.tab||tab.textContent.trim();tab.classList.toggle('locked',!isTabUnlocked(n))})}
function ensureActiveTabAllowed(){if(activeTab==='Main'||isTabUnlocked(activeTab))return false;activeTab='Main';setActiveTab('Main');if($('mainArea'))$('mainArea').innerHTML=defaultMainAreaHtml;bindMainAreaEvents();return true}
function switchTab(name){if(!isTabUnlocked(name))return showLockedBanner(tabRequirements[name]?.label||'progression');activeTab=name;$('tabLockBanner')?.classList.remove('show');$('mainArea').classList.remove('population-mode','buildings-mode','masonry-mode','main-one-screen','dashboard-main');if(name==='Main')renderMainArea();else if(name==='Population')renderPopulationTab();else if(name==='Buildings')renderBuildingsTab();else if(name==='Upgrades')renderUpgradesTab();else if(name==='Military')renderMilitaryTab();else if(name==='Trade')renderTradeTab();else if(name==='Deities')renderDeityTab();else $('mainArea').innerHTML='<div class="panel"><div class="content">Not implemented</div></div>'}
function renderMainArea(){activeTab='Main';$('mainArea').classList.remove('population-mode','buildings-mode','masonry-mode');$('mainArea').classList.add('main-one-screen','dashboard-main');$('mainArea').innerHTML=defaultMainAreaHtml;refreshAll();makeMainPanelsCompact();bindMainAreaEvents()}
function getClickYield(type){const bonus={food:buildingCount('granary'),wood:buildingCount('lumberyard'),stone:buildingCount('quarry')}[type]||0;return(game.gather[type]||BALANCE.resourceClick.base)+bonus*BALANCE.resourceClick.buildingBonus+(game.modifiers.clickYieldBonus||0)}
function projectPaidTotal(p){return Object.entries(p.cost||{}).reduce((a,[r,c])=>a+Math.min(c,(p.paid||{})[r]||0),0)}
function projectCostTotal(p){return Object.values(p.cost||{}).reduce((a,v)=>a+v,0)}
function projectProgressPct(p){return Math.floor(projectPaidTotal(p)/Math.max(1,projectCostTotal(p))*100)}
function projectComplete(p){return p.type==='remove'?projectPaidTotal(p)<=0:projectPaidTotal(p)>=projectCostTotal(p)}
function buildQueueResourceTotals(){const totals={};(game.buildQueue||[]).forEach(p=>{Object.entries(p.cost||{}).forEach(([r,c])=>{if(!totals[r])totals[r]={paid:0,needed:0,demolish:0};if(p.type==='remove')totals[r].demolish+=Math.ceil(Math.max(0,(p.paid||{})[r]||0));else{totals[r].paid+=Math.floor(Math.max(0,(p.paid||{})[r]||0));totals[r].needed+=Math.ceil(Math.max(0,c-((p.paid||{})[r]||0)))}})});return totals}
function buildQueueResourceSummary(){const totals=buildQueueResourceTotals(),rows=Object.entries(totals).filter(([,v])=>v.paid||v.needed||v.demolish).map(([r,v])=>r+': '+(v.needed?formatWhole(v.needed)+' needed':'')+(v.paid?(v.needed?', ':'')+formatWhole(v.paid)+' used':'')+(v.demolish?(v.needed||v.paid?', ':'')+formatWhole(v.demolish)+' demolition':'')).join(' | ');return rows||'No queued resource use'}
function projectCanReceiveInput(p){if(!p||projectComplete(p))return false;p.paid=p.paid||{};if(p.type==='remove')return Object.values(p.paid||{}).some(v=>v>0);return Object.entries(p.cost||{}).some(([r,c])=>(p.paid[r]||0)<c&&(game.resources[r]||0)>0)}
function activeBuildProjects(){const q=game.buildQueue||[],activeLimit=Math.max(1,game.modifiers.buildParallelProjects||1);return q.filter(projectCanReceiveInput).slice(0,activeLimit)}
function renderBuildQueuePanel(){const q=game.buildQueue||[],activeLimit=Math.max(1,game.modifiers.buildParallelProjects||1),activeIds=new Set(activeBuildProjects().map(p=>p.id)),rate=(game.jobs.builder||0)*(game.modifiers.buildResourcePerBuilder||1)*(game.modifiers.buildSpeedMultiplier||1);if(!q.length)return'<div class="rule"></div><div class="storage-row"><span>Build Queue</span><span>Empty</span></div><div class="box-sub always-info">Queued buildings receive resources from active builders over time.</div>';return'<div class="rule"></div><div class="storage-row"><span>Build Queue</span><span>'+q.length+' queued</span></div><div class="controls"><button class="mini-btn" data-cancel-all-builds="1" title="Cancel every queued construction and demolition project. Paid construction resources are refunded.">Cancel All</button></div><div class="storage-row"><span>Builder Input</span><span>'+formatNum(rate)+'/s across '+formatWhole(Math.min(activeLimit,activeIds.size))+' active</span></div><div class="box-sub always-info">'+buildQueueResourceSummary()+'</div>'+q.slice(0,4).map(p=>{const pct=projectProgressPct(p),active=activeIds.has(p.id),blocked=!active&&!projectComplete(p)&&!projectCanReceiveInput(p),name=buildingDefs[p.key]?.name||p.key,isRemove=p.type==='remove',isConvert=p.type==='convert',fromName=buildingDefs[p.from]?.name||p.from,actionLabel=isRemove?'Removing ':isConvert?'Converting '+fromName+' -> ':'Building ',remaining=Object.entries(p.cost).map(([r,c])=>isRemove?formatWhole(Math.max(0,(p.paid?.[r]||0)))+' '+r:formatWhole(Math.ceil(Math.max(0,c-(p.paid?.[r]||0))))+' '+r).join(', '),used=!isRemove?Object.entries(p.paid||{}).filter(([,a])=>a>0).map(([r,a])=>formatWhole(a)+' '+r).join(', '):'',last=p.lastInput?'<div class="building-cost bad">'+(isRemove?'Demolished ':'-')+formatWhole(p.lastInput.amount)+' '+p.lastInput.resource+'</div>':'',rush=game.hasMarket&&!isRemove?'<button class="mini-btn" data-rush-build="'+p.id+'" data-rush-mode="boost" '+((game.resources.gold||0)<5?'disabled':'')+' title="Spend 5 gold to add 5 construction input to this project.">Rush +5</button><button class="mini-btn" data-rush-build="'+p.id+'" data-rush-mode="finish" '+((game.resources.gold||0)<rushFinishCost(p)?'disabled':'')+' title="Spend gold to complete all remaining resource input.">Finish ('+rushFinishCost(p)+'g)</button>':'';return'<div class="building-card"><div class="building-title"><span>'+(active?'Active: ':blocked?'Waiting Resources: ':'Queued: ')+actionLabel+name+'</span><span>'+formatWhole(pct)+'%</span></div><div class="bar"><div class="fill '+(isRemove?'stone':isConvert?'gold':p.key==='farm'?'':'wood')+'" style="width:'+clamp(pct,0,100)+'%"></div></div><div class="building-cost">'+(isRemove?(active?'Demolition left: ':'Waiting demolition: '):blocked?'Needs resources: ':(active?'Needs: ':'Waiting: '))+remaining+'</div>'+(used?'<div class="building-cost good">Used: '+used+'</div>':'')+last+'<div class="building-actions"><button class="mini-btn" data-cancel-build="'+p.id+'" title="Cancel this queued project. Construction resources already paid are refunded.">Cancel</button>'+rush+'</div></div>'}).join('')+(q.length>4?'<div class="box-sub always-info">+'+(q.length-4)+' more queued.</div>':'')}
function defaultLegacyState(){return{primary:null,primaryLocked:false,runComplete:false,pendingChoices:[],earned:{trade:false,conquest:false,size:false},bonuses:{trade:{caravanDiscipline:0,trustedBrokers:0,safeRoads:0},conquest:{veteranMuster:0,cartographerCorps:0,ironGarrisons:0},size:{foundingFamilies:0,efficientHomesteads:0,crisisMemory:0}},projects:{trade:{active:false,completed:0},conquest:{active:false,completed:0},size:{active:false,completed:0}},startApplied:false}}
function defaultCrisisState(){return{active:false,recovery:0,stableTicks:0,meters:{starvation:0,housing:0,unrest:0,raid:0,disaster:0,trade:0,land:0},cooldowns:{starvation:0,housing:0,unrest:0,raid:0,disaster:0,trade:0,land:0},history:[]}}
function mergeDefaults(target,defs){Object.entries(defs).forEach(([k,v])=>{if(v&&typeof v==='object'&&!Array.isArray(v)){if(!target[k]||typeof target[k]!=='object'||Array.isArray(target[k]))target[k]={};mergeDefaults(target[k],v)}else if(target[k]===undefined)target[k]=v});return target}
function ensureLegacyState(){game.legacy=mergeDefaults(game.legacy||{},defaultLegacyState());game.crisis=mergeDefaults(game.crisis||{},defaultCrisisState());LEGACY_PATHS.forEach(p=>{game.legacy.projects[p]=mergeDefaults(game.legacy.projects[p]||{active:false,completed:0},{active:false,completed:0});game.legacy.earned[p]=!!game.legacy.earned[p];game.legacy.bonuses[p]=mergeDefaults(game.legacy.bonuses[p]||{},defaultLegacyState().bonuses[p])});game.legacy.pendingChoices=(game.legacy.pendingChoices||[]).filter(p=>LEGACY_PATHS.includes(p)&&game.legacy.earned[p])}
function legacyTier(path,key){ensureLegacyState();return Number(game.legacy.bonuses?.[path]?.[key]||0)}
function legacyRole(path){ensureLegacyState();return game.legacy.primary===path?'Primary':game.legacy.earned[path]?'Secondary':'Available'}
function legacyMultiplier(path){ensureLegacyState();return game.legacy.primary===path?1:.5}
function legacyActiveProjectCount(){ensureLegacyState();return LEGACY_PATHS.filter(p=>game.legacy.projects[p]?.active&&!game.legacy.earned[p]).length}
function legacyVisible(){ensureLegacyState();return progressionAtLeast('smallCity')||legacyActiveProjectCount()>0||LEGACY_PATHS.some(p=>game.legacy.earned[p])}
function legacyStage(path){ensureLegacyState();const p=game.legacy.projects[path];return legacyProjectDefs[path]?.stages[p.completed]||null}
function legacyStageReady(path){const s=legacyStage(path);return !!(s&&(!s.requires||s.requires()))}
function startLegacyProject(path){ensureLegacyState();const p=game.legacy.projects[path],def=legacyProjectDefs[path];if(!def||game.legacy.earned[path])return;if(!game.legacy.primary){game.legacy.primary=path;game.logs.unshift(eventStamp()+' Legacy direction declared: '+def.name+' will be your Primary Legacy unless abandoned before Stage 2.')}else if(game.legacy.primary!==path&&!game.legacy.primaryLocked){const old=game.legacy.projects[game.legacy.primary];if(old&&old.completed===0)game.legacy.primary=path}p.active=true;game.logs.unshift(eventStamp()+' Legacy project started: '+def.name+'.');refreshAll();if(activeTab==='Buildings')renderBuildingsTab()}
function abandonLegacyProject(path){ensureLegacyState();const p=game.legacy.projects[path],def=legacyProjectDefs[path];if(!p?.active||p.completed>0||game.legacy.primaryLocked&&game.legacy.primary===path){game.logs.unshift(eventStamp()+' This legacy can no longer be abandoned. Stage 2 has begun.');renderEvents();return}p.active=false;if(game.legacy.primary===path)game.legacy.primary=null;game.logs.unshift(eventStamp()+' Legacy project abandoned: '+def.name+'.');refreshAll();if(activeTab==='Buildings')renderBuildingsTab()}
function completeLegacyStage(path){ensureLegacyState();const p=game.legacy.projects[path],def=legacyProjectDefs[path],stage=legacyStage(path);if(!def||!stage||game.legacy.earned[path])return;if(!p.active)startLegacyProject(path);if(!legacyStageReady(path)){game.logs.unshift(eventStamp()+' Legacy stage locked: '+stage.text);renderEvents();return}if(!canAfford(stage.cost)){game.logs.unshift(eventStamp()+' Legacy stage needs: '+formatCost(missingCost(stage.cost))+'.');renderEvents();return}payCost(stage.cost);p.completed++;if(p.completed>=1&&game.legacy.primary===path)game.legacy.primaryLocked=true;if(p.completed>=def.stages.length){game.legacy.earned[path]=true;p.active=false;if(!game.legacy.pendingChoices.includes(path))game.legacy.pendingChoices.push(path);game.logs.unshift(eventStamp()+' Legacy earned: '+def.name+'. Choose a permanent '+legacyRole(path)+' bonus.');saveLegacyArchive();refreshAll();showLegacyBonusChoice(path);return}game.logs.unshift(eventStamp()+' Legacy stage complete: '+def.name+' - '+stage.name+'.');refreshAll();if(activeTab==='Buildings')renderBuildingsTab()}
function showLegacyBonusChoice(path){ensureLegacyState();const defs=legacyBonusDefs[path],role=legacyRole(path),mult=legacyMultiplier(path);if(!defs)return;showModal('Choose '+role+' Legacy Bonus','<div class="box-sub">This bonus applies to future runs. '+role+' legacies gain '+(mult===1?'full':'half')+' strength, and tiers stack without diminishing returns.</div>'+Object.entries(defs).map(([k,b])=>'<div class="upgrade-row"><div class="upgrade-top"><div class="upgrade-name"><span>'+b.name+'</span></div><div>Tier '+formatNum(legacyTier(path,k))+'</div></div><div class="box-sub">'+b.desc+'</div><button class="mini-btn save" data-legacy-bonus-path="'+path+'" data-legacy-bonus="'+k+'">Choose</button></div>').join(''));document.querySelectorAll('[data-legacy-bonus]').forEach(b=>b.onclick=()=>chooseLegacyBonus(b.dataset.legacyBonusPath,b.dataset.legacyBonus))}
function chooseLegacyBonus(path,key){ensureLegacyState();if(!legacyBonusDefs[path]?.[key])return;game.legacy.bonuses[path][key]=Number(game.legacy.bonuses[path][key]||0)+legacyMultiplier(path);game.legacy.pendingChoices=game.legacy.pendingChoices.filter(p=>p!==path);game.logs.unshift(eventStamp()+' Permanent legacy bonus chosen: '+legacyBonusDefs[path][key].name+' tier '+formatNum(game.legacy.bonuses[path][key])+'.');saveLegacyArchive();closeModal();refreshAll();if(activeTab==='Buildings')renderBuildingsTab()}
function legacyArchivePayload(){ensureLegacyState();initWorldMap();return{version:1,savedAt:new Date().toISOString(),legacy:{earned:game.legacy.earned,bonuses:game.legacy.bonuses},world:{hostileFactions:game.world.hostileFactions||0,sectors:game.world.sectors||{},selectedSector:game.world.selectedSector||null,target:null}}}
function saveLegacyArchive(){try{localStorage.setItem(LEGACY_SAVE_KEY,JSON.stringify(legacyArchivePayload()))}catch(err){}}
function loadLegacyArchive(){try{return JSON.parse(localStorage.getItem(LEGACY_SAVE_KEY)||'null')}catch(err){return null}}
function applyLegacyArchiveToGame(){ensureLegacyState();const a=loadLegacyArchive();if(!a?.legacy)return;deepMerge(game.legacy.earned,a.legacy.earned||{});deepMerge(game.legacy.bonuses,a.legacy.bonuses||{});if(a.world){game.world=Object.assign(game.world||{},a.world);initWorldMap();recalcConqueredLand()}applyLegacyStartFeatures()}
function mergeLegacyBonusesFromArchive(){ensureLegacyState();const a=loadLegacyArchive();if(!a?.legacy)return;deepMerge(game.legacy.earned,a.legacy.earned||{});deepMerge(game.legacy.bonuses,a.legacy.bonuses||{})}
function applyLegacyStartFeatures(){ensureLegacyState();if(game.legacy.startApplied)return;const families=Math.floor(legacyTier('size','foundingFamilies')*5),militia=Math.floor(legacyTier('conquest','veteranMuster')),tradeGold=Math.floor((legacyTier('trade','trustedBrokers')+legacyTier('trade','caravanDiscipline'))*8);for(let i=0;i<families;i++)addAdultToJob('idle','peasants');for(let i=0;i<militia;i++)addAdultToJob('grunt','peasants');if(tradeGold>0)addResource('gold',tradeGold);game.legacy.startApplied=true;if(families||militia||tradeGold)game.logs.unshift(eventStamp()+' Legacy inheritance applied: '+families+' founding family members, '+militia+' militia, '+tradeGold+' gold credit.')}
function renderLegacyStageRow(path){const def=legacyProjectDefs[path],p=game.legacy.projects[path],stage=legacyStage(path),role=legacyRole(path),pending=game.legacy.pendingChoices.includes(path),earned=game.legacy.earned[path];if(earned)return'<div class="upgrade-row"><div class="upgrade-top"><div class="upgrade-name"><span>'+def.name+'</span></div><div class="good">'+role+' earned</div></div><div class="box-sub">'+def.theme+'. Permanent bonus pending: '+(pending?'yes':'no')+'.</div><div class="controls">'+(pending?'<button class="mini-btn save" data-legacy-action="bonus" data-legacy-path="'+path+'">Choose Bonus</button>':'')+'</div></div>';const label=stage?stage.name:'Complete',req=stage?stage.text:'All stages complete',ready=stage&&legacyStageReady(path),afford=stage&&canAfford(stage.cost),btnText=!p.active?'Start':ready&&afford?'Complete '+stage.name:ready?'Needs '+formatCost(missingCost(stage.cost)):'Locked';return'<div class="upgrade-row" title="'+req.replace(/"/g,'&quot;')+'"><div class="upgrade-top"><div class="upgrade-name"><span>'+def.name+'</span></div><div>'+role+' - Stage '+(p.completed+1)+'/3</div></div><div class="box-sub">'+def.theme+': '+req+'</div><div class="building-cost">Cost: '+formatCost(stage?.cost||{})+'</div><div class="controls"><button class="mini-btn save" data-legacy-action="'+(p.active?'stage':'start')+'" data-legacy-path="'+path+'" '+(p.active&&(!ready||!afford)?'disabled':'')+'>'+btnText+'</button>'+(p.active&&p.completed===0?'<button class="mini-btn" data-legacy-action="abandon" data-legacy-path="'+path+'">Abandon</button>':'')+'</div></div>'}
function renderLegacyProjectsPanel(){if(!legacyVisible())return'';ensureLegacyState();const summary='<div class="storage-row"><span>Primary Legacy</span><span>'+(game.legacy.primary?legacyProjectDefs[game.legacy.primary].name+(game.legacy.primaryLocked?' locked':' flexible'):'Not chosen')+'</span></div><div class="storage-row"><span>Earned</span><span>'+LEGACY_PATHS.filter(p=>game.legacy.earned[p]).length+'/3</span></div><div class="box-sub always-info">First project becomes Primary. You may abandon only before Stage 2. Other completed paths become Secondary and grant half-strength permanent bonuses.</div>';const wonder=LEGACY_PATHS.some(p=>game.legacy.earned[p])&&(progressionAtLeast('largeKingdom')||buildingCount('imperialPalace')>0)?'<div class="rule"></div><div class="storage-row"><span>Empire Wonder</span><span class="gold">Ready</span></div><div class="controls"><button class="mini-btn save" data-legacy-action="empire">Complete Empire Wonder</button></div>':'';return panelHtml('buildings','legacy_projects','Legacy Projects',summary+LEGACY_PATHS.map(renderLegacyStageRow).join('')+wonder,'summary-panel legacy-projects-panel')}
function attachLegacyProjectsToBuildings(){const html=renderLegacyProjectsPanel(),land=$('landUsePanel');if(!html||!land||document.querySelector('.legacy-projects-panel'))return;land.insertAdjacentHTML('afterend',html);bindCollapseToggles($('mainArea'));document.querySelectorAll('[data-legacy-action]').forEach(b=>b.onclick=e=>{e.stopPropagation();handleLegacyAction(b.dataset.legacyAction,b.dataset.legacyPath)})}
function handleLegacyAction(action,path){if(action==='start')startLegacyProject(path);else if(action==='stage')completeLegacyStage(path);else if(action==='abandon')abandonLegacyProject(path);else if(action==='bonus')showLegacyBonusChoice(path);else if(action==='empire')showRunCompletionScreen()}
function renderLegacyMainPanel(){if(!legacyVisible())return'';ensureLegacyState();const earned=LEGACY_PATHS.filter(p=>game.legacy.earned[p]).map(p=>legacyProjectDefs[p].name).join(', ')||'None',active=LEGACY_PATHS.filter(p=>game.legacy.projects[p]?.active&&!game.legacy.earned[p]).map(p=>legacyProjectDefs[p].name+' '+game.legacy.projects[p].completed+'/3').join(', ')||'None';return'<div class="rule"></div><div class="storage-row"><span>Primary Legacy</span><span>'+(game.legacy.primary?legacyProjectDefs[game.legacy.primary].name:'Not chosen')+'</span></div><div class="storage-row"><span>Active Legacy</span><span>'+active+'</span></div><div class="storage-row"><span>Earned Legacy</span><span>'+earned+'</span></div>'}
function renderLegacyActiveEffects(){if(!legacyVisible())return'';const pressure=legacyPressureScore();return'<div class="effect-row"><span>Legacy Pressure</span><span class="'+(pressure>45?'bad':pressure>15?'gold':'muted')+'">'+Math.round(pressure)+'%</span></div>'}
function legacyPressureScore(){ensureLegacyState();return LEGACY_PATHS.reduce((a,p)=>{const pr=game.legacy.projects[p];return a+(pr?.active&&!game.legacy.earned[p]?(pr.completed<=0?8:pr.completed===1?28:50):0)},0)}
function renderCollapseRecoveryPanel(){ensureLegacyState();const meters=game.crisis.meters||{},cooldowns=game.crisis.cooldowns||{},top=Object.entries(meters).sort((a,b)=>b[1]-a[1]).slice(0,3).filter(([,v])=>v>10),cooling=Object.entries(cooldowns).filter(([,v])=>v>0).slice(0,2);if(!game.crisis.active&&!top.length&&!cooling.length)return'';return'<div class="crisis-strip">'+(game.crisis.active?'<span class="crisis-chip bad"><b>Collapse</b> recovery '+game.crisis.recovery+'s</span>':'')+top.map(([k,v])=>'<span class="crisis-chip '+(v>70?'bad':'')+'"><b>'+k+'</b> '+Math.round(v)+'%</span>').join('')+cooling.map(([k,v])=>'<span class="crisis-chip"><b>'+k+'</b> cooldown '+formatClock(v).slice(3)+'</span>').join('')+'</div>'}
function showRunCompletionScreen(){ensureLegacyState();game.legacy.runComplete=true;saveLegacyArchive();showModal('Empire Wonder Complete','<div class="box-sub">The empire can end as a dynasty milestone. Earned legacy bonuses apply to the next run; continuing keeps this sandbox alive.</div><div class="storage-row"><span>Primary</span><span>'+(game.legacy.primary?legacyProjectDefs[game.legacy.primary].name:'None')+'</span></div><div class="storage-row"><span>Earned Paths</span><span>'+LEGACY_PATHS.filter(p=>game.legacy.earned[p]).length+'/3</span></div><div class="controls"><button class="mini-btn save" data-run-end="new">Found New World</button><button class="mini-btn" data-run-end="continue">Continue Empire</button><button class="mini-btn" data-run-end="abdicate">Abdicate</button></div>');document.querySelectorAll('[data-run-end]').forEach(b=>b.onclick=()=>handleRunEndChoice(b.dataset.runEnd))}
function handleRunEndChoice(choice){if(choice==='continue'){closeModal();game.logs.unshift(eventStamp()+' The empire continues. Legacy bonuses remain pending for a future restart.');refreshAll();return}saveLegacyArchive();localStorage.removeItem(SAVE_KEY);location.reload()}
function crisisLabel(k){return{starvation:'Starvation',housing:'Housing Pressure',unrest:'Unrest',raid:'Raid Panic',disaster:'Disaster Spiral',trade:'Trade Breakdown',land:'Land Overcrowding'}[k]||k}
function ensureCrisisCooldowns(){ensureLegacyState();game.crisis.cooldowns=Object.assign(defaultCrisisState().cooldowns,game.crisis.cooldowns||{});return game.crisis.cooldowns}
function crisisConditionScores(){const p=getJobProduction(),foodNet=p.food-getFoodConsumption()-getFoodSpoilage(),land=getLandStats(),disasters=activeDisasterEntries().length,tradeBad=game.hasMarket?Math.max(0,45-(game.trade?.standing||50)):0;return{starvation:starvationActive()?Math.min(16,5+Math.abs(Math.min(0,foodNet))*1.2+Math.min(8,game.population*.03)):0,housing:game.population>game.housing?Math.min(8,1.2+(game.population-game.housing)*.06):0,unrest:isSocialPressureActive()&&Math.max(game.crime,game.disorder)>35?Math.max(game.crime,game.disorder)*.055:0,raid:game.raidIncoming?9:game.raidAwakened&&game.threat>80?4:0,disaster:disasters?4+disasters*2:0,trade:tradeBad*.05,land:land.over?Math.min(7,1.5+land.over*.04):0}}
function crisisReliefScores(){const foodRelief=(game.resources.food||0)>0?Math.min(20,getFoodConsumption()):0,openHousing=Math.max(0,game.housing-game.population),land=getLandStats();return{starvation:foodRelief,housing:openHousing,unrest:Math.max(0,45-Math.max(game.crime,game.disorder))*.06,raid:game.raidIncoming?0:Math.max(0,55-game.threat)*.04,disaster:activeDisasterEntries().length?0:1.2,trade:game.hasMarket?Math.max(0,(game.trade?.standing||50)-45)*.05:1,land:land.over?0:Math.max(1,land.cap>0?(land.cap-land.used)/Math.max(25,land.cap)*3:1)}}
function triggerCrisisFactor(k){const label=crisisLabel(k);game.crisis.meters[k]=0;ensureCrisisCooldowns()[k]=300;game.crisis.history.unshift({reason:k,year:game.year,month:game.month,day:game.day});game.crisis.history=game.crisis.history.slice(0,10);if(k==='starvation'){const deaths=Math.min(game.population,Math.max(1,Math.ceil(game.population*.04)));if(deaths>0)losePopulation(deaths);game.popProgress=Object.assign({birth:0,migration:0,death:0},game.popProgress||{});game.popProgress.birth=0;game.popProgress.migration=Math.min(0,game.popProgress.migration);game.happiness=clamp(game.happiness-12,0,100);game.fear=clamp(game.fear+8,0,100);game.disorder=clamp(game.disorder+4,0,100);game.logs.unshift(eventStamp()+' Starvation crisis: '+deaths+' people died before emergency order returned. Births and migration are suppressed until food exists, and starvation is on a 5 minute cooldown.');return}if(k==='housing'){const over=Math.max(0,game.population-game.housing);if(over>0&&game.population>5)losePopulation(Math.max(1,Math.ceil(over*.08)));game.happiness=clamp(game.happiness-8,0,100);game.disorder=clamp(game.disorder+7,0,100)}else if(k==='unrest'){game.happiness=clamp(game.happiness-10,0,100);game.fear=clamp(game.fear+6,0,100);game.disorder=clamp(game.disorder+12,0,100);if(game.population>25)processDissentFactions()}else if(k==='raid'){game.fear=clamp(game.fear+10,0,100);game.happiness=clamp(game.happiness-5,0,100);if(updateRaidAwareness()){game.threat=100;triggerRaid()}}else if(k==='disaster'){const eligible=eligibleDisasters();if(eligible.length)startDisaster(eligible[Math.floor(Math.random()*eligible.length)]);else if(Math.random()<.5)damageRandomBuilding();game.happiness=clamp(game.happiness-5,0,100)}else if(k==='trade'){game.trade.standing=clamp((game.trade?.standing||50)-15,0,100);game.resources.gold=Math.max(0,(game.resources.gold||0)-Math.ceil(10+game.population*.02));game.happiness=clamp(game.happiness-5,0,100)}else if(k==='land'){damageRandomBuilding();game.happiness=clamp(game.happiness-6,0,100);game.disorder=clamp(game.disorder+5,0,100)}game.logs.unshift(eventStamp()+' Crisis triggered: '+label+'. The immediate damage landed, and this crisis is on a 5 minute cooldown.')}
function processCrisisMeters(){ensureLegacyState();const cooldowns=ensureCrisisCooldowns(),scores=crisisConditionScores(),relief=crisisReliefScores(),memory=1-clamp(legacyTier('size','crisisMemory')*.06,0,.65),pressure=legacyPressureScore()*.012;Object.keys(game.crisis.meters).forEach(k=>{if(cooldowns[k]>0){cooldowns[k]=Math.max(0,cooldowns[k]-1);game.crisis.meters[k]=clamp((game.crisis.meters[k]||0)-(relief[k]||1)-1,0,100);return}const score=scores[k]||0,linkedPressure=k==='starvation'&&!starvationActive()?0:pressure,inc=score*memory+linkedPressure,dec=inc?relief[k]||0:Math.max(1,relief[k]||0);game.crisis.meters[k]=clamp((game.crisis.meters[k]||0)+inc-dec,0,100);if(game.crisis.meters[k]>=100)triggerCrisisFactor(k)});if(!game.crisis.active){const vals=Object.values(game.crisis.meters),high=vals.filter(v=>v>=70).length;if(high>=3)beginCollapse('multiple connected crises')}processCollapseState()}
function beginCollapse(reason){game.crisis.active=true;game.crisis.recovery=180;game.crisis.stableTicks=0;game.crisis.history.unshift({reason,year:game.year,month:game.month,day:game.day});game.crisis.history=game.crisis.history.slice(0,10);game.happiness=clamp(game.happiness-10,0,100);game.fear=clamp(game.fear+8,0,100);game.disorder=clamp(game.disorder+10,0,100);game.logs.unshift(eventStamp()+' Collapse state begins: '+reason+' has gone unmanaged too long. Happiness, fear, and disorder now reflect the crisis.')}
function processCollapseState(){if(!game.crisis.active)return;const vals=Object.values(game.crisis.meters),avg=vals.reduce((a,v)=>a+v,0)/Math.max(1,vals.length),stable=vals.every(v=>v<35);game.crisis.recovery=Math.max(0,(game.crisis.recovery||180)-1);game.crisis.stableTicks=stable?(game.crisis.stableTicks||0)+1:0;if(game.time%10===0){game.happiness=clamp(game.happiness-1,0,100);game.fear=clamp(game.fear+1,0,100)}if(game.time%25===0&&avg>55){if(Math.random()<.45)damageRandomBuilding();if(game.population>5)losePopulation(Math.max(1,Math.ceil(game.population*.015)));game.happiness=clamp(game.happiness-2,0,100);game.disorder=clamp(game.disorder+3,0,100)}if(game.crisis.stableTicks>=30){game.crisis.active=false;game.crisis.recovery=0;Object.keys(game.crisis.meters).forEach(k=>game.crisis.meters[k]*=.35);game.logs.unshift(eventStamp()+' Collapse recovery succeeded. The settlement survives with scars.')}else if(game.crisis.recovery<=0||game.population<=0){failCollapseRecovery()}}
function failCollapseRecovery(){game.logs.unshift(eventStamp()+' Collapse recovery failed. The settlement falls back into a damaged thorp, but the world remembers.');Object.keys(game.crisis.meters).forEach(k=>game.crisis.meters[k]=0);game.crisis.active=false;game.crisis.recovery=0;['house','cottage','mansion','market','barracks','wall','watchtower','workshop','granary','lumberyard','quarry','farm'].forEach(k=>{if(game.buildings[k]>0)game.buildings[k]=Math.floor(game.buildings[k]*.65)});game.resources.food=Math.min(game.resources.food,25);game.resources.wood=Math.min(game.resources.wood,25);game.resources.stone=Math.min(game.resources.stone,25);if(game.population<5){for(let i=0;i<5;i++)addAdultToJob('idle','peasants')}game.population=Math.max(5,Math.min(game.population,50));syncPopulationAccounting();applyBuildingEffects();rebalanceWorkforce();saveLegacyArchive()}
function ensureRegionControl(){initWorldMap();const base=55+legacyTier('conquest','ironGarrisons')*8;ownedConquestCells().forEach(c=>{if(c.control==null)c.control=clamp(base,0,100);if(c.loyalty==null)c.loyalty=45;if(c.garrison==null)c.garrison=0;if(c.output==null)c.output=100;if(c.rebellionRisk==null)c.rebellionRisk=0})}
function processRegionControl(){if(game.time%30!==0)return;ensureRegionControl();ownedConquestCells().forEach(c=>{const support=(game.jobs.guard||0)+(game.jobs.soldier||0)+(game.jobs.priest||0)*.6,pressure=Math.max(0,game.disorder-35)*.04+Math.max(0,game.fear-65)*.025;c.control=clamp((c.control||55)+support*.015-pressure,0,100);c.loyalty=clamp((c.loyalty||45)+((c.control||0)>60?.6:-.8)-pressure*.2,0,100);c.rebellionRisk=clamp(100-c.control+(game.disorder||0)*.3-(c.loyalty||0)*.25,0,100);if(c.rebellionRisk>85&&Math.random()<.08){c.owner='enemy';game.world.hostileFactions=(game.world.hostileFactions||0)+1;game.logs.unshift(eventStamp()+' Rebellion: '+c.name+' broke away from your control.');recalcConqueredLand()}})}
function rushFinishCost(p){return Math.max(10,projectCostTotal(p)-projectPaidTotal(p))}
function rushBuildProject(id,mode){const p=(game.buildQueue||[]).find(x=>String(x.id)===String(id));if(!p||p.type==='remove')return;let cost=mode==='finish'?rushFinishCost(p):5;if((game.resources.gold||0)<cost)return;game.resources.gold-=cost;if(mode==='finish'){Object.entries(p.cost||{}).forEach(([r,c])=>p.paid[r]=c);completeBuildProject(p);game.buildQueue=(game.buildQueue||[]).filter(x=>!projectComplete(x));game.logs.unshift(eventStamp()+' Gold rushed completion: '+(buildingDefs[p.key]?.name||p.key)+'.')}else{let left=5;for(const r of Object.keys(p.cost||{})){if(left<=0)break;const need=Math.max(0,p.cost[r]-(p.paid[r]||0)),add=Math.min(left,need);p.paid[r]=(p.paid[r]||0)+add;left-=add}if(projectComplete(p)){completeBuildProject(p);game.buildQueue=(game.buildQueue||[]).filter(x=>!projectComplete(x))}game.logs.unshift(eventStamp()+' Spent 5 gold to rush '+(buildingDefs[p.key]?.name||p.key)+'.')}refreshAll();if(activeTab==='Buildings')renderBuildingsTab()}
function inputResourceToProject(p){p.paid=p.paid||{};if(p.type==='remove'){const needs=Object.entries(p.cost||{}).filter(([r])=>(p.paid[r]||0)>0);if(!needs.length)return false;const r=needs[0][0],take=Math.min(1,p.paid[r]||0);p.paid[r]=Math.max(0,(p.paid[r]||0)-take);p.lastInput={resource:r,amount:take,timer:2};return true}const needs=Object.entries(p.cost||{}).filter(([r,c])=>(p.paid[r]||0)<c&&(game.resources[r]||0)>0);if(!needs.length)return false;needs.sort((a,b)=>(a[1]-(p.paid[a[0]]||0))-(b[1]-(p.paid[b[0]]||0)));const r=needs[0][0],take=Math.min(1,game.resources[r],p.cost[r]-(p.paid[r]||0));if(take<=0)return false;game.resources[r]-=take;p.paid[r]=(p.paid[r]||0)+take;p.lastInput={resource:r,amount:take,timer:2};return true}
function cancelBuildProject(id){const q=game.buildQueue||[],idx=q.findIndex(p=>String(p.id)===String(id));if(idx<0)return;const p=q[idx],name=buildingDefs[p.key]?.name||p.key;if(p.type!=='remove')Object.entries(p.paid||{}).forEach(([r,a])=>{if(a>0)addResource(r,a)});q.splice(idx,1);game.buildQueue=q;game.logs.unshift(eventStamp()+' Canceled queued '+(p.type==='remove'?'demolition':'construction')+': '+name+'.');refreshAll();if(activeTab==='Buildings')renderBuildingsTab()}
function cancelAllBuildProjects(){const q=game.buildQueue||[];if(!q.length)return;let refunded=0;q.forEach(p=>{if(p.type!=='remove')Object.entries(p.paid||{}).forEach(([r,a])=>{if(a>0){addResource(r,a);refunded+=a}})});game.buildQueue=[];game.logs.unshift(eventStamp()+' Canceled all queued building work'+(refunded?' and refunded '+formatWhole(refunded)+' paid resources.':'.'));refreshAll();if(activeTab==='Buildings')renderBuildingsTab()}
function completeBuildProject(p){if(p.type==='remove'){game.buildings[p.key]=Math.max(0,buildingCount(p.key)-1);applyBuildingEffects();game.logs.unshift(eventStamp()+' Demolition complete: '+buildingDefs[p.key].name+'.');return}if(p.type==='convert'){game.buildings[p.from]=Math.max(0,buildingCount(p.from)-1);game.buildings[p.key]=buildingCount(p.key)+1;applyBuildingEffects();game.logs.unshift(eventStamp()+' Conversion complete: '+buildingDefs[p.from].name+' -> '+buildingDefs[p.key].name+'.');return}game.buildings[p.key]=buildingCount(p.key)+1;applyBuildingEffects();game.logs.unshift(eventStamp()+' Construction complete: '+buildingDefs[p.key].name+'.')}
function processBuildQueue(){const q=game.buildQueue||[];q.forEach(p=>{if(p.lastInput&&p.lastInput.timer>0)p.lastInput.timer--;if(p.lastInput&&p.lastInput.timer<=0)delete p.lastInput});if(!q.length||game.jobs.builder<1)return;const totalRate=(game.jobs.builder||0)*(game.modifiers.buildResourcePerBuilder||1)*(game.modifiers.buildSpeedMultiplier||1);let work=Math.max(0,totalRate);while(work>=1){const active=activeBuildProjects();if(!active.length)break;let moved=false;for(const p of active){if(work<1)break;if(inputResourceToProject(p)){work--;moved=true;if(projectComplete(p))completeBuildProject(p)}}game.buildQueue=(game.buildQueue||q).filter(p=>!projectComplete(p));if(!moved)break}if(work>0&&Math.random()<work){const active=activeBuildProjects();for(const p of active){if(inputResourceToProject(p)){if(projectComplete(p))completeBuildProject(p);break}}game.buildQueue=(game.buildQueue||[]).filter(p=>!projectComplete(p))}}
function resourceFlingIcon(type,e){if(!e||!document.body)return;const icons={food:'🍎',wood:'🪵',stone:'🪨'};const el=document.createElement('div');el.className='resource-pop';el.textContent=icons[type]||'+';el.style.left=e.clientX+'px';el.style.top=e.clientY+'px';el.style.setProperty('--dx',(Math.random()*80-40)+'px');el.style.setProperty('--dy',(-70-Math.random()*55)+'px');el.style.setProperty('--rot',(Math.random()*90-45)+'deg');document.body.appendChild(el);el.addEventListener('animationend',()=>el.remove())}
function gatherResource(type,e){if(!(type in game.gather))return;resourceFlingIcon(type,e);game.resources[type]=clamp(game.resources[type]+getClickYield(type),0,game.storage[type]);refreshAll();if(activeTab==='Buildings')renderBuildingsTab()}
function addAdultToJob(job,classType='peasants'){job=canHireJob(job)?job:'idle';addWorkerRecord(game,{age:'adults',classType,job});if(job==='builder')game.builderAutoReplace=true}
function moveExistingAdultToJob(job,classType='peasants'){job=canHireJob(job)?job:'idle';const changed=ageWorkerRecords(game,{from:'children',to:'adults',job,count:1});if(!changed)addWorkerRecord(game,{age:'adults',classType,job});if(job==='builder')game.builderAutoReplace=true}
function recruitVillagers(amount){ensureClassJobs();game.recruitOptions.amount=amount||game.recruitOptions.amount;amount=recruitAmountValue();if(!Number.isFinite(amount)||amount<=0)return;let job=canHireJob(game.recruitOptions.job)?game.recruitOptions.job:'idle',classType=game.recruitOptions.classType||'peasants',hired=0;if(classType==='elites'&&!eliteUnlocked())classType='peasants';for(let i=0;i<amount;i++){const cost=recruitClassCost(classType);if(!canAfford(cost))break;payCost(cost);addAdultToJob(job,classType);hired++}if(hired>0)game.logs.unshift(eventStamp()+' Hired '+hired+' '+classType+' as '+job+'.');refreshAll()}
function assignJob(job,amount){syncPopulationAccounting();if(!Object.prototype.hasOwnProperty.call(game.jobs,job))return;const age=game.jobAssignAge||'adults',elig=getWorkAgeEligibility(),idleAges=getIdleAgeCounts();if(amount==='max')amount=age&&idleAges[age]!=null?idleAges[age]:game.jobs.idle;if(amount==='-max')amount=-game.jobs[job];amount=Number(amount);if(!Number.isFinite(amount)||amount===0)return;if(amount>0){if(age==='children'&&!elig.children){game.logs.unshift(eventStamp()+' Policy prevents children from working.');refreshAll();return}if(age==='elders'&&!elig.elders&&job!=='priest'){game.logs.unshift(eventStamp()+' Policy prevents elder labor; elders may only serve as priests.');refreshAll();return}amount=Math.min(amount,idleAges[age]||0);if(amount<=0){game.logs.unshift(eventStamp()+' No idle '+age+' are available.');refreshAll();return}const moved=assignWorkerRecords(game,{from:'idle',to:job,age,count:amount});if(job==='builder'&&moved>0)game.builderAutoReplace=true}else{const remove=Math.abs(amount);const moved=assignWorkerRecords(game,{from:job,to:'idle',count:remove});if(job==='builder'&&moved>0)game.builderAutoReplace=false}game.patrols=clamp(game.patrols,0,game.jobs.guard+game.jobs.scout);refreshAll()}
function removeSpecificAge(age,amount,classType='peasants'){if(amount==='custom')amount=prompt('Remove how many '+age+'?','1');amount=Math.max(0,Number(amount)||0);if(amount<=0||!['children','adults','elders'].includes(age))return;classType=game.classes[classType]!=null?classType:'peasants';const removed=removeWorkerRecords(game,{age,classType,count:amount}).length;if(removed<=0){game.logs.unshift(eventStamp()+' No matching '+classType+' '+age+' to remove.');renderEvents();return}rebalanceWorkforce();game.logs.unshift(eventStamp()+' Removed '+removed+' '+classType+' '+age+'.');refreshAll();if(activeTab==='Population')renderPopulationTab()}
function enforceChildAdultRatio(){syncPopulationAccounting();let children=game.ages.children||0,adults=game.ages.adults||0;if(children<=0)return;if(adults<=0){moveExistingAdultToJob(game.builderAutoReplace&&game.jobs.builder<1?'builder':'idle','peasants');children--;adults++;game.logs.unshift(eventStamp()+' An older child came of age early to keep the hamlet functioning.')}const maxChildren=Math.max(0,(game.ages.adults||0)*BALANCE.population.childSupportPerAdult),excess=Math.max(0,(game.ages.children||0)-maxChildren);if(excess<=0)return;const promote=Math.ceil(excess*.75),lost=excess-promote;for(let i=0;i<promote;i++){if((game.ages.children||0)<=0)break;moveExistingAdultToJob(game.builderAutoReplace&&game.jobs.builder<1?'builder':takeQueuedChildJob(),'peasants')}if(lost>0)removeWorkerRecords(game,{age:'children',count:lost});game.logs.unshift(eventStamp()+' Child ratio corrected: '+promote+' became adults'+(lost?'; '+lost+' children were lost.':'.'))}
function bindMainAreaEvents(){['food','wood','stone'].forEach(type=>{const btn=$(type+'Btn'),card=$(type+'Card');if(btn)btn.onclick=e=>{e.stopPropagation();gatherResource(type,e)};if(card)card.onclick=e=>{if(e.target.tagName!=='BUTTON')gatherResource(type,e)}});document.querySelectorAll('[data-villager]').forEach(btn=>btn.onclick=()=>recruitVillagers(btn.dataset.villager));if($('clearEventsBtn'))$('clearEventsBtn').onclick=()=>{game.logs=[];renderEvents()}}
function bindResourceInputGuards(){document.querySelectorAll('.resource-card,.resource-card button').forEach(el=>{el.oncontextmenu=e=>e.preventDefault();el.ondblclick=e=>e.preventDefault()})}
function bindButtonFirstClickGuards(root=document){root.querySelectorAll('button').forEach(btn=>{btn.type='button';btn.style.pointerEvents='auto';if(btn.dataset.firstClickReady)return;btn.dataset.firstClickReady='1';btn.addEventListener('pointerdown',()=>{if(!btn.disabled)btn.classList.add('button-pressed')},{passive:true});btn.addEventListener('pointerup',()=>btn.classList.remove('button-pressed'),{passive:true});btn.addEventListener('pointerleave',()=>btn.classList.remove('button-pressed'),{passive:true})})}
function rebalanceWorkforce(){syncPopulationAccounting();const available=getWorkforceCapacity().total,order=['medic','sapper','scout','archer','soldier','guard','grunt','priest','builder','miner','woodcutter','farmer'];let assigned=order.reduce((a,k)=>a+(game.jobs[k]||0),0);for(const k of order){while(assigned>available&&game.jobs[k]>0){assignWorkerRecords(game,{from:k,to:'idle',count:1});assigned--}}syncPopulationAccounting();game.patrols=clamp(game.patrols,0,game.jobs.guard+game.jobs.scout)}
function losePopulation(c){let left=Math.max(0,Math.floor(c||0));for(const age of ['adults','elders','children']){if(left<=0)break;const removed=removeWorkerRecords(game,{age,count:left}).length;left-=removed}rebalanceWorkforce()}
function advanceCalendarDay(){game.day++;const len=MONTH_LENGTHS[game.month-1];if(game.day>len){game.day=1;game.month++;if(game.month>12){game.month=1;game.year++}}}
function isDropdownActive(){const el=document.activeElement;return !!(el&&el.matches&&el.matches('select,.select-control'))}
function refreshAll(){try{const holdDropdown=isDropdownActive();syncPopulationAccounting();ensureClassJobs();ensureJobAges();updateBrandTitle();getSocietyMetrics();updateAchievements();game.logs=game.logs.slice(0,120);renderResources();renderStorage();if(!holdDropdown){renderOverview();renderWorkers();if(activeTab==='Main')makeMainPanelsCompact()}renderEvents();renderSeason();renderSettlementSummary();renderEffects();renderThreat();iconifyActionButtons(document);bindInfoButtons();bindResourceInputGuards();bindButtonFirstClickGuards(document);applyGlobalTooltips(document);updateTabStates()}catch(err){console.error('Render failed:',err);const el=$('workersContent');if(el)el.innerHTML='<div class="bad">Render error: '+err.message+'</div>'}}
const SAVE_KEY='hamletOfWoodstockSaveV2';
const LEGACY_SAVE_KEY='hamletOfWoodstockLegacyV1';
function deepMerge(target,src){if(!src||typeof src!=='object')return target;Object.entries(src).forEach(([k,v])=>{if(v&&typeof v==='object'&&!Array.isArray(v)){if(!target[k]||typeof target[k]!=='object'||Array.isArray(target[k]))target[k]={};deepMerge(target[k],v)}else target[k]=v});return target}
function serializeGame(){const gameState=JSON.parse(JSON.stringify(game));gameState.devUnlockTabs=false;return JSON.stringify({version:2,savedAt:new Date().toISOString(),game:gameState,upgrades:Object.fromEntries(Object.entries(upgrades).map(([k,u])=>[k,{purchased:!!u.purchased,level:u.level||0}]))})}
function applyCompactUI(){document.body.classList.toggle('compact-ui',game.options.compact!==false)}
function applyExtendedInfo(){document.body.classList.toggle('extended-info',!!game.options.extendedInfo)}
function applyDisplayOptions(){applyCompactUI();applyExtendedInfo();document.body.classList.toggle('guidance-off',game.options.guidance===false)}
function saveGame(manual=true){try{localStorage.setItem(SAVE_KEY,serializeGame());if(manual){game.logs.unshift(eventStamp()+' Game saved.');refreshAll()}}catch(err){game.logs.unshift(eventStamp()+' Save failed: '+err.message);renderEvents()}}
function restoreUpgradeState(saved){Object.entries(saved||{}).forEach(([k,v])=>{if(upgrades[k]){if('purchased'in v)upgrades[k].purchased=!!v.purchased;if('level'in v)upgrades[k].level=Number(v.level)||0}})}
function loadGame(silent=false,text){try{const raw=text||localStorage.getItem(SAVE_KEY);if(!raw){if(!silent){game.logs.unshift(eventStamp()+' No saved game found.');renderEvents()}return false}const data=JSON.parse(raw);deepMerge(game,data.game||{});game.options=Object.assign({autosave:true,tickSpeed:1000,compact:true,extendedInfo:false,guidance:false},game.options||{});ensureTimeControl();game.policies=Object.assign({focus:'balanced',growth:'balanced',birthPolicy:'normal',labor:'balanced',workAge:'onlyAdults',migration:'controlled',religion:'neutral'},game.policies||{});game.land=Object.assign({base:100,bonus:0,conquered:0},game.land||{});if(game.land.base<100)game.land.base=100;game.trade=Object.assign({routes:{},deals:0,caravanTimer:45,lastEvent:'No caravans yet.',standing:50,tariff:'balanced'},game.trade||{});game.trade.routes=Object.assign(Object.fromEntries(Object.keys(tradeRouteDefs).map(k=>[k,false])),game.trade.routes||{});game.disasters=Object.assign({active:{},cooldown:75,history:[]},game.disasters||{});game.disasters.active=Object.assign({},game.disasters.active||{});game.advisorSeen=Object.assign({},game.advisorSeen||{});game.jobAssignStep=Object.assign({global:'1'},game.jobAssignStep||{});game.jobAssignAge=game.jobAssignAge||'adults';game.buildQueue=Array.isArray(game.buildQueue)?game.buildQueue:[];game.ui=Object.assign({collapsed:{buildings:{},upgrades:{},population:{}}},game.ui||{});ensureUiState();game.modifiers=Object.assign({buildResourcePerBuilder:BALANCE.construction.baseResourcePerBuilder,buildParallelProjects:BALANCE.construction.baseParallelProjects,buildSpeedMultiplier:BALANCE.construction.baseSpeedMultiplier},game.modifiers||{});game.gather.food=BALANCE.resourceClick.base;game.gather.wood=BALANCE.resourceClick.base;game.gather.stone=BALANCE.resourceClick.base;if(!Object.prototype.hasOwnProperty.call(game.jobs,'sapper'))game.jobs.sapper=0;if(!Object.prototype.hasOwnProperty.call(game.jobs,'grunt'))game.jobs.grunt=0;game.devUnlockTabs=false;game.progression=Object.assign({buildingsUnlocked:false,populationUnlocked:false},game.progression||{});restoreUpgradeState(data.upgrades);if((game.injuries||0)>0&&(!game.injuryQueue||!game.injuryQueue.length))game.injuryQueue=[{count:game.injuries,timer:45}];syncPopulationAccounting();ensureBreakthroughState();initWorldMap();applyBuildingEffects();rebalanceWorkforce();applyDisplayOptions();applyTheme();updateBrandTitle();renderTimeControls();if(!silent)game.logs.unshift(eventStamp()+' Game loaded.');refreshAll();if(activeTab==='Main')bindMainAreaEvents();return true}catch(err){game.logs.unshift(eventStamp()+' Load failed: '+err.message);renderEvents();return false}}
const loadGameLegacyBase=loadGame;
loadGame=function(silent=false,text){const ok=loadGameLegacyBase(silent,text);if(ok){ensureLegacyState();mergeLegacyBonusesFromArchive();saveLegacyArchive();refreshAll()}return ok}
function exportSave(){const data=serializeGame();showModal('Export Save','<div class="box-sub">Copy this save text to keep a backup or move it to another browser.</div><textarea class="modal-textarea" readonly>'+data.replace(/</g,'&lt;')+'</textarea>')}
function importSave(){const raw=prompt('Paste exported save data:');if(!raw)return;if(loadGame(false,raw)){saveGame(false);game.logs.unshift(eventStamp()+' Imported save data.');refreshAll()}}
function resetSave(){if(!confirm('Reset the current village and delete the local saved game? This cannot be undone.'))return;localStorage.removeItem(SAVE_KEY);location.reload()}
function setTickSpeed(ms){game.options.tickSpeed=Number(ms)||1000;restartTick();saveGame(false);renderOptionsMenu()}
function toggleAutosave(){game.options.autosave=!game.options.autosave;saveGame(false);renderOptionsMenu()}
function toggleCompact(){game.options.compact=game.options.compact===false;applyDisplayOptions();saveGame(false);refreshAll();renderOptionsMenu()}
function toggleExtendedInfo(){game.options.extendedInfo=!game.options.extendedInfo;applyDisplayOptions();saveGame(false);refreshAll();renderOptionsMenu()}
function toggleGuidance(){game.options.guidance=game.options.guidance===false;applyDisplayOptions();saveGame(false);refreshAll();renderOptionsMenu()}
function themeOptions(){return[['classic','Classic'],['forest','Forest'],['ocean','Ocean'],['dusk','Dusk'],['ember','Ember'],['slate','Slate'],['parchment','Parchment'],['highcontrast','High Contrast']]}
function applyTheme(){const theme=game.options.theme||'classic';document.body.classList.remove('theme-classic','theme-forest','theme-ocean','theme-dusk','theme-ember','theme-slate','theme-parchment','theme-highcontrast');document.body.classList.add('theme-'+theme)}
function setTheme(theme){game.options.theme=theme;applyTheme();saveGame(false);renderOptionsMenu()}
function renderOptionsMenu(){showModal('Options','<div class="option-grid"><div class="storage-row"><span>Autosave</span><span>'+(game.options.autosave?'On':'Off')+'</span></div><div class="controls"><button class="mini-btn" id="toggleAutosaveBtn">Toggle Autosave</button></div><div class="storage-row"><span>Tick Speed</span><span>'+game.options.tickSpeed+' ms</span></div><div class="controls"><button class="mini-btn" data-speed="500">Fast</button><button class="mini-btn" data-speed="1000">Normal</button><button class="mini-btn" data-speed="2000">Slow</button></div><div class="storage-row"><span>Compact UI</span><span>'+(game.options.compact!==false?'On':'Off')+'</span></div><div class="controls"><button class="mini-btn" id="toggleCompactBtn">Toggle Compact UI</button></div><div class="storage-row"><span>Extended Info</span><span>'+(game.options.extendedInfo?'On':'Off')+'</span></div><div class="controls"><button class="mini-btn" id="toggleExtendedInfoBtn">Toggle Extended Info</button></div><div class="storage-row"><span>Color Scheme</span><span>'+(game.options.theme||'classic')+'</span></div><div class="controls">'+themeOptions().map(([v,t])=>'<button class="mini-btn" data-theme="'+v+'">'+t+'</button>').join('')+'</div><div class="rule"></div><div class="controls"><button class="mini-btn save" id="optionsSaveBtn">Save</button><button class="mini-btn" id="loadGameBtn">Load</button><button class="mini-btn" id="exportSaveBtn">Export</button><button class="mini-btn" id="importSaveBtn">Import</button><button class="mini-btn" id="resetSaveBtn">Reset</button></div></div>');if($('toggleAutosaveBtn'))$('toggleAutosaveBtn').onclick=toggleAutosave;if($('toggleCompactBtn'))$('toggleCompactBtn').onclick=toggleCompact;if($('toggleExtendedInfoBtn'))$('toggleExtendedInfoBtn').onclick=toggleExtendedInfo;document.querySelectorAll('[data-speed]').forEach(b=>b.onclick=()=>setTickSpeed(b.dataset.speed));document.querySelectorAll('[data-theme]').forEach(b=>b.onclick=()=>setTheme(b.dataset.theme));if($('optionsSaveBtn'))$('optionsSaveBtn').onclick=()=>saveGame(true);if($('loadGameBtn'))$('loadGameBtn').onclick=()=>loadGame(false);if($('exportSaveBtn'))$('exportSaveBtn').onclick=exportSave;if($('importSaveBtn'))$('importSaveBtn').onclick=importSave;if($('resetSaveBtn'))$('resetSaveBtn').onclick=resetSave}
function optionHtml(items,current){return items.map(([v,t])=>'<option value="'+v+'" '+(v===current?'selected':'')+'>'+t+'</option>').join('')}
function policyOptionTip(type,value){const tips={focus:{balanced:'No modifiers.',agrarian:'+20% food production.',industrial:'+15% wood, +15% stone, -10% food, -5 happiness.',spiritual:'+5 happiness, +10% faith production, -5% food production.'},labor:{balanced:'No modifiers.',hard:'+10% food, wood, stone, and build production; -8 happiness; +6 fear.',relaxed:'-10% food, wood, stone, and build production; +8 happiness.'},growth:{balanced:'No modifiers.',encourage:'+20% birth, +10% food use, +2 happiness.',restrict:'-20% birth, -5% food use, -3 happiness.'},birthPolicy:{normal:'No modifiers.',encourage:'+25% birth, +8% food use, +1 happiness.',families:'+12% birth, +4% food use, +4 happiness.',restrict:'-35% birth, -4% food use, -2 happiness.'},migration:{controlled:'Normal migration.',open:'+2 immigration score, +3 happiness, -2 fear.',closed:'Blocks immigration, -4 happiness, +5 fear.'},religion:{neutral:'No religious policy modifiers.',mandatory:'+35% faith production, +7 fear, -8 happiness.',freedom:'-25% faith production, +8 happiness, -3 fear.',state:'+18% faith production, +4 fear.'},workAge:{everyone:'Adults, children, and elders can work. Children/elders are less efficient.',noElders:'Adults and children work; elders rest.',noKids:'Adults and elders work; children rest.',onlyAdults:'Only adults work.'},law:{curfew:'-10 crime, +5 disorder, +6 fear, -5 happiness, slight birth penalty.',policing:'-14 crime, -2 disorder, +4 fear, -2 happiness, -3% gold income.',taxRelief:'+7 happiness, +4% birth, -6 disorder, -12% gold income, -3% build speed.',publicWorks:'+20% build speed, +2 happiness, -4 disorder, +2 crime, -8% gold income, +2% food use.'}};return tips[type]?.[value]||''}
function policyOptionHtml(type,items,current){return items.map(([v,t])=>'<option value="'+v+'" title="'+policyOptionTip(type,v).replace(/"/g,'&quot;')+'" '+(v===current?'selected':'')+'>'+t+'</option>').join('')}
function panelByTitle(title){return Array.from(document.querySelectorAll('#mainArea .panel')).find(p=>p.querySelector('h3')?.textContent===title)}
function prependSummaryPanel(title,html){const panel=document.createElement('div');panel.className='panel summary-panel';panel.innerHTML='<h3>'+title+'</h3><div class="content">'+html+'</div>';const masonry=$('mainArea')?.querySelector('.masonry-layout'),col=masonry?.querySelector('.masonry-col');if(col)col.insertBefore(panel,col.firstChild);else $('mainArea')?.insertBefore(panel,$('mainArea').firstChild)}
function policySelectRow(type,label,items,current){const tip=policyOptionTip(type,current);return'<div class="policy-control"><label class="storage-row"><span>'+label+'</span><select class="select-control" data-policy-select="'+type+'" aria-label="'+label+'" title="'+tip.replace(/"/g,'&quot;')+'">'+policyOptionHtml(type,items,current)+'</select></label><div class="box-sub always-info policy-preview" data-policy-preview="'+type+'">'+tip+'</div></div>'}
function applyPolicySelectTooltips(){document.querySelectorAll('[data-policy-select]').forEach(sel=>{const update=()=>{const tip=policyOptionTip(sel.dataset.policySelect,sel.value);sel.title=tip;sel.dataset.uiTip=tip;const preview=document.querySelector('[data-policy-preview="'+sel.dataset.policySelect+'"]');if(preview)preview.textContent=tip};sel.oninput=update;sel.onchange=()=>{setPolicy(sel.dataset.policySelect,sel.value);update()};update()})}
function replacePolicyControlsWithSelects(){const panel=panelByTitle('Policies'),content=panel?.querySelector('.content');if(!content)return;content.innerHTML=policySelectRow('focus','Economic Focus',[['balanced','Balanced'],['agrarian','Agrarian'],['industrial','Industrial'],['spiritual','Spiritual']],game.policies.focus)+'<div class="rule"></div>'+policySelectRow('labor','Labor Policy',[['balanced','Balanced'],['hard','Hard Labor'],['relaxed','Relaxed']],game.policies.labor)+'<div class="rule"></div>'+policySelectRow('growth','Growth Policy',[['balanced','Balanced'],['encourage','Encourage'],['restrict','Restrict']],game.policies.growth)+'<div class="rule"></div>'+policySelectRow('birthPolicy','Birth Rate Policy',[['normal','Normal'],['encourage','Encourage Births'],['families','Support Families'],['restrict','Restrict Births']],game.policies.birthPolicy||'normal')+'<div class="rule"></div>'+policySelectRow('migration','Migration Policy',[['controlled','Controlled'],['open','Open'],['closed','Closed']],game.policies.migration)+'<div class="rule"></div>'+policySelectRow('religion','Religion Policy',[['neutral','Neutral'],['mandatory','Mandatory Worship'],['freedom','Religious Freedom'],['state','State Religion']],game.policies.religion)+'<div class="rule"></div>'+policySelectRow('workAge','Who Works',[['everyone','Everyone Works'],['noElders','Respect Your Elders'],['noKids','Let Them Be Kids'],['onlyAdults','Only Adults Work']],game.policies.workAge);addPolicyTooltips();applyPolicySelectTooltips()}
function enhanceTradeTab(){prependSummaryPanel('Trade Summary','<div class="storage-row"><span>Gold Income</span><span class="gold">+'+formatRate(getTradeGoldIncome())+'/s</span></div><div class="storage-row"><span>Deals</span><span>'+game.trade.deals+'</span></div><div class="storage-row"><span>Open Routes</span><span>'+Object.values(game.trade.routes||{}).filter(Boolean).length+'</span></div><div class="box-sub extra-info">Use exchange for resources, contracts for labor, and mercenaries for gold-based defense. Prices respond to season and stored scarcity.</div>');const identity=panelByTitle('Village Identity')?.querySelector('.content');if(identity){identity.innerHTML='<label class="storage-row"><span>Current</span><select class="select-control" id="identitySelect" aria-label="Village identity">'+optionHtml([['balanced','Balanced'],['agrarian','Agrarian'],['industrial','Industrial'],['spiritual','Spiritual']],game.identity)+'</select></label><div class="box-sub">Identity adjusts market prices and nudges the village toward a specialty.</div>';$('identitySelect').onchange=e=>setVillageIdentity(e.target.value)}const merc=panelByTitle('Mercenary Contracts')?.querySelector('.content');if(merc){merc.innerHTML='<div class="storage-row"><span>Cost</span><span>'+BALANCE.trade.mercenaryCost+' Gold each</span></div><label class="storage-row"><span>Hire Role</span><select class="select-control" id="mercJobSelect" aria-label="Mercenary role">'+optionHtml([['random','Random Military Job'],['guard','Guard'],['soldier','Soldier'],['archer','Archer'],['scout','Scout'],['sapper','Sapper'],['medic','Medic']],'random')+'</select></label><div class="controls"><button class="mini-btn" id="hireMercOne" '+((game.resources.gold||0)<BALANCE.trade.mercenaryCost?'disabled':'')+'>Hire 1</button><button class="mini-btn" id="hireMercFive" '+((game.resources.gold||0)<BALANCE.trade.mercenaryCost*5?'disabled':'')+'>Hire 5</button></div><div class="box-sub">Mercenaries are hired with gold and immediately join military jobs.</div>';$('hireMercOne').onclick=()=>hireMercenary($('mercJobSelect').value,1);$('hireMercFive').onclick=()=>hireMercenary($('mercJobSelect').value,5)}}
function applySocietyTooltips(){const tips={loyalty:'Loyalty measures willingness to stay and support the settlement. High happiness and health raise it; fear and disorder lower it.',obedience:'Obedience measures how strongly people follow rules. Fear and faith raise it, but disorder can weaken it.',education:'Education increases productivity over time, but an educated population can create more social tension if stability is poor.',health:'Health reduces mortality and injury pressure. Housing pressure, land overcrowding, and injuries lower it; medics raise it.'};document.querySelectorAll('[data-society-tip]').forEach(el=>{el.title=tips[el.dataset.societyTip]||''})}
function populationEraProgressPanel(){const stage=getProgressionStage(),rows=[['Thorp','0','Food, huts, gathering center, raw survival.',progressionAtLeast('thorp')],['Hamlet','50','Houses, farms, workshop, well, foragers, carpenter, palisade.',progressionAtLeast('hamlet')],['Small Village','101','Cottages, storage economy, tavern, blacksmith, herbalist, meeting hall, walls.',progressionAtLeast('village')],['Medium Village','500','Light crime appears, school/clinic governance pressure begins.',progressionAtLeast('mediumVillage')],['Big Village','1500','Large storage and administration pressure before town wealth.',progressionAtLeast('bigVillage')],['Town','2000','Market, gold, trade, town hall, courts, banking, customs, full society problems.',progressionAtLeast('smallTown')],['City','50k','Guild hall, university, foundry, districts, specialization.',progressionAtLeast('smallCity')],['Empire','20m','Senate, vassals, grand roads, palace, authority.',progressionAtLeast('largeKingdom')]],next=rows.find(r=>!r[3]);return'<div class="panel summary-panel"><h3>Era Progression</h3><div class="content"><div class="storage-row"><span>Current Era</span><span>'+stage.label+' - '+stage.focus+'</span></div>'+(next?'<div class="storage-row"><span>Next Era</span><span>'+next[0]+' at '+next[1]+' pop</span></div>':'<div class="storage-row"><span>Next Era</span><span>All listed eras reached</span></div>')+'<div class="rule"></div>'+rows.map(([name,pop,desc,done])=>'<div class="storage-row"><span>'+name+' <span class="muted">'+pop+'</span></span><span class="'+(done?'good':'muted')+'">'+(done?'Active':'Locked')+'</span></div><div class="box-sub always-info">'+desc+'</div>').join('')+'</div></div>'}
function enhancePopulationTab(){const m=getPopulationMetrics(),overview=panelByTitle('Population Overview'),needs=panelByTitle('Needs & Stability'),society=panelByTitle('Society');if(!panelByTitle('Era Progression'))$('mainArea')?.insertAdjacentHTML('afterbegin',populationEraProgressPanel());if(overview){overview.classList.add('summary-panel');overview.querySelector('h3').textContent='Population Summary';const c=overview.querySelector('.content');if(c&&!c.querySelector('[data-pop-summary="1"]'))c.insertAdjacentHTML('afterbegin','<div data-pop-summary="1"><div class="storage-row"><span>Population Cap</span><span>'+game.population+'/'+game.housing+'</span></div><div class="storage-row"><span>Stability</span><span>'+m.needs.overall+'%</span></div><div class="box-sub extra-info">Migrants and children can exceed housing, creating pressure to build more space.</div><div class="rule"></div></div>')}if(needs&&society){needs.querySelector('h3').textContent='Needs & Society';const nc=needs.querySelector('.content'),sc=society.querySelector('.content');if(nc&&sc&&!nc.querySelector('[data-merged-society="1"]'))nc.insertAdjacentHTML('beforeend','<div class="rule" data-merged-society="1"></div>'+sc.innerHTML);society.remove()}replacePolicyControlsWithSelects();applySocietyTooltips()}
function enhanceDeityTab(){const law=game.policies.religion||'neutral';prependSummaryPanel('Religion Summary','<div class="storage-row"><span>Law</span><span>'+law+'</span></div><div class="storage-row"><span>Deity</span><span>'+(getDeity()?.name||'None')+'</span></div><div class="storage-row"><span>Faith</span><span>'+formatWhole(game.resources.faith)+'</span></div><div class="box-sub extra-info">Choose law first, then deity only when worship is mandatory or state-run. Favor, rituals, doctrine, and deity upgrades shape long-term society.</div>');const chooser=panelByTitle('Choose Religious Law')?.querySelector('.content');if(chooser){chooser.innerHTML='<label class="storage-row"><span>Religious Law</span><select class="select-control" id="religionLawSelect" aria-label="Religious law"><option value="">Choose...</option>'+optionHtml([['mandatory','Mandatory Worship'],['state','State Worship'],['freedom','Free Worship']],'')+'</select></label><div class="box-sub">Free worship removes the deity requirement.</div>';$('religionLawSelect').onchange=e=>{if(e.target.value)chooseReligiousLaw(e.target.value)}}}
function applyMilitaryTooltips(){const tips={fortifyTownBtn:'Spend 25 wood and 15 stone to temporarily strengthen defenses and lower raid threat.',mobilizeCiviliansBtn:'During an active raid, conscript available civilians as weaker temporary soldiers.',sacrificeDefenseBtn:'Spend 20 food, wood, or stone to lower raid threat and reinforce defenses.',scoutTargetBtn:'Scout the selected conquest target. Better scouting upgrades reveal more exact enemy strength, walls, and units.',startConquestBtn:'Start an offensive raid against the selected target using your current military.',backWorldBtn:'Return from the local 5x5 area map to the world map.'};Object.entries(tips).forEach(([id,tip])=>{if($(id))$(id).title=tip});document.querySelectorAll('.nation-cell').forEach(b=>{b.title='Select this nation as a conquest target.'});document.querySelectorAll('.world-sector').forEach(b=>{b.title='Open this region and view its nearby conquest targets.'})}
function enhanceMilitaryTab(){const arms=Math.round(getCombinedArmsBonus()*100),enemy=game.currentRaid?.enemyUnits||null,match=enemy?getMatchupModifier(enemy):null;prependSummaryPanel('Military Summary','<div class="storage-row"><span>Defense</span><span class="good">'+Math.round(getDefensePower(enemy))+'</span></div><div class="storage-row"><span>Combined Arms</span><span class="good">+'+arms+'%</span></div>'+(match?'<div class="storage-row"><span>Matchup</span><span class="'+(match.mod>=1?'good':'bad')+'">'+Math.round(match.mod*100)+'%</span></div>':'')+'<div class="storage-row"><span>Raid</span><span>'+(game.raidIncoming?'Respond':game.raidAwakened?Math.round(game.threat)+'%':'Dormant')+'</span></div><div class="storage-row"><span>Target</span><span>'+(game.world.target||'None')+'</span></div><div class="box-sub extra-info">Use balanced lines: guards/soldiers protect archers, sappers counter walls, scouts reveal threats, and cavalry-heavy enemies punish archer-only defenses.</div>');applyMilitaryTooltips()}
function wrapRender(fn,after){return function(){const result=fn.apply(this,arguments);after&&after.apply(this,arguments);return result}}
const getTradeGoldIncomeLegacyBase=getTradeGoldIncome;
getTradeGoldIncome=function(){return getTradeGoldIncomeLegacyBase()*(1+legacyTier('trade','trustedBrokers')*.06)}
const nextCaravanDelayLegacyBase=nextCaravanDelay;
nextCaravanDelay=function(){return Math.max(BALANCE.trade.minCaravanDelay,Math.round(nextCaravanDelayLegacyBase()*(1-clamp(legacyTier('trade','caravanDiscipline')*.04,0,.8))))}
const getDefensePowerLegacyBase=getDefensePower;
getDefensePower=function(enemyUnits=null){return getDefensePowerLegacyBase(enemyUnits)*(1+legacyTier('conquest','veteranMuster')*.06)}
const getScoutingLevelLegacyBase=getScoutingLevel;
getScoutingLevel=function(){return getScoutingLevelLegacyBase()+Math.floor(legacyTier('conquest','cartographerCorps'))}
const getHousingPressureLegacyBase=getHousingPressure;
getHousingPressure=function(){return getHousingPressureLegacyBase()*(1-clamp(legacyTier('size','crisisMemory')*.05,0,.6))}
const applyBuildingEffectsLegacyBase=applyBuildingEffects;
applyBuildingEffects=function(){applyBuildingEffectsLegacyBase();const extra=legacyTier('size','efficientHomesteads');if(extra>0)game.housing+=Math.floor((buildingCount('hut')+buildingCount('house')+buildingCount('cottage')+buildingCount('mansion'))*extra)}
renderSettlementSummary=wrapRender(renderSettlementSummary,()=>{const el=$('summaryContent');if(!el)return;const extra=renderCollapseRecoveryPanel()+renderLegacyMainPanel();if(extra)el.insertAdjacentHTML('beforeend','<div data-summary-extra="legacy">'+extra+'</div>')});
renderEffects=wrapRender(renderEffects,()=>{const el=$('effectsContent');if(!el)return;const extra=renderCollapseRecoveryPanel()+renderLegacyActiveEffects();if(extra)el.insertAdjacentHTML('afterbegin','<div data-effects-extra="legacy">'+extra+'</div>')});
function showPreBarracksGrunts(){if(buildingCount('barracks')>0)return;const panel=panelByTitle('Assign Units'),content=panel?.querySelector('.content');if(!content)return;content.innerHTML='<div class="storage-row"><span>Idle Adults Available</span><span>'+game.jobs.idle+'</span></div>'+militaryQuickRow('grunt','Grunts','half-strength emergency infantry')+'<div class="box-sub always-info">Build a Barracks to unlock guards, soldiers, archers, scouts, sappers, and medics.</div>';content.querySelectorAll('[data-mil-job][data-mil-amount]').forEach(b=>b.onclick=()=>{assignJob(b.dataset.milJob,b.dataset.milAmount);renderMilitaryTab()})}
renderMilitaryTab=wrapRender(renderMilitaryTab,()=>{showPreBarracksGrunts();applyMilitaryTooltips();applyGlobalTooltips($('mainArea')||document)});
function applyAccessibilityLabels(){const labels={food:'Food resource. Click card to harvest food.',wood:'Wood resource. Click card to cut wood.',stone:'Stone resource. Click card to mine stone.',gold:'Gold resource details.',faith:'Faith resource details.'};['food','wood','stone','gold','faith'].forEach(r=>{const card=$(r+'Card'),eye=document.querySelector('[data-resource-eye="'+r+'"]'),btn=$(r+'Btn');if(card){card.setAttribute('role',r==='food'||r==='wood'||r==='stone'?'button':'group');card.setAttribute('aria-label',labels[r]||r)}if(eye)eye.setAttribute('aria-label','View '+r+' details');if(btn)btn.setAttribute('aria-label',btn.textContent)});[['populationEye','View population details'],['seasonEye','View season details'],['happinessEye','View happiness details'],['fearEye','View fear details']].forEach(([id,label])=>{if($(id))$(id).setAttribute('aria-label',label)});if($('overviewThreatBox')){$('overviewThreatBox').setAttribute('role','button');$('overviewThreatBox').setAttribute('tabindex','0');$('overviewThreatBox').setAttribute('aria-label','View raid threat or respond to raid');$('overviewThreatBox').onkeydown=e=>{if(e.key==='Enter'||e.key===' '){e.preventDefault();showRaidPanel()}}}document.querySelectorAll('.mini-btn,.top-btn,.tab,.nation-cell,.world-sector,.panel-toggle,.idle-tile,.action-btn,.select-control').forEach(el=>{if(!el.getAttribute('aria-label'))el.setAttribute('aria-label',(el.textContent||el.value||el.id||'Control').trim().replace(/\\s+/g,' '))});bindButtonFirstClickGuards(document)}
function applyGlobalTooltips(root=document){const tips={'Total Population':'All children, adults, and elders currently counted in the settlement.','Population Cap':'Housing capacity. Migrants and children can exceed it, causing pressure to build more homes.','Housing':'Available housing from huts, houses, cottages, and mansions.','Idle Adults':'Adults available for assignment under the current age-work policy.','Idle Children':'Children not working. Children consume half food and can work only under permissive age policy.','Idle Elders':'Elders not working. Elders consume half food and can always be assigned as priests when available.','Injured':'People temporarily removed from useful work until healed.','Children':'Young population; grows into adults over time and consumes half as much food.','Adults':'Primary workforce and military pool.','Elders':'Older population; consume half food and can serve as priests.','Food Need':'How secure the food supply is for the current population.','Housing Need':'How well current housing covers the population.','Morale':'A blend of happiness and low fear.','Overall Stability':'A combined score from food, housing, morale, and land pressure.','Crime Pressure':'Hidden early. Later, wealth and population create crime unless controlled by guards, laws, and priests.','Disorder Pressure':'Hidden early. Later, fear, overcrowding, and low morale create unrest.','Security Need':'How urgently the settlement needs guards, patrols, laws, or priests.','Land Used':'Buildings consume land unless noted. Going over cap creates land overcrowding.','Land Overcrowding':'Pressure from using more land than the current cap supports.','Active Builders':'Builders required to add resources to the construction queue.','Settlement Age':'Progression stage based on population and systems unlocked.','Labor Policy':'Adjusts production, fatigue, happiness, and fear.','Economic Focus':'Specializes the settlement economy.','Growth Policy':'Broad population-growth posture.','Birth Rate Policy':'Directly changes birth rate and family pressure.','Migration Policy':'Controls immigration and emigration behavior.','Religion Policy':'Sets how religion shapes faith, fear, and happiness.','Who Works':'Controls which ages are allowed to work.','Rationing':'Temporary lower food use at the cost of happiness.','Festival':'Temporary happiness boost.','Forced Labor':'Temporary production boost with higher fear and lower happiness.','Peasants':'Basic class. Cheap and flexible.','Skilled Workers':'Workshop-unlocked class with better productivity.','Elites':'Mansion-unlocked class that improves happiness but consumes more food.','Loyalty':'Willingness to stay and support the settlement.','Obedience':'Willingness to follow rules. Fear and faith increase it; disorder weakens it.','Education':'Raises productivity but can increase social tension if stability is poor.','Health':'Reduces mortality, injury pressure, and migration loss.'};root.querySelectorAll('.storage-row span:first-child,.effect-row span:first-child,label.storage-row span:first-child').forEach(el=>{const key=el.textContent.trim().replace(/\\s+/g,' ');if(!el.title&&tips[key])el.title=tips[key]});root.querySelectorAll('[data-law]').forEach(el=>{if(!el.title)el.title='Toggle this law. Laws alter fear, happiness, stability, or construction.'});root.querySelectorAll('[data-edict]').forEach(el=>{if(!el.title)el.title='Start this temporary edict. Edicts expire after their timer runs out.'});root.querySelectorAll('[data-upgrade]').forEach(el=>{if(!el.title)el.title='Buy this upgrade. Hover the upgrade row for exact effects and requirements.'});root.querySelectorAll('[data-build]').forEach(el=>{if(!el.title)el.title='Queue this building. Builders add resources over time instead of instantly completing it.'});root.querySelectorAll('.select-control').forEach(el=>{if(!el.title&&el.getAttribute('aria-label'))el.title='Choose '+el.getAttribute('aria-label')+'. The selected option changes gameplay immediately.'});root.querySelectorAll('.building-card,.upgrade-row,.worker-row').forEach(el=>{if(!el.title){const desc=el.querySelector('.building-effects,.building-desc,.box-sub')?.textContent?.trim();if(desc)el.title=desc}})}
renderBuildingsTab=wrapRender(renderBuildingsTab,()=>{showFundedBuildCounts($('mainArea')||document);iconifyActionButtons($('mainArea')||document);applyGlobalTooltips($('mainArea')||document)});
renderUpgradesList=wrapRender(renderUpgradesList,()=>applyGlobalTooltips($('upgradesContent')||document));
function renderRecruitControls(){const el=$('recruitControls');if(!el)return;const opts=game.recruitOptions,amounts=[['1','+1'],['10','+10'],['100','+100'],['max','+Max'],['custom','Custom: '+(opts.customAmount||1)]],jobs=[['idle','Idle'],['farmer','Farmer'],['woodcutter','Woodcutter'],['miner','Miner'],['builder','Builder'],['priest','Priest'],['guard','Guard'],['soldier','Soldier'],['archer','Archer'],['scout','Scout'],['medic','Medic'],['sapper','Sapper']].filter(([j])=>canHireJob(j));if(opts.classType==='skilled'&&buildingCount('workshop')<=0)opts.classType='peasants';if(opts.classType==='elites'&&!eliteUnlocked())opts.classType='peasants';const classes=[['peasants','Peasant']];if(buildingCount('workshop')>0)classes.push(['skilled','Skilled']);else classes.push(['peasants','Undiscovered: Workshop required']);if(eliteUnlocked())classes.push(['elites','Elite']);else classes.push(['peasants','Undiscovered: Mansion required']);el.innerHTML='<select class="select-control" id="recruitAmountSelect" aria-label="Villagers to hire">'+optionHtml(amounts,opts.amount)+'</select><select class="select-control" id="recruitJobSelect" aria-label="Hiring job">'+optionHtml(jobs,opts.job)+'</select><select class="select-control" id="recruitClassSelect" aria-label="Hiring class">'+optionHtml(classes,opts.classType)+'</select><button class="mini-btn save" id="hireVillagerBtn">Hire</button>';$('recruitAmountSelect').onchange=e=>setRecruitOption('amount',e.target.value);$('recruitJobSelect').onchange=e=>setRecruitOption('job',e.target.value);$('recruitClassSelect').onchange=e=>setRecruitOption('classType',e.target.value);$('hireVillagerBtn').onclick=()=>recruitVillagers(opts.amount)}
renderTradeTab=wrapRender(renderTradeTab,()=>{enhanceTradeTab();applyAccessibilityLabels();applyGlobalTooltips($('mainArea')||document)});
renderPopulationTab=wrapRender(renderPopulationTab,()=>{enhancePopulationTab();applyAccessibilityLabels();applyGlobalTooltips($('mainArea')||document)});
renderDeityTab=wrapRender(renderDeityTab,()=>{enhanceDeityTab();applyAccessibilityLabels();applyGlobalTooltips($('mainArea')||document)});
renderMilitaryTab=wrapRender(renderMilitaryTab,()=>{enhanceMilitaryTab();applyAccessibilityLabels();applyGlobalTooltips($('mainArea')||document)});
renderOptionsMenu=wrapRender(renderOptionsMenu,()=>{const body=$('resourceDetailBody');if(!body)return;const themeRow=Array.from(body.querySelectorAll('.storage-row')).find(r=>r.textContent.includes('Color Scheme'));const themeControls=Array.from(body.querySelectorAll('.controls')).find(c=>c.querySelector('[data-theme]'));if(themeRow&&themeControls){themeControls.innerHTML='<select class="select-control" id="themeSelect" aria-label="Color scheme">'+optionHtml(themeOptions(),game.options.theme||'classic')+'</select>';$('themeSelect').onchange=e=>setTheme(e.target.value)}const rule=body.querySelector('.rule');if(rule&&!$('toggleGuidanceBtn')){const row=document.createElement('div');row.innerHTML='<div class="storage-row"><span>Tips & Guidance</span><span>'+(game.options.guidance===false?'Off':'On')+'</span></div><div class="controls"><button class="mini-btn" id="toggleGuidanceBtn">Toggle Tips</button></div><div class="box-sub always-info">Controls the Best Move card, early mini-goals, advisor hints, and growth highlights.</div>';rule.parentNode.insertBefore(row,rule);$('toggleGuidanceBtn').onclick=toggleGuidance}applyGlobalTooltips(body)});
function renderHelpMenu(){showModal('Help','<div class="help-list"><div><b>Tabs</b><div class="box-sub">Tabs unlock through buildings, population, market access, and military infrastructure. Achievements moved to the top button beside Help.</div></div><div><b>Seasons</b><div class="box-sub">Spring and Summer help food. Winter raises food use and weakens combat unless you invest in seasonal upgrades.</div></div><div><b>Jobs</b><div class="box-sub">Idle adults can become farmers, woodcutters, miners, builders, priests, guards, soldiers, archers, scouts, or medics. Injuries and elders reduce available labor.</div></div><div><b>Raids</b><div class="box-sub">Threat rises from population, crime, disorder, and overcrowding. Scouts, walls, watchtowers, fortresses, patrols, and divine protection reduce danger.</div></div><div><b>Disasters</b><div class="box-sub">Famine, fire, plague, embargoes, unrest, drought, locusts, floods, dragons, and succession crises can appear as the settlement grows. Active Effects shows the current counter percent and the next practical response.</div></div><div><b>Religion</b><div class="box-sub">Choose a religious law first. Free worship skips deity selection; mandatory and state worship require a deity and unlock deity upgrades.</div></div><div><b>Trade</b><div class="box-sub">Markets unlock exchange, routes, caravans, and gold income. Warehouses and roads improve trade value.</div></div><div><b>Saving</b><div class="box-sub">Use Save for localStorage. Options can load, reset, export, import, toggle autosave, change tick speed, or enable compact UI.</div></div></div>')}
function devAddPopulation(n){n=Number(n)||0;if(n<=0)return;for(let i=0;i<n;i++)addWorkerRecord(game,{age:'adults',classType:'peasants',job:'idle'});refreshAll()}
function devAddBuilding(k,n=1){if(!buildingDefs[k])return;game.buildings[k]=Math.max(0,buildingCount(k)+Number(n||1));applyBuildingEffects();refreshAll();if(activeTab==='Buildings')renderBuildingsTab()}
function devSetThreat(v){game.raidAwakened=true;game.threat=clamp(Number(v)||0,0,100);if(game.threat>=100)triggerRaid();refreshAll()}
function devForceRaid(){game.raidAwakened=true;game.threat=100;triggerRaid();refreshAll();showRaidPanel()}
function devClearRaid(){game.raidIncoming=false;game.currentRaid=null;game.threat=0;refreshAll()}
function devUnlockAllBuildings(){Object.keys(buildingDefs).forEach(k=>game.buildings[k]=(game.buildings[k]||0)+1);game.logs.unshift(eventStamp()+' Dev: added +1 to every building.');applyBuildingEffects();refreshAll();if(activeTab==='Buildings')renderBuildingsTab()}
function devBuyAllUpgrades(){Object.values(upgrades).forEach(u=>{if(u.scaling)u.level=Math.max(1,u.level||0);else u.purchased=true;if(typeof u.apply==='function')u.apply()});refreshAll();if(activeTab==='Upgrades')renderUpgradesTab()}
function debugSection(title,rows){return'<div><b>'+title+'</b><div class="debug-unlocks">'+(rows.length?rows.join(''):'<div class="box-sub">None hidden.</div>')+'</div></div>'}
function showDebugUnlocks(){const hiddenBuildings=Object.entries(buildingDefs).filter(([k])=>missingPrereqs(k).length>0&&buildingCount(k)<=0).map(([k,d])=>'<div class="storage-row"><span>'+d.name+'</span><span>'+missingPrereqs(k).join(', ')+'</span></div>'),hiddenUpgrades=Object.entries(upgrades).filter(([,u])=>u.requires&&!u.requires()&&!isUpgradeOwned(u)).map(([k,u])=>'<div class="storage-row"><span>'+u.name+'</span><span>'+(u.unlockText||'Prerequisite not met')+'</span></div>'),hiddenTabs=Object.entries(tabRequirements).filter(([name])=>!isTabUnlocked(name)).map(([name,r])=>'<div class="storage-row"><span>'+name+'</span><span>'+r.label+'</span></div>'),hiddenRoutes=Object.entries(tradeRouteDefs||{}).filter(([k,r])=>!game.trade.routes[k]&&r.requires&&!r.requires()).map(([k,r])=>'<div class="storage-row"><span>'+r.name+'</span><span>Route prerequisite unmet</span></div>');showModal('Debug Unlock Requirements','<div class="box-sub">Testing-only view. This does not unlock anything.</div>'+debugSection('Tabs',hiddenTabs)+debugSection('Buildings',hiddenBuildings)+debugSection('Upgrades',hiddenUpgrades)+debugSection('Trade Routes',hiddenRoutes))}
function renderDevMenu(){const el=$('devMenu');if(!el)return;el.innerHTML='<div class="dev-menu-title" id="devDragHandle"><span>Developer Menu</span><button class="mini-btn" id="devCloseBtn">Close</button></div><div class="dev-section"><div class="dev-section-title">Progression</div><button class="mini-btn" id="devToggleTabsBtn">'+(game.devUnlockTabs?'Lock Tabs':'Unlock Tabs')+'</button><div class="dev-row"><button class="mini-btn" id="devUnlockBuildingsBtn">+1 Each Building</button><button class="mini-btn" id="devBuyUpgradesBtn">Buy All Upgrades</button></div><button class="mini-btn" id="devDebugUnlocksBtn">Debug Unlock Requirements</button></div><div class="dev-section"><div class="dev-section-title">Resources</div><div class="dev-row three">'+['food','wood','stone'].map(r=>'<button class="mini-btn" data-dev-resource="'+r+'" data-dev-amount="100">+100 '+r+'</button>').join('')+'</div><div class="dev-row three">'+['food','wood','stone'].map(r=>'<button class="mini-btn" data-dev-resource="'+r+'" data-dev-amount="1000">+1000 '+r+'</button>').join('')+'</div><div class="dev-row"><button class="mini-btn" data-dev-resource="gold" data-dev-amount="500">+500 Gold</button><button class="mini-btn" data-dev-resource="faith" data-dev-amount="500">+500 Faith</button></div><div class="dev-row"><button class="mini-btn" data-dev-resource="gold" data-dev-amount="-500">-500 Gold</button><button class="mini-btn" data-dev-resource="faith" data-dev-amount="-500">-500 Faith</button></div></div><div class="dev-section"><div class="dev-section-title">Population & Society</div><div class="dev-row three"><button class="mini-btn" data-dev-pop="1">+1 Pop</button><button class="mini-btn" data-dev-pop="10">+10 Pop</button><button class="mini-btn" data-dev-pop="100">+100 Pop</button></div><div class="dev-row"><button class="mini-btn" id="devKillPopBtn">Kill 5</button><button class="mini-btn" id="devInjurePopBtn">Injure 5</button></div><div class="dev-row"><button class="mini-btn" id="devHappyBtn">+10 Happiness</button><button class="mini-btn" id="devFearBtn">+10 Fear</button></div><div class="dev-row"><button class="mini-btn" id="devCrimeBtn">+25 Crime</button><button class="mini-btn" id="devDisorderBtn">+25 Disorder</button></div></div><div class="dev-section"><div class="dev-section-title">Raids</div><div class="dev-row"><button class="mini-btn" id="devThreat50Btn">Threat 50%</button><button class="mini-btn" id="devThreat99Btn">Threat 99%</button></div><div class="dev-row"><button class="mini-btn" id="devForceRaidBtn">Trigger Raid</button><button class="mini-btn" id="devOpenRaidBtn">Open Raid Box</button></div><div class="dev-row"><button class="mini-btn" id="devWinRaidBtn">Win Raid</button><button class="mini-btn" id="devClearRaidBtn">Clear Raid</button></div></div><div class="dev-section"><div class="dev-section-title">Buildings</div><div class="dev-row"><button class="mini-btn" data-dev-building="hut">+Hut</button><button class="mini-btn" data-dev-building="workshop">+Workshop</button></div><div class="dev-row"><button class="mini-btn" data-dev-building="market">+Market</button><button class="mini-btn" data-dev-building="shrine">+Shrine</button></div><div class="dev-row"><button class="mini-btn" data-dev-building="barracks">+Barracks</button><button class="mini-btn" data-dev-building="wall">+Wall</button></div></div>';delete el.dataset.dragReady;bindDevMenuEvents();initDevMenuDrag()}
function bindDevMenuEvents(){const el=$('devMenu');if(!el)return;if($('devCloseBtn'))$('devCloseBtn').onclick=()=>el.classList.remove('show');if($('devToggleTabsBtn'))$('devToggleTabsBtn').onclick=()=>{game.devUnlockTabs=!game.devUnlockTabs;renderDevMenu();refreshAll()};el.querySelectorAll('[data-dev-resource]').forEach(btn=>btn.onclick=()=>{const r=btn.dataset.devResource,a=Number(btn.dataset.devAmount)||0;game.resources[r]=Math.max(0,(game.resources[r]||0)+a);refreshAll()});el.querySelectorAll('[data-dev-pop]').forEach(btn=>btn.onclick=()=>devAddPopulation(btn.dataset.devPop));el.querySelectorAll('[data-dev-building]').forEach(btn=>btn.onclick=()=>devAddBuilding(btn.dataset.devBuilding,1));if($('devUnlockBuildingsBtn'))$('devUnlockBuildingsBtn').onclick=devUnlockAllBuildings;if($('devBuyUpgradesBtn'))$('devBuyUpgradesBtn').onclick=devBuyAllUpgrades;if($('devDebugUnlocksBtn'))$('devDebugUnlocksBtn').onclick=showDebugUnlocks;if($('devKillPopBtn'))$('devKillPopBtn').onclick=()=>{losePopulation(Math.min(5,game.population));refreshAll()};if($('devInjurePopBtn'))$('devInjurePopBtn').onclick=()=>{addInjuries(Math.min(5,game.population||5),90);refreshAll()};if($('devHappyBtn'))$('devHappyBtn').onclick=()=>{game.happiness=clamp(game.happiness+10,0,100);refreshAll()};if($('devFearBtn'))$('devFearBtn').onclick=()=>{game.fear=clamp(game.fear+10,0,100);refreshAll()};if($('devCrimeBtn'))$('devCrimeBtn').onclick=()=>{game.crime=clamp(game.crime+25,0,100);refreshAll()};if($('devDisorderBtn'))$('devDisorderBtn').onclick=()=>{game.disorder=clamp(game.disorder+25,0,100);refreshAll()};if($('devThreat50Btn'))$('devThreat50Btn').onclick=()=>devSetThreat(50);if($('devThreat99Btn'))$('devThreat99Btn').onclick=()=>devSetThreat(99);if($('devForceRaidBtn'))$('devForceRaidBtn').onclick=devForceRaid;if($('devOpenRaidBtn'))$('devOpenRaidBtn').onclick=showRaidPanel;if($('devWinRaidBtn'))$('devWinRaidBtn').onclick=()=>{if(game.currentRaid){game.currentRaid.enemyPower=0;finishRaid(true,1,1)}};if($('devClearRaidBtn'))$('devClearRaidBtn').onclick=devClearRaid}
function bindVillageThemeDevControls(){if($('devStartVillageThemeBtn'))$('devStartVillageThemeBtn').onclick=()=>startVillageTheme();if($('devStopVillageThemeBtn'))$('devStopVillageThemeBtn').onclick=()=>stopVillageTheme();const volume=$('devVillageThemeVolume');if(volume){volume.value=String(getVillageThemeVolume());volume.oninput=e=>setMusicVolume(e.target.value)}}
function renderVillageThemeDevSection(){const el=$('devMenu');if(!el||$('devVillageThemeSection'))return;const section=document.createElement('div');section.className='dev-section';section.id='devVillageThemeSection';section.innerHTML='<div class="dev-section-title">Village Theme Test</div><div class="dev-row"><button class="mini-btn" id="devStartVillageThemeBtn">Start Theme</button><button class="mini-btn" id="devStopVillageThemeBtn">Stop Theme</button></div><label class="storage-row"><span>Volume</span><input id="devVillageThemeVolume" type="range" min="0" max="1" step="0.01" aria-label="Village theme volume" style="width:100%"></label><div class="box-sub always-info">16-bar D major Web Audio test loop.</div>';const buildings=Array.from(el.querySelectorAll('.dev-section-title')).find(title=>title.textContent.trim()==='Buildings')?.closest('.dev-section');el.insertBefore(section,buildings||null);bindVillageThemeDevControls()}
const renderDevMenuVillageThemeBase=renderDevMenu;
renderDevMenu=function(){renderDevMenuVillageThemeBase();renderVillageThemeDevSection()}
const bindDevMenuEventsVillageThemeBase=bindDevMenuEvents;
bindDevMenuEvents=function(){bindDevMenuEventsVillageThemeBase();bindVillageThemeDevControls()}
function initDevMenuDrag(){const el=$('devMenu'),handle=$('devDragHandle');if(!el||!handle||el.dataset.dragReady)return;el.dataset.dragReady='1';let dragging=false,dx=0,dy=0;handle.addEventListener('pointerdown',e=>{if(e.target.closest('button'))return;dragging=true;const rect=el.getBoundingClientRect();dx=e.clientX-rect.left;dy=e.clientY-rect.top;el.classList.add('dragging');handle.setPointerCapture?.(e.pointerId)});handle.addEventListener('pointermove',e=>{if(!dragging)return;const x=clamp(e.clientX-dx,4,window.innerWidth-el.offsetWidth-4),y=clamp(e.clientY-dy,4,window.innerHeight-el.offsetHeight-4);el.style.left=x+'px';el.style.top=y+'px';el.style.right='auto'});handle.addEventListener('pointerup',e=>{dragging=false;el.classList.remove('dragging');handle.releasePointerCapture?.(e.pointerId)})}
function makePopulationPanelsCollapsible(){ensureUiState();document.querySelectorAll('#mainArea .panel').forEach((panel,i)=>{const h=panel.querySelector('h3'),content=panel.querySelector('.content');if(!h||!content)return;const title=h.textContent.trim(),key=title.toLowerCase().replace(/[^a-z0-9]+/g,'_')+'_'+i,collapsed=!!game.ui.collapsed.population[key];if(!h.querySelector('.panel-toggle'))h.innerHTML='<button class="panel-toggle" data-collapse-scope="population" data-collapse-key="'+key+'" aria-label="Toggle '+title+'">'+(collapsed?'+':'-')+'</button><span>'+title+'</span>';content.style.display=collapsed?'none':''});bindCollapseToggles($('mainArea'))}
function makeMainPanelsCompact(){document.querySelectorAll('#mainArea .panel').forEach(panel=>panel.classList.add('compact-details'));const storage=Array.from(document.querySelectorAll('#mainArea .panel')).find(p=>p.querySelector('h3')?.textContent.includes('Resource Storage'));if(storage){const h=storage.querySelector('h3'),content=storage.querySelector('.content');storage.classList.add('detail-panel','storage-popover-panel');if(h&&content&&!h.querySelector('.resource-eye'))h.innerHTML='<span>Storage</span><button class="resource-eye" id="mainStorageInfo" title="View storage details">i</button>';if(content)content.style.display='none';if($('mainStorageInfo'))$('mainStorageInfo').onclick=e=>{e.stopPropagation();showModal('Resource Storage',$('storageContent')?.innerHTML||'<div class="box-sub">No storage details.</div>')}}}
function iconifyActionButtons(root=document){root.querySelectorAll('[data-build]').forEach(btn=>{const c=btn.dataset.buildCount;if(c==='1'){btn.textContent='+';btn.classList.add('icon-btn');btn.title=btn.title||'Queue 1 building'}else{if(c!=='max'||!btn.textContent.startsWith('Max '))btn.textContent=c==='max'?'Max':'x'+c;btn.classList.add('icon-btn-wide')}});root.querySelectorAll('[data-cancel-build]').forEach(btn=>{btn.textContent='x';btn.classList.add('icon-btn');btn.title=btn.title||'Cancel project'});root.querySelectorAll('[data-cancel-all-builds]').forEach(btn=>{btn.textContent='Cancel All';btn.classList.add('icon-btn-wide')});root.querySelectorAll('[data-rush-build][data-rush-mode="boost"]').forEach(btn=>{btn.textContent='?';btn.classList.add('icon-btn')});root.querySelectorAll('[data-rush-build][data-rush-mode="finish"]').forEach(btn=>{btn.textContent='?';btn.classList.add('icon-btn')});root.querySelectorAll('[data-job-compact][data-dir="+"]').forEach(btn=>{btn.textContent='+';btn.classList.add('icon-btn')});root.querySelectorAll('[data-job-compact][data-dir="-"]').forEach(btn=>{btn.textContent='-';btn.classList.add('icon-btn')});root.querySelectorAll('.resource-eye').forEach(btn=>{if(btn.textContent.trim().toLowerCase()==='i')btn.title=btn.title||'Details'})}
function showFundedBuildCounts(root=document){root.querySelectorAll('[data-build][data-build-count="max"]').forEach(btn=>{const k=btn.dataset.build,n=maxQueueableBuildings(k);btn.textContent='Max '+n;btn.title='Queue up to '+n+' with current stored resources.'})}
function renderWorkers(){
  const el=$('workersContent');
  if(!el)return;
  const idle=getIdleAgeCounts(),elig=getWorkAgeEligibility(),jobs=getJobRows().filter(j=>j.show);
  game.jobAssignStep=game.jobAssignStep||{};
  game.jobAssignAge=game.jobAssignAge||'adults';
  const step=game.jobAssignStep.global||'1';
  const ageNote={adults:'Assignable adults. Injured adults are excluded from idle labor. Current who-works policy: '+workAgePolicyLabel(game.policies.workAge)+'.',children:(elig.children?'Children can currently work. ':'Policy prevents work for children. ')+'Current who-works policy: '+workAgePolicyLabel(game.policies.workAge)+'.',elders:(elig.elders?'Elders can currently work. ':'Policy prevents elder labor; elders can only be priests. ')+'Current who-works policy: '+workAgePolicyLabel(game.policies.workAge)+'.'};
  const idleTile=(age,label,value)=>'<button class="idle-tile clickable '+(game.jobAssignAge===age?'selected':'')+'" data-assign-age="'+age+'" title="'+ageNote[age]+'"><b>'+label+'</b><span>'+value+'</span><span class="muted">'+(game.jobAssignAge===age?'Selected':'Click to assign')+'</span></button>';
  el.innerHTML=
    '<div class="idle-strip">'+
      idleTile('adults','Idle Adults',idle.adults)+
      idleTile('children','Idle Children',idle.children)+
      idleTile('elders','Idle Elders',idle.elders)+
      '<div class="idle-tile"><b>Assign Amount</b><select class="select-control worker-step" id="globalJobStep" aria-label="Assignment amount"><option value="1" '+(step==='1'?'selected':'')+'>1</option><option value="5" '+(step==='5'?'selected':'')+'>5</option><option value="10" '+(step==='10'?'selected':'')+'>10</option><option value="100" '+(step==='100'?'selected':'')+'>100</option><option value="custom" '+(step==='custom'?'selected':'')+'>Custom</option><option value="max" '+(step==='max'?'selected':'')+'>Max</option></select><span class="muted">Used by all job buttons</span></div>'+
    '</div><div class="worker-grid">'+
    jobs.map(j=>'<div class="worker-compact-row"><button class="resource-eye" data-job-info="'+j.key+'" aria-label="View '+j.name+' details">i</button><div class="worker-compact-name"><b>'+j.name+'</b><span class="muted extra-info">'+j.note+'</span></div><div class="worker-count">'+(game.jobs[j.key]||0)+'</div><button class="mini-btn" data-job-compact="'+j.key+'" data-dir="-">-</button><button class="mini-btn" data-job-compact="'+j.key+'" data-dir="+">+</button></div>').join('')+
    '</div>';
  el.querySelectorAll('[data-assign-age]').forEach(btn=>btn.onclick=()=>{game.jobAssignAge=btn.dataset.assignAge;renderWorkers()});
  if($('globalJobStep'))$('globalJobStep').onchange=()=>{game.jobAssignStep.global=$('globalJobStep').value;if(game.jobAssignStep.global==='custom'){const n=Math.max(1,Math.floor(Number(prompt('Assign/remove how many workers?','1'))||1));game.jobAssignCustomAmount=n}};
  el.querySelectorAll('[data-job-compact]').forEach(btn=>btn.onclick=()=>{
    const key=btn.dataset.jobCompact,raw=game.jobAssignStep.global||'1',value=raw==='custom'?String(game.jobAssignCustomAmount||1):raw;
    assignJob(key,btn.dataset.dir==='+'?value:(value==='max'?'-max':-Number(value)));
  });
  el.querySelectorAll('[data-job-info]').forEach(btn=>btn.onclick=e=>{e.stopPropagation();showJobDetails(btn.dataset.jobInfo)});
}
function uiSlug(v){return String(v||'panel').toLowerCase().replace(/[^a-z0-9]+/g,'_').replace(/^_+|_+$/g,'')||'panel'}
function uiBadge(text,kind='muted'){return'<span class="ui-badge '+kind+'">'+text+'</span>'}
function statChip(label,value,kind=''){return'<div class="stat-chip"><b>'+label+'</b><span class="'+kind+'">'+value+'</span></div>'}
function ensureLiveRegions(){if($('eventsContent')){$('eventsContent').setAttribute('aria-live','polite');$('eventsContent').setAttribute('aria-relevant','additions text')}if($('tabLockBanner')){$('tabLockBanner').setAttribute('role','status');$('tabLockBanner').setAttribute('aria-live','assertive')}let live=$('uiAssertiveLive');if(!live){live=document.createElement('div');live.id='uiAssertiveLive';live.className='sr-only';live.setAttribute('aria-live','assertive');live.setAttribute('aria-atomic','true');document.body.appendChild(live)}}
function announceUrgent(msg){ensureLiveRegions();if($('uiAssertiveLive'))$('uiAssertiveLive').textContent=msg}
function tooltipEl(){let el=$('uiTooltip');if(!el){el=document.createElement('div');el.id='uiTooltip';el.className='ui-tooltip';el.setAttribute('role','tooltip');document.body.appendChild(el)}return el}
function showUiTooltip(target,text){if(!text)return;const tip=tooltipEl();tip.textContent=text;tip.classList.add('show');const rect=target.getBoundingClientRect(),pad=10;let x=Math.min(window.innerWidth-tip.offsetWidth-pad,Math.max(pad,rect.left+rect.width/2-tip.offsetWidth/2)),y=rect.bottom+8;if(y+tip.offsetHeight>window.innerHeight-pad)y=Math.max(pad,rect.top-tip.offsetHeight-8);tip.style.left=x+'px';tip.style.top=y+'px'}
function hideUiTooltip(){const tip=$('uiTooltip');if(tip)tip.classList.remove('show')}
function bindRealTooltips(root=document){normalizeNativeTooltips(root);root.querySelectorAll('[data-ui-tip]').forEach(el=>{const txt=el.dataset.uiTip;if(!txt)return;if(!el.getAttribute('aria-describedby'))el.setAttribute('aria-describedby','uiTooltip');if(!el.getAttribute('aria-label')&&['BUTTON','SELECT'].includes(el.tagName))el.setAttribute('aria-label',el.textContent.trim().replace(/\s+/g,' ')||txt);if(el.dataset.tipBound)return;el.dataset.tipBound='1';el.addEventListener('mouseenter',()=>showUiTooltip(el,el.dataset.uiTip));el.addEventListener('mouseleave',hideUiTooltip);el.addEventListener('focus',()=>showUiTooltip(el,el.dataset.uiTip));el.addEventListener('blur',hideUiTooltip);el.addEventListener('pointerdown',()=>{if(matchMedia('(hover: none)').matches){showUiTooltip(el,el.dataset.uiTip);clearTimeout(el._tipTimer);el._tipTimer=setTimeout(hideUiTooltip,2400)}})})}
function enhanceModalState(open){const wrap=document.querySelector('.wrap');document.body.classList.toggle('modal-open',!!open);if(wrap){try{wrap.inert=!!open}catch(_){}if(open)wrap.setAttribute('aria-hidden','true');else wrap.removeAttribute('aria-hidden')}if(!open)hideUiTooltip()}
const showModalUiBase=showModal;showModal=function(title,html){showModalUiBase(title,html);enhanceModalState(true);applyGameUiPass($('resourceDetailBody')||document);announceUrgent(String(title||'Dialog opened'))}
const closeModalUiBase=closeModal;closeModal=function(){enhanceModalState(false);closeModalUiBase()}
function defaultCollapsed(scope,key,shouldCollapse){ensureUiState();game.ui.collapsed[scope]=game.ui.collapsed[scope]||{};if(game.ui.collapsed[scope][key]===undefined)game.ui.collapsed[scope][key]=!!shouldCollapse}
function makePanelsDisclosure(scope,openTitles=[]){ensureUiState();game.ui.collapsed[scope]=game.ui.collapsed[scope]||{};const open=openTitles.map(uiSlug);document.querySelectorAll('#mainArea .panel').forEach(panel=>{const h=panel.querySelector('h3'),content=panel.querySelector('.content');if(!h||!content)return;const title=h.textContent.trim().replace(/^[+-]\s*/,'').trim(),key=uiSlug(title),shouldCollapse=!open.includes(key)&&!panel.classList.contains('summary-panel')&&!panel.classList.contains('primary-panel');defaultCollapsed(scope,key,shouldCollapse);let collapsed=!!game.ui.collapsed[scope][key];if(!h.querySelector('[data-stable-collapse]'))h.innerHTML='<button class="panel-toggle" data-stable-collapse="'+scope+'" data-stable-key="'+key+'" aria-label="Toggle '+title.replace(/"/g,'&quot;')+'">'+(collapsed?'+':'-')+'</button><span class="panel-title">'+title+'</span>';else h.querySelector('[data-stable-collapse]').textContent=collapsed?'+':'-';content.style.display=collapsed?'none':'';panel.classList.toggle('collapsed-panel',collapsed)});document.querySelectorAll('[data-stable-collapse]').forEach(btn=>{btn.onclick=e=>{e.stopPropagation();const scope=btn.dataset.stableCollapse,key=btn.dataset.stableKey;game.ui.collapsed[scope]=game.ui.collapsed[scope]||{};game.ui.collapsed[scope][key]=!game.ui.collapsed[scope][key];const panel=btn.closest('.panel'),content=panel?.querySelector('.content'),collapsed=!!game.ui.collapsed[scope][key];btn.textContent=collapsed?'+':'-';if(content)content.style.display=collapsed?'none':'';panel?.classList.toggle('collapsed-panel',collapsed)}})}
function labelPanelRoles(root=document){root.querySelectorAll('.panel').forEach(panel=>{const title=panel.querySelector('h3')?.textContent.trim()||'';if(/summary/i.test(title))panel.classList.add('summary-panel');if(/planning|policies|exchange|choose|market ledger|land use/i.test(title))panel.classList.add('primary-panel');if(/actions|defense|contracts|divine power|ritual/i.test(title))panel.classList.add('action-panel');if(/details|classes|routes|doctrine|upgrades|caravans|laws|edicts/i.test(title))panel.classList.add('detail-panel')})}
function addPanelCounts(root=document){root.querySelectorAll('.panel h3').forEach(h=>{if(h.querySelector('.category-count'))return;const panel=h.closest('.panel'),n=panel?.querySelectorAll('.upgrade-row,.building-card,.worker-compact-row,.nation-cell').length||0;if(n>1)h.insertAdjacentHTML('beforeend','<span class="category-count">'+uiBadge(n,'muted')+'</span>')})}
function buildingFilterOptions(){return [['all','All Buildings'],['Housing & Population','Housing'],['Storage','Storage'],['Food','Food'],['Trade & Gold','Trade'],['Faith & Religion','Faith'],['Military & Defense','Military'],['Happiness & Society','Society'],['Infrastructure','Infrastructure'],['Governance','Governance']]}
function populationSectionOptions(){return[['all','All'],['summary','Summary'],['policies','Policies'],['ages','Ages'],['society','Society']]}
function populationPanelSection(panel){const title=(panel.querySelector('h3')?.textContent||'').toLowerCase();if(/policy|law|edict/.test(title))return'policies';if(/age|class/.test(title))return'ages';if(/society|need|stability|crime|disorder/.test(title))return'society';return'summary'}
function addPopulationSectionNav(){if(activeTab!=='Population'||!$('mainArea'))return;ensureUiState();const current=game.ui.populationSection||'all';if(!$('populationSectionNav'))$('mainArea').insertAdjacentHTML('afterbegin','<div class="panel primary-panel" id="populationSectionNav"><h3>Population Sections</h3><div class="content"><div class="building-filter-chips">'+populationSectionOptions().map(([v,t])=>'<button class="mini-btn filter-chip '+(v===current?'active':'')+'" data-pop-section="'+v+'">'+t+'</button>').join('')+'</div></div></div>');document.querySelectorAll('[data-pop-section]').forEach(btn=>btn.onclick=e=>{e.stopPropagation();ensureUiState();game.ui.populationSection=btn.dataset.popSection;renderPopulationTab()});document.querySelectorAll('#mainArea .panel').forEach(panel=>{if(panel.id==='populationSectionNav')return;const sec=populationPanelSection(panel);panel.style.display=current==='all'||current===sec?'':'none'})}
function simplifyBuildingActions(){const land=$('landUsePanel')?.querySelector('.content'),current=game.ui?.buildingFilter||'all';if(land&&!$('buildAmountSelect'))land.insertAdjacentHTML('afterbegin','<label class="storage-row"><span>Build Amount</span><select class="select-control" id="buildAmountSelect" aria-label="Build queue amount"><option value="1">1</option><option value="10">10</option><option value="100">100</option><option value="max">Max funded</option></select></label><label class="storage-row mobile-filter-row"><span>Category</span><select class="select-control" id="buildingFilterSelect" aria-label="Building category filter">'+optionHtml(buildingFilterOptions(),current)+'</select></label><div class="building-filter-chips" aria-label="Building filters">'+buildingFilterOptions().map(([v,t])=>'<button class="mini-btn filter-chip '+(v===current?'active':'')+'" data-building-filter="'+v+'">'+t+'</button>').join('')+'</div>');if($('buildingFilterSelect'))$('buildingFilterSelect').onchange=e=>{ensureUiState();game.ui.buildingFilter=e.target.value;renderBuildingsTab()};document.querySelectorAll('[data-building-filter]').forEach(b=>b.onclick=e=>{e.stopPropagation();ensureUiState();game.ui.buildingFilter=b.dataset.buildingFilter;renderBuildingsTab()});document.querySelectorAll('.building-card').forEach(card=>{const buttons=Array.from(card.querySelectorAll('[data-build]'));if(!buttons.length)return;const first=buttons.find(b=>b.dataset.buildCount==='1')||buttons[0];buttons.forEach(b=>{if(b!==first)b.remove()});first.textContent='+';first.classList.add('icon-btn');first.dataset.buildCount='ui';first.setAttribute('aria-label','Queue building with selected amount');first.onclick=e=>{e.stopPropagation();buildBuilding(first.dataset.build,$('buildAmountSelect')?.value||'1')}})}
function enhanceUpgradePanels(){defaultCollapsed('upgrades','purchased',true);addPanelCounts($('upgradesContent')||document);const purchased=Array.from(document.querySelectorAll('#upgradesContent .panel')).find(p=>/purchased/i.test(p.querySelector('h3')?.textContent||''));if(purchased){const key='purchased';game.ui.collapsed.upgrades[key]=game.ui.collapsed.upgrades[key]!==false;purchased.querySelector('.content').style.display=game.ui.collapsed.upgrades[key]?'none':'';purchased.classList.toggle('collapsed-panel',game.ui.collapsed.upgrades[key])}document.querySelectorAll('#upgradesContent .upgrade-row').forEach(row=>{const desc=row.querySelector('.box-sub')?.textContent.trim();if(desc)row.dataset.uiTip=desc})}
function enhanceTradeExchangeTable(){const panel=panelByTitle('Resource Exchange'),content=panel?.querySelector('.content');if(!content)return;const resources=['food','wood','stone','faith'].concat(unlockedProgressionResources()),amounts={food:20,wood:15,stone:12,faith:10,tools:5,influence:4,steel:3,knowledge:4,authority:2};content.innerHTML='<table class="table-compact"><thead><tr><th>Resource</th><th>Stock</th><th>Buy</th><th>Sell</th></tr></thead><tbody>'+resources.map(r=>{const price=getTradePrice(r),amount=amounts[r]||10,sellable=r!=='faith',stock=formatWhole(game.resources[r]||0)+(hasInfiniteStorage(r)?'':'/'+formatWhole(game.storage[r]||0));return'<tr><td><b>'+r.charAt(0).toUpperCase()+r.slice(1)+'</b></td><td>'+stock+'</td><td><button class="mini-btn" data-trade-buy="'+r+'" '+((game.resources.gold||0)<price.buy?'disabled':'')+' aria-label="Buy '+amount+' '+r+'">Buy '+amount+' <span class="ui-badge gold">'+price.buy+'g</span></button></td><td>'+(sellable?'<button class="mini-btn" data-trade-sell="'+r+'" '+((game.resources[r]||0)<amount?'disabled':'')+' aria-label="Sell '+amount+' '+r+'">Sell '+amount+' <span class="ui-badge gold">'+price.sell+'g</span></button>':'<span class="ui-badge muted">No Sale</span>')+'</td></tr>'}).join('')+'</tbody></table>';content.querySelectorAll('[data-trade-buy]').forEach(b=>b.onclick=()=>tradeExchange(b.dataset.tradeBuy,'buy'));content.querySelectorAll('[data-trade-sell]').forEach(b=>b.onclick=()=>tradeExchange(b.dataset.tradeSell,'sell'))}
function renderCommandWorkers(){
  const el=$('workersContent');if(!el)return;const idle=getIdleAgeCounts(),elig=getWorkAgeEligibility(),jobs=getJobRows().filter(j=>j.show);game.jobAssignStep=game.jobAssignStep||{};game.jobAssignAge=game.jobAssignAge||'adults';const step=game.jobAssignStep.global||'1',groupFor=j=>j.key==='builder'?'Build':j.key==='priest'?'Faith':['guard','soldier','archer','scout','sapper','medic','grunt'].includes(j.key)?'Military':'Gather',groups=['Gather','Build','Military','Faith'],ageNote={adults:'Assignable adults. Injured adults are excluded. Policy: '+workAgePolicyLabel(game.policies.workAge)+'.',children:(elig.children?'Children can work. ':'Policy prevents work for children. ')+'Policy: '+workAgePolicyLabel(game.policies.workAge)+'.',elders:(elig.elders?'Elders can work. ':'Policy prevents elder labor; elders can only be priests. ')+'Policy: '+workAgePolicyLabel(game.policies.workAge)+'.'},idleTile=(age,label,value)=>'<button class="idle-tile clickable '+(game.jobAssignAge===age?'selected':'')+'" data-assign-age="'+age+'" data-ui-tip="'+ageNote[age].replace(/"/g,'&quot;')+'"><b>'+label+'</b><span>'+value+'</span><span class="muted">'+(game.jobAssignAge===age?'Selected':'Click to assign')+'</span></button>',row=j=>'<div class="worker-compact-row" data-ui-tip="'+String(j.note||'').replace(/"/g,'&quot;')+'"><button class="resource-eye" data-job-info="'+j.key+'" aria-label="View '+j.name+' details">i</button><div class="worker-compact-name"><b>'+j.name+'</b><span class="muted extra-info">'+j.note+'</span></div><div class="worker-count">'+(game.jobs[j.key]||0)+'</div><button class="mini-btn icon-btn" data-job-compact="'+j.key+'" data-dir="-" aria-label="Remove '+j.name+'">-</button><button class="mini-btn icon-btn" data-job-compact="'+j.key+'" data-dir="+" aria-label="Assign '+j.name+'">+</button></div>';
  el.innerHTML='<div class="idle-strip">'+idleTile('adults','Idle Adults',idle.adults)+idleTile('children','Idle Children',idle.children)+idleTile('elders','Idle Elders',idle.elders)+'<div class="idle-tile"><b>Assign Amount</b><select class="select-control worker-step" id="globalJobStep" aria-label="Assignment amount">'+optionHtml([['1','1'],['5','5'],['10','10'],['100','100'],['custom','Custom'],['max','Max']],step)+'</select><span class="muted">Used by job buttons</span></div></div>'+groups.map(g=>{const rows=jobs.filter(j=>groupFor(j)===g);return rows.length?'<div class="worker-group"><div class="worker-group-title"><span>'+g+'</span>'+uiBadge(rows.length,'muted')+'</div><div class="worker-grid">'+rows.map(row).join('')+'</div></div>':''}).join('');
  el.querySelectorAll('[data-assign-age]').forEach(btn=>btn.onclick=()=>{game.jobAssignAge=btn.dataset.assignAge;renderWorkers()});if($('globalJobStep'))$('globalJobStep').onchange=()=>{game.jobAssignStep.global=$('globalJobStep').value;if(game.jobAssignStep.global==='custom'){const n=Math.max(1,Math.floor(Number(prompt('Assign/remove how many workers?','1'))||1));game.jobAssignCustomAmount=n}};el.querySelectorAll('[data-job-compact]').forEach(btn=>btn.onclick=()=>{const key=btn.dataset.jobCompact,raw=game.jobAssignStep.global||'1',value=raw==='custom'?String(game.jobAssignCustomAmount||1):raw;assignJob(key,btn.dataset.dir==='+'?value:(value==='max'?'-max':-Number(value)))});el.querySelectorAll('[data-job-info]').forEach(btn=>btn.onclick=e=>{e.stopPropagation();showJobDetails(btn.dataset.jobInfo)});bindRealTooltips(el)}
renderWorkers=renderCommandWorkers;
function keyboardClick(el,e){if(e.key==='Enter'||e.key===' '){e.preventDefault();el.click();return true}return false}
function applyKeyboardNavigation(root=document){
  const tabList=document.querySelector('.tabs');
  if(tabList)tabList.setAttribute('role','tablist');
  tabs.forEach((tab,i)=>{
    const name=tab.dataset.tab||tab.textContent.trim(),active=tab.classList.contains('active'),locked=!isTabUnlocked(name);
    tab.setAttribute('role','tab');
    tab.setAttribute('aria-selected',active?'true':'false');
    tab.setAttribute('aria-disabled','false');
    tab.setAttribute('aria-label',locked?name+' locked. Click to see unlock requirement.':name);
    tab.setAttribute('tabindex','0');
    if(!tab.dataset.keyboardReady){
      tab.dataset.keyboardReady='1';
      tab.addEventListener('keydown',e=>{
        if(keyboardClick(tab,e))return;
        const visible=tabs.filter(t=>t.offsetParent!==null),current=visible.indexOf(tab);
        if(current<0)return;
        if(e.key==='ArrowRight'||e.key==='ArrowDown'){e.preventDefault();visible[(current+1)%visible.length].focus()}
        if(e.key==='ArrowLeft'||e.key==='ArrowUp'){e.preventDefault();visible[(current-1+visible.length)%visible.length].focus()}
        if(e.key==='Home'){e.preventDefault();visible[0]?.focus()}
        if(e.key==='End'){e.preventDefault();visible[visible.length-1]?.focus()}
      });
    }
  });
  root.querySelectorAll('.resource-card.gatherable').forEach(card=>{
    card.setAttribute('tabindex','0');
    if(!card.getAttribute('aria-label'))card.setAttribute('aria-label','Gather '+(card.id||'resource').replace(/Card$/,''));
    if(!card.dataset.keyboardReady){
      card.dataset.keyboardReady='1';
      card.addEventListener('keydown',e=>{
        if(e.key!=='Enter'&&e.key!==' ')return;
        const type=(card.id||'').replace(/Card$/,'');
        if(type&&game.gather&&Object.prototype.hasOwnProperty.call(game.gather,type)){
          e.preventDefault();
          gatherResource(type,e);
        }
      });
    }
  });
  root.querySelectorAll('.idle-tile.clickable,.world-sector,.nation-cell,.raid-threat-clickable,.panel-toggle,[data-panel-toggle],[data-stable-collapse]').forEach(el=>{
    if(!el.getAttribute('tabindex'))el.setAttribute('tabindex','0');
    if(!el.dataset.keyboardReady){
      el.dataset.keyboardReady='1';
      el.addEventListener('keydown',e=>keyboardClick(el,e));
    }
  });
}
function applyModalA11y(){const overlay=$('resourceDetailOverlay'),wrap=document.querySelector('.wrap');if(!overlay||!wrap)return;if(overlay.classList.contains('show'))wrap.setAttribute('aria-hidden','true');else wrap.removeAttribute('aria-hidden')}
