function addMobileSummaryToggle(){if(activeTab==='Main'||!$('mainArea')){document.body.classList.remove('mobile-summary-mode');return}const mobile=window.matchMedia('(max-width: 700px)').matches;document.body.classList.toggle('mobile-summary-mode',mobile&&game.options.mobileDetails!==true);if(!mobile)return;if(!$('mobileDetailToggle')){$('mainArea').insertAdjacentHTML('afterbegin','<div class="panel mobile-detail-toggle-panel"><div class="content"><button class="mini-btn" id="mobileDetailToggle">'+(game.options.mobileDetails===true?'Summary View':'Show Details')+'</button><span class="muted">Condenses heavy tabs on phone screens.</span></div></div>')}$('mobileDetailToggle').onclick=()=>{game.options.mobileDetails=game.options.mobileDetails!==true;refreshAll();if(activeTab!=='Main')switchTab(activeTab)}}
