function earlyFocusActive(){return !progressionAtLeast('hamlet')&&!game.crisis?.active&&!game.raidIncoming}
function earlyFoodNet(){const p=getJobProduction();return p.food-getFoodConsumption()-getFoodSpoilage()-(getBuildQueueDrainRates().food||0)}
function renderEarlyFocusSummary(){if(!$('summaryContent'))return;const foodNet=earlyFoodNet(),housingRoom=game.housing-game.population,queue=(game.buildQueue||[]).length,rows=[summaryRow('Food',formatWhole(game.resources.food)+' stored · '+(foodNet>=0?'+':'')+formatRate(foodNet)+'/s',foodNet>=0?'good':'bad'),summaryRow('Housing',game.population+' / '+game.housing,housingRoom>=0?'good':'bad'),summaryRow('Basic Materials','Wood '+formatWhole(game.resources.wood)+' · Stone '+formatWhole(game.resources.stone),'gold')];if(queue)rows.push(summaryRow('Building',queue+' queued',queue?'gold':'muted'));let html=renderCrisisStrip()+renderGrowthGuidance()+rows.join('');if(game.options.guidance!==false)html+=renderMiniGoals();$('summaryContent').innerHTML=html;applyGrowthHighlight()}
function renderEarlyFocusEffects(){if(!$('effectsContent'))return;const foodNet=earlyFoodNet(),housingRoom=game.housing-game.population,drain=getBuildQueueDrainRates(),queue=(game.buildQueue||[]).length,materialNote=(drain.wood||drain.stone)?'Builders using '+formatRate(drain.wood||0)+' wood/s, '+formatRate(drain.stone||0)+' stone/s':'No builder drain';$('effectsContent').innerHTML='<div class="effect-row"><span>Food</span><span class="'+(foodNet>=0?'good':'bad')+'">'+(foodNet>=0?'+':'')+formatRate(foodNet)+'/s</span></div><div class="effect-row"><span>Housing Room</span><span class="'+(housingRoom>=0?'good':'bad')+'">'+(housingRoom>=0?housingRoom+' open':Math.abs(housingRoom)+' over')+'</span></div><div class="effect-row"><span>Materials</span><span>Wood '+formatWhole(game.resources.wood)+' · Stone '+formatWhole(game.resources.stone)+'</span></div>'+(queue?'<div class="effect-row"><span>Build Queue</span><span class="gold">'+queue+' queued</span></div><div class="box-sub always-info">'+materialNote+'</div>':'')}
function renderEarlyPopulationTab(){activeTab='Population';$('mainArea').classList.remove('buildings-mode','masonry-mode');$('mainArea').classList.add('population-mode');const p=getJobProduction(),foodUse=getFoodConsumption()+getFoodSpoilage(),foodNet=p.food-foodUse,room=game.housing-game.population;$('mainArea').innerHTML='<div class="panel summary-panel"><h3>Population & Housing</h3><div class="content"><div class="storage-row"><span>Total Population</span><span>'+game.population+'</span></div><div class="storage-row"><span>Housing</span><span class="'+(room>=0?'good':'bad')+'">'+game.population+'/'+game.housing+'</span></div><div class="storage-row"><span>Room Left</span><span class="'+(room>=0?'good':'bad')+'">'+room+'</span></div><div class="storage-row"><span>Idle Adults</span><span>'+game.jobs.idle+'</span></div></div></div><div class="panel"><h3>Food Pressure</h3><div class="content"><div class="storage-row"><span>Food Stored</span><span>'+formatWhole(game.resources.food)+'/'+formatWhole(game.storage.food)+'</span></div><div class="storage-row"><span>Food Produced</span><span class="good">+'+formatRate(p.food)+'/s</span></div><div class="storage-row"><span>Food Used</span><span class="bad">-'+formatRate(foodUse)+'/s</span></div><div class="storage-row"><span>Food Net</span><span class="'+(foodNet>=0?'good':'bad')+'">'+(foodNet>=0?'+':'')+formatRate(foodNet)+'/s</span></div></div></div><div class="panel"><h3>Basic Materials</h3><div class="content"><div class="storage-row"><span>Wood</span><span>'+formatWhole(game.resources.wood)+'/'+formatWhole(game.storage.wood)+'</span></div><div class="storage-row"><span>Stone</span><span>'+formatWhole(game.resources.stone)+'/'+formatWhole(game.storage.stone)+'</span></div><div class="box-sub always-info">Early growth is only food, shelter, and enough material to keep building.</div></div></div>';applyGameUiPass($('mainArea')||document)}
