function crestForStage(key){return{thorp:'?',hamlet:'¦',village:'?',mediumVillage:'?',bigVillage:'?',smallTown:'?',mediumTown:'?',bigTown:'?',fortifiedTown:'?',smallCity:'?',mediumCity:'?',bigCity:'?',smallKingdom:'?',mediumKingdom:'?',largeKingdom:'?'}[key]||'?'}
function eraAssetKey(key){
  if(key==='largeKingdom')return'empire';
  if(['smallKingdom','mediumKingdom'].includes(key))return'kingdom';
  if(['smallCity','mediumCity','bigCity'].includes(key))return'city';
  if(['smallTown','mediumTown','bigTown','fortifiedTown'].includes(key))return'town';
  if(['village','mediumVillage','bigVillage'].includes(key))return'village';
  if(key==='hamlet')return'hamlet';
  return'thorp';
}
function eraIconPath(key){return'assets/era-icons/'+eraAssetKey(key)+'.png'}
function dynamicSubtitleText(){const stage=getProgressionStage(),happy=getEffectiveHappiness(),fear=getEffectiveFear(),foodNet=earlyFoodNet?earlyFoodNet():getJobProduction().food-getFoodConsumption()-getFoodSpoilage();if(game.crisis?.active)return'A battered '+stage.label.toLowerCase()+' fighting its way back from collapse.';if(game.raidIncoming)return'A threatened '+stage.label.toLowerCase()+' rallying beneath the alarm bells.';if(foodNet<0&&!progressionAtLeast('hamlet'))return'A hungry thorp counting every loaf.';if(fear>=75&&happy<45)return'An oppressive '+stage.label.toLowerCase()+' facing constant turmoil.';if(happy>=75&&buildingCount('workshop')+buildingCount('market')+buildingCount('tavern')>=3)return'A flourishing '+stage.label.toLowerCase()+' with grand ambitions.';if(progressionAtLeast('smallKingdom'))return'An ambitious realm balancing rule, faith, and unrest.';if(progressionAtLeast('smallCity'))return'A growing city looking beyond its walls.';if(progressionAtLeast('smallTown'))return'A prosperous town discovering the cost of wealth.';if(progressionAtLeast('village'))return'A humble village with grand ambitions.';if(progressionAtLeast('hamlet'))return'A young hamlet learning to stand on its own.';return'A small thorp fighting for food and shelter.'}
const updateBrandTitleDashboardBase=updateBrandTitle;
updateBrandTitle=function(){updateBrandTitleDashboardBase();const stage=getProgressionStage(),crest=$('eraCrest')||document.querySelector('.brand-icon'),subtitle=$('dynamicSubtitle')||document.querySelector('.subtitle');if(crest){crest.textContent='';crest.dataset.era=stage.key;const img=document.createElement('img');img.className='crest-icon';img.alt='';img.src=eraIconPath(stage.key);img.onerror=()=>{crest.innerHTML='<span class="crest-mark">'+crestForStage(stage.key)+'</span>'};crest.appendChild(img)}if(subtitle)subtitle.textContent=dynamicSubtitleText()}
function optionList(options,selected){return options.map(([v,t,disabled])=>'<option value="'+v+'" '+(v===selected?'selected':'')+' '+(disabled?'disabled':'')+'>'+t+'</option>').join('')}
const JOB_ROLE_OPTIONS=[['idle','Idle'],['farmer','Farmer'],['woodcutter','Woodcutter'],['miner','Miner'],['builder','Builder'],['priest','Priest'],['grunt','Grunt'],['guard','Guard'],['soldier','Soldier'],['archer','Archer'],['scout','Scout'],['medic','Medic'],['sapper','Sapper']];
function jobRequirementText(job){if(['idle','farmer','woodcutter','miner','builder'].includes(job))return'Available from the start.';if(job==='priest')return'Requires a Shrine.';if(job==='grunt')return'Requires visible raid risk before a Barracks exists.';if(['guard','soldier','archer','scout','medic','sapper'].includes(job))return'Requires a Barracks.';return'Unknown requirement.'}
function dashboardClassOptions(){const opts=[['peasants','Peasant',false]];opts.push(['skilled',buildingCount('workshop')>0?'Skilled':'Undiscovered: Workshop required',buildingCount('workshop')<=0]);opts.push(['elites',eliteUnlocked()?'Elite':'Undiscovered: Mansion required',!eliteUnlocked()]);return opts}
