function renderDashboardPopulation(){const el=$('dashboardPopulationContent');if(!el)return;const opts=game.recruitOptions;if(opts.classType==='skilled'&&buildingCount('workshop')<=0)opts.classType='peasants';if(opts.classType==='elites'&&!eliteUnlocked())opts.classType='peasants';const amountOptions=[['1','+1'],['10','+10'],['100','+100'],['max','+Max'],['custom','Custom: '+(opts.customAmount||1)]],count=selectedRecruitCount(),cost=scaledCost(recruitClassCost(opts.classType),count);el.innerHTML='<div class="population-hero-number">'+game.population+' / '+game.housing+'</div><div class="hire-grid"><select class="select-control" id="dashRecruitAmount" aria-label="Hire amount">'+optionList(amountOptions,opts.amount)+'</select><select class="select-control" id="dashRecruitJob" aria-label="Hire role">'+optionList(dashboardJobOptions(),opts.job)+'</select><select class="select-control hire-wide" id="dashRecruitClass" aria-label="Hire requirement">'+optionList(dashboardClassOptions(),opts.classType)+'</select><button class="mini-btn save hire-wide" id="dashHireBtn">Hire</button></div><div class="cost-lines"><div>Cost for '+(opts.amount==='max'?'Max':count)+': '+formatCost(cost)+'</div><div>Gain: <span class="good">+'+(getBirthRate()+getPopulationMetrics().migrationToTown/100).toFixed(2)+'/s</span></div><div>Loss: <span class="bad">-'+(getMortalityRate()+getPopulationMetrics().migrationFromTown/100).toFixed(2)+'/s</span></div></div>';$('dashRecruitAmount').onchange=e=>{setRecruitOption('amount',e.target.value);renderDashboardPopulation();renderSettlementSummary()};$('dashRecruitJob').onchange=e=>{setRecruitOption('job',e.target.value);renderDashboardPopulation()};$('dashRecruitClass').onchange=e=>{setRecruitOption('classType',e.target.value);renderDashboardPopulation();renderSettlementSummary()};$('dashHireBtn').onclick=()=>{recruitVillagers(game.recruitOptions.amount);renderDashboardPopulation();renderSettlementSummary()}}
function renderWorldOverviewPanel(){const el=$('worldOverviewContent');if(!el)return;const stage=getProgressionStage(),season=currentSeason(),foodNet=getJobProduction().food-getFoodConsumption()-getFoodSpoilage();el.innerHTML='<div class="world-scene" role="img" aria-label="Medieval valley settlement overview"><div class="world-scene-content"><div class="world-kicker">Season</div><div class="world-season">'+season+'</div><div>Year '+game.year+' · Month '+game.month+' · Day '+game.day+'</div><div>'+stage.label+' · '+stage.focus+'</div></div></div><div class="storage-row"><span>Food Trend</span><span class="'+(foodNet<0?'bad':foodNet>.05?'good':'muted')+'">'+(foodNet<-.05?'Food Trend: Falling':foodNet>.05?'Food Trend: Rising':'Food Trend: Stable')+'</span></div><div class="storage-row"><span>Online Time</span><span>'+formatClock(game.time)+'</span></div>'}
function renderWellBeingPanel(){const el=$('wellBeingContent');if(!el)return;const happy=Math.round(getEffectiveHappiness()),fear=Math.round(getEffectiveFear()),fearColor=fear>=65?'var(--red)':fear>=30?'var(--gold-bright)':'#6f879f';el.innerHTML='<div class="wellbeing-grid"><div class="meter-card" title="Affects growth and migration."><div class="meter-label">Happiness</div><div class="meter-ring" style="--value:'+happy+';--meter-color:var(--green)"><span>'+happy+'%</span></div><div class="meter-desc">Affects growth and migration.</div></div><div class="meter-card" title="Controls crime but can raise disorder."><div class="meter-label">Fear</div><div class="meter-ring" style="--value:'+fear+';--meter-color:'+fearColor+'"><span>'+fear+'%</span></div><div class="meter-desc">Controls crime but can raise disorder.</div></div></div>'}
function tuneDashboardWorkerControls(){const idle=getIdleAgeCounts(),selected=game.jobAssignAge||'adults';document.querySelectorAll('[data-job-compact][data-dir="+"]').forEach(btn=>btn.disabled=(idle[selected]||0)<=0);document.querySelectorAll('[data-job-compact][data-dir="-"]').forEach(btn=>btn.disabled=(game.jobs[btn.dataset.jobCompact]||0)<=0);if($('workerCountBubble'))$('workerCountBubble').textContent=getAssignedWorkers()}
function renderDashboardMain(){if(activeTab!=='Main')return;renderDashboardPopulation();renderWorldOverviewPanel();renderWellBeingPanel();tuneDashboardWorkerControls()}
const renderSettlementSummaryDashboardBase=renderSettlementSummary;
renderSettlementSummary=function(){const out=renderSettlementSummaryDashboardBase();renderDashboardMain();return out}
const renderWorkersDashboardBase=renderWorkers;
renderWorkers=function(){renderWorkersDashboardBase();tuneDashboardWorkerControls()}
const renderEventsDashboardBase=renderEvents;
renderEvents=function(){renderEventsDashboardBase();if($('clearEventsBtn'))$('clearEventsBtn').onclick=()=>{game.logs=[];renderEvents()}}
function ensureTimeControl(){
  const defaults={paused:false,speed:1,allowedSpeeds:[.5,1,2,5]};
  game.timeControl=Object.assign(defaults,game.timeControl||{});
  game.timeControl.allowedSpeeds=defaults.allowedSpeeds.slice();
  game.timeControl.speed=Number(game.timeControl.speed)||1;
  if(!game.timeControl.allowedSpeeds.includes(game.timeControl.speed))game.timeControl.speed=1;
  game.timeControl.paused=!!game.timeControl.paused;
}
function renderTimeControls(){
  ensureTimeControl();
  if($('pauseBtn')){
    $('pauseBtn').textContent=game.timeControl.paused?'Resume':'Pause';
    $('pauseBtn').setAttribute('aria-pressed',game.timeControl.paused?'true':'false');
    $('pauseBtn').onclick=toggleGamePause;
  }
  document.querySelectorAll('[data-game-speed]').forEach(btn=>{
    const active=Number(btn.dataset.gameSpeed)===game.timeControl.speed;
    btn.classList.toggle('active',active);
    btn.setAttribute('aria-pressed',active?'true':'false');
    btn.onclick=()=>setGameSpeed(Number(btn.dataset.gameSpeed));
  });
  if($('pausedBadge'))$('pausedBadge').style.display=game.timeControl.paused?'inline-flex':'';
  document.body.classList.toggle('game-paused',game.timeControl.paused);
}
function toggleGamePause(){
  ensureTimeControl();
  game.timeControl.paused=!game.timeControl.paused;
  renderTimeControls();
  restartTick();
  saveGame(false);
}
function setGameSpeed(speed){
  ensureTimeControl();
  if(!game.timeControl.allowedSpeeds.includes(speed))return;
  game.timeControl.speed=speed;
  renderTimeControls();
  restartTick();
  saveGame(false);
}
function dashboardSelectors(){
  syncPopulationAccounting();
  const p=getJobProduction(),foodUse=getFoodConsumption()+getFoodSpoilage(),foodNet=p.food-foodUse,idle=getIdleAgeCounts(),stage=getProgressionStage(),housingOver=Math.max(0,game.population-game.housing),housingPct=game.housing>0?Math.min(100,Math.round(game.population/game.housing*100)):0,workers=getAssignedWorkers(),queue=(game.buildQueue||[]).length;
  return{p,foodUse,foodNet,idle,stage,housingOver,housingPct,workers,queue,total:game.population,housing:game.housing,adults:game.ages.adults||0,children:game.ages.children||0,elders:game.ages.elders||0};
}
function clickableLabel(text,key,extra=''){
  return'<button class="click-label '+extra+'" type="button" data-detail-key="'+key+'">'+text+'</button>';
}
function summaryStat(label,value,key,kind=''){
  return'<div class="summary-stat-row"><span>'+clickableLabel(label,key)+'</span><span class="'+kind+'">'+value+'</span></div>';
}
function renderDashboardPopulation(){
  const el=$('dashboardPopulationContent');
  if(!el)return;
  const d=dashboardSelectors(),opts=game.recruitOptions;
  if(!canHireJob(opts.job))opts.job='idle';
  if(opts.classType==='skilled'&&buildingCount('workshop')<=0)opts.classType='peasants';
  if(opts.classType==='elites'&&!eliteUnlocked())opts.classType='peasants';
  const amountOptions=[['1','+1'],['10','+10'],['100','+100'],['max','+Max'],['custom','Custom: '+(opts.customAmount||1)]],count=selectedRecruitCount(),cost=scaledCost(recruitClassCost(opts.classType),count),over=d.housingOver>0;
  el.innerHTML='<div class="labor-stat-grid">'+
    '<div class="stat-chip"><span class="stat-chip-label">'+clickableLabel('Population','stat:population')+'</span><span class="stat-chip-value '+(over?'bad':'')+'">'+d.total+' / '+d.housing+'</span></div>'+
    '<div class="stat-chip"><span class="stat-chip-label">'+clickableLabel('Adults','stat:adults')+'</span><span class="stat-chip-value">'+d.adults+'</span></div>'+
    '<div class="stat-chip"><span class="stat-chip-label">'+clickableLabel('Children','stat:children')+'</span><span class="stat-chip-value">'+d.children+'</span></div>'+
    '<div class="stat-chip"><span class="stat-chip-label">'+clickableLabel('Elders','stat:elders')+'</span><span class="stat-chip-value">'+d.elders+'</span></div>'+
    '<div class="stat-chip"><span class="stat-chip-label">'+clickableLabel('Idle Adults','stat:idleAdults')+'</span><span class="stat-chip-value">'+d.idle.adults+'</span></div>'+
    '<div class="stat-chip"><span class="stat-chip-label">'+clickableLabel('Workers Assigned','stat:workersAssigned')+'</span><span class="stat-chip-value">'+d.workers+'</span></div>'+
  '</div>'+
  '<div class="compact-hire-row"><select class="select-control" id="dashRecruitAmount" aria-label="Hire amount">'+optionList(amountOptions,opts.amount)+'</select><select class="select-control" id="dashRecruitJob" aria-label="Hire role">'+optionList(dashboardJobOptions(),opts.job)+'</select><select class="select-control" id="dashRecruitClass" aria-label="Hire requirement">'+optionList(dashboardClassOptions(),opts.classType)+'</select><button class="mini-btn save" id="dashHireBtn">Hire</button></div>'+
  '<div class="cost-lines"><span>Cost for '+(opts.amount==='max'?'Max':count)+': '+formatCost(cost)+'</span><span class="extra-info"> · Growth <span class="good">+'+(getBirthRate()+getPopulationMetrics().migrationToTown/100).toFixed(2)+'/s</span> · Loss <span class="bad">-'+(getMortalityRate()+getPopulationMetrics().migrationFromTown/100).toFixed(2)+'/s</span></span></div>';
  $('dashRecruitAmount').onchange=e=>{setRecruitOption('amount',e.target.value);renderDashboardPopulation();renderSettlementSummary()};
  $('dashRecruitJob').onchange=e=>{setRecruitOption('job',e.target.value);renderDashboardPopulation()};
  $('dashRecruitClass').onchange=e=>{setRecruitOption('classType',e.target.value);renderDashboardPopulation();renderSettlementSummary()};
  $('dashHireBtn').onclick=()=>{recruitVillagers(game.recruitOptions.amount);renderDashboardPopulation();renderWorkers();renderSettlementSummary()};
  bindDashboardDetails(el);
}
function renderCompactWorkers(){
  const el=$('workersContent');
  if(!el)return;
  const d=dashboardSelectors(),step=(game.jobAssignStep?.global||'1'),known=Object.fromEntries(getJobRows().map(j=>[j.key,j])),jobs=JOB_ROLE_OPTIONS.filter(([key])=>key!=='idle').map(([key,label])=>known[key]||{key,name:label+'s',note:jobRequirementText(key)});
  const stepOptions=[['1','1'],['5','5'],['10','10'],['100','100'],['custom','Custom'],['max','Max']];
  el.innerHTML='<div class="labor-toolbar"><label class="muted" for="globalJobStep">Assign Amount</label><select class="select-control worker-step" id="globalJobStep" aria-label="Assignment amount">'+optionHtml(stepOptions,step)+'</select></div><div class="worker-grid">'+jobs.map(j=>{
    const unlocked=canHireJob(j.key),count=unlocked?(game.jobs[j.key]||0):'?',name=unlocked?j.name:'Unknown',tip=unlocked?String(j.note||''):jobRequirementText(j.key),disabled=!unlocked,detail=unlocked?clickableLabel(name,'worker:'+j.key):'<span class="locked-job-label">Unknown</span>';
    return'<div class="worker-compact-row '+(unlocked?'':'locked-job-row')+'" data-ui-tip="'+tip.replace(/"/g,'&quot;')+'"><div class="worker-compact-name">'+detail+'<span class="muted extra-info">'+tip+'</span></div><div class="worker-count">'+count+'</div><button class="mini-btn icon-btn" data-job-compact="'+j.key+'" data-dir="-" '+(disabled||count<=0?'disabled':'')+' aria-label="Remove '+name+'">-</button><button class="mini-btn icon-btn" data-job-compact="'+j.key+'" data-dir="+" '+(disabled||d.idle.adults<=0?'disabled':'')+' aria-label="Assign '+name+'">+</button></div>';
  }).join('')+'</div>';
  if($('globalJobStep'))$('globalJobStep').onchange=()=>{game.jobAssignStep=game.jobAssignStep||{};game.jobAssignStep.global=$('globalJobStep').value;if(game.jobAssignStep.global==='custom'){const n=Math.max(1,Math.floor(Number(prompt('Assign/remove how many workers?','1'))||1));game.jobAssignCustomAmount=n}};
  el.querySelectorAll('[data-job-compact]').forEach(btn=>btn.onclick=()=>{
    const key=btn.dataset.jobCompact,raw=game.jobAssignStep.global||'1',value=raw==='custom'?String(game.jobAssignCustomAmount||1):raw;
    game.jobAssignAge='adults';
    assignJob(key,btn.dataset.dir==='+'?value:(value==='max'?'-max':-Number(value)));
  });
  bindDashboardDetails(el);
  bindRealTooltips(el);
}
function escapeHtml(value){return String(value??'').replace(/[&<>"']/g,ch=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[ch]))}
function seasonArtEraKey(){
  const key=getProgressionStage().key;
  if(key==='largeKingdom')return'empire';
  if(['smallKingdom','mediumKingdom'].includes(key))return'kingdom';
  if(['smallCity','mediumCity','bigCity'].includes(key))return'city';
  if(['smallTown','mediumTown','bigTown','fortifiedTown'].includes(key))return'town';
  if(['hamlet','village','mediumVillage','bigVillage'].includes(key))return'hamlet';
  return'thorp';
}
function seasonArtPath(){
  return'assets/seasons/'+seasonArtEraKey()+'-'+currentSeason().toLowerCase()+'.png';
}
function signedPercent(value){return(value>=0?'+':'')+Math.round(value*100)+'%'}
function seasonEffectDashboardText(sm){
  const parts=[];
  if(sm.production)parts.push(signedPercent(sm.production)+' food production');
  if(sm.foodUse)parts.push(signedPercent(sm.foodUse)+' food use');
  return sm.label+': '+(parts.length?parts.join(', '):'no active modifier');
}
function foodTrendText(foodNet){return foodNet<-.05?'Food Trend: Falling':foodNet>.05?'Food Trend: Rising':'Food Trend: Stable'}
function renderEventLogModal(){
  const rows=(game.logs&&game.logs.length?game.logs:['00:00 No events recorded.']).map(e=>{
    const p=splitEventLog(e);
    return'<div class="full-log-row"><div class="event-time">'+escapeHtml(p.time)+'</div><div class="event-text">'+escapeHtml(p.body)+'</div></div>';
  }).join('');
  showModal('Full Event History','<div class="box-sub always-info">Newest events are listed first. This log uses the same event state as Recent Events.</div><div class="rule"></div><div class="full-log-list">'+rows+'</div>');
}
function renderActiveEffectsModal(){
  const entries=activeEffectEntries();
  const rows=entries.length?entries.map(e=>{
    const detailList=e.details.length?'<ul class="detail-list">'+e.details.map(x=>'<li>'+escapeHtml(x)+'</li>').join('')+'</ul>':'';
    const fixes=e.fixes.length?'<div class="box-sub always-info"><b>How to reduce:</b></div><ul class="detail-list">'+e.fixes.map(x=>'<li>'+escapeHtml(x)+'</li>').join('')+'</ul>':'';
    return'<div class="full-effect-row"><h4>'+escapeHtml(e.title)+(e.value?' <span class="'+e.kind+'">'+escapeHtml(e.value)+'</span>':'')+'</h4><div class="box-sub always-info">'+escapeHtml(e.short)+'</div>'+detailList+fixes+'</div>';
  }).join(''):'<div class="full-effect-row"><h4>No Active Effects</h4><div class="box-sub always-info">No active gameplay modifiers are currently changing resources, people, happiness, fear, growth, labor, production, death, birth, migration, fatigue, or construction.</div></div>';
  showModal('Active Effects - Full Detail','<div class="box-sub always-info">This list intentionally excludes plain settings unless they currently modify gameplay.</div><div class="rule"></div><div class="full-effect-list">'+rows+'</div>');
}
function renderGrowthGuidance(){
  if(game.options.guidance===false)return'';
  const g=getGrowthGuidance();
  return'<button class="guidance-card compact-guidance" type="button" data-highlight-target="'+g.target+'" data-detail-key="guidance" title="'+g.detail.replace(/"/g,'&quot;')+'"><div><b>Best Move</b><span>'+g.label+'</span><span class="extra-info">'+g.detail+'</span></div></button>';
}
function renderWorldOverviewPanel(){
  const el=$('worldOverviewContent');
  if(!el)return;
  const season=currentSeason(),sm=seasonModifiers(),foodNet=getJobProduction().food-getFoodConsumption()-getFoodSpoilage(),path=seasonArtPath();
  el.innerHTML='<button class="world-scene season-'+season.toLowerCase()+' era-art-'+seasonArtEraKey()+'" type="button" data-detail-key="season" aria-label="Open season details" style="--season-art:url(&quot;'+path+'&quot;)"><div class="world-scene-content"><div class="world-kicker">Season</div><div class="world-season">'+season+'</div><div class="world-meta"><span>Year '+game.year+'</span><span>Month '+game.month+'</span><span>Day '+game.day+'</span></div></div></button><div class="storage-row"><span>'+clickableLabel('Season Effect','season')+'</span><span class="'+(sm.production<0||sm.foodUse>0?'gold':'good')+'">'+seasonEffectDashboardText(sm)+'</span></div><div class="storage-row"><span>'+clickableLabel('Food Trend','stat:foodNet')+'</span><span class="'+(foodNet<0?'bad':foodNet>.05?'good':'muted')+'">'+foodTrendText(foodNet)+'</span></div>';
  bindDashboardDetails(el);
}
function showSeasonDetails(){
  const s=currentSeason(),sm=seasonModifiers(),stage=getProgressionStage(),p=getJobProduction(),use=getFoodConsumption()+getFoodSpoilage();
  showModal('Season Details: '+s,'<div class="storage-row"><span>Current Season</span><span>'+s+'</span></div><div class="storage-row"><span>Season Type</span><span>'+sm.label+'</span></div><div class="storage-row"><span>Year</span><span>'+game.year+'</span></div><div class="storage-row"><span>Month</span><span>'+game.month+'</span></div><div class="storage-row"><span>Day</span><span>'+game.day+'</span></div><div class="storage-row"><span>Era</span><span>'+stage.label+' - '+stage.focus+'</span></div><div class="rule"></div><div class="storage-row"><span>Food Production Modifier</span><span class="'+(sm.production>=0?'good':'bad')+'">'+(sm.production>=0?'+':'')+Math.round(sm.production*100)+'%</span></div><div class="storage-row"><span>Food Use Modifier</span><span class="'+(sm.foodUse<=0?'good':'bad')+'">'+(sm.foodUse>=0?'+':'')+Math.round(sm.foodUse*100)+'%</span></div><div class="storage-row"><span>Current Food Produced</span><span class="good">+'+formatRate(p.food)+'/s</span></div><div class="storage-row"><span>Current Food Used</span><span class="bad">-'+formatRate(use)+'/s</span></div><div class="box-sub always-info">'+sm.desc+'</div><div class="rule"></div><div class="box-sub always-info">Season art source: '+seasonArtPath()+'. If the matching image file is present, the World Overview uses it automatically.</div>');
}
function renderDashboardMilestones(){
  const goals=[['Build 3 huts',buildingCount('hut'),3,'milestone:huts'],['Assign 2 farmers',game.jobs.farmer||0,2,'milestone:farmers'],['Survive first winter',(game.year>1&&game.month>=3)?1:0,1,'milestone:winter'],['Reach 50 population',Math.min(game.population,50),50,'milestone:population50']];
  return'<div class="mini-goals">'+goals.map(([label,now,max,key])=>'<button class="mini-goal '+(now>=max?'done':'')+'" type="button" data-detail-key="'+key+'">'+(now>=max?'Done: ':'')+label+' <b>'+now+'/'+max+'</b></button>').join('')+'</div>';
}
function renderCompactSettlementSummary(){
  const el=$('summaryContent');
  if(!el)return;
  const d=dashboardSelectors(),housingText=d.housingOver?d.housingOver+' over':Math.max(0,d.housing-d.total)+' open';
  let html=(game.options.guidance!==false?renderGrowthGuidance():'')+'<div class="summary-grid">'+
    summaryStat('Era',d.stage.label+' - '+d.stage.focus,'stat:era')+
    summaryStat('Population',d.total+' / '+d.housing,'stat:population',d.housingOver?'bad':'')+
    summaryStat('Housing',housingText,'stat:housing',d.housingOver?'bad':'good')+
    summaryStat('Workers Assigned',d.workers,'stat:workersAssigned')+
    summaryStat('Build Queue',d.queue+' project'+(d.queue===1?'':'s'),'stat:buildQueue',d.queue?'gold':'muted')+
    summaryStat('Injuries',game.injuries,'stat:injuries',game.injuries?'bad':'good')+
  '</div>'+renderDashboardMilestones();
  el.innerHTML=html;
  applyGrowthHighlight();
  bindDashboardDetails(el);
}
function activeEffectEntries(){
  const out=[],sm=seasonModifiers(),season=currentSeason(),d=dashboardSelectors(),crisis=game.crisis||{},meters=crisis.meters||{},cooldowns=crisis.cooldowns||{};
  const add=e=>out.push(Object.assign({kind:'',value:'',short:'',details:[],fixes:[]},e));
  if(crisis.active||crisis.recovery>0)add({key:'collapse',title:'Collapse Recovery',value:(crisis.recovery||0)+'s',kind:'bad',short:'Settlement is recovering from crisis.',details:['Recovery timer: '+(crisis.recovery||0)+'s','Stable ticks: '+(crisis.stableTicks||0)],fixes:['Keep food, housing, unrest, and disasters under control.']});
  if((meters.starvation||0)>0||cooldowns.starvation>0||(game.resources.food<=0&&game.population>0))add({key:'starvation',title:'Starvation',value:cooldowns.starvation>0?'cooldown '+formatClock(cooldowns.starvation).slice(3):Math.round(meters.starvation||100)+'%',kind:'bad',short:'Food shortage is harming population stability.',details:['Food stored: '+formatWhole(game.resources.food),'Food net: '+(d.foodNet>=0?'+':'')+formatRate(d.foodNet)+'/s','Mortality rate: '+getMortalityRate().toFixed(3)+'/s'],fixes:['Assign farmers.','Build food production or storage.','Stabilize food above 0. Each food consumed reduces the starvation meter by 1%.']});
  if(d.housingOver>0||(meters.housing||0)>0||cooldowns.housing>0)add({key:'housing',title:'Housing Pressure',value:cooldowns.housing>0?'cooldown '+formatClock(cooldowns.housing).slice(3):Math.round(meters.housing||((d.total/Math.max(1,d.housing))*100))+'%',kind:'bad',short:'Overcrowding is blocking clean growth.',details:['Population: '+d.total,'Housing: '+d.housing,'Over capacity: '+d.housingOver,'Empty slots reduce this crisis by 1% per slot each second.'],fixes:['Queue housing.','Pause hiring until housing catches up.']});
  Object.entries(cooldowns).filter(([k,v])=>v>0&&!['starvation','housing'].includes(k)).forEach(([k,v])=>add({key:'crisisCooldown:'+k,title:crisisLabel(k),value:'cooldown '+formatClock(v).slice(3),kind:'bad',short:'This crisis recently triggered and cannot trigger again until the cooldown ends.',details:['Cooldown left: '+formatClock(v).slice(3),'Meter: '+Math.round(meters[k]||0)+'%'],fixes:['Keep the requirement solved so the meter stays low after cooldown.']}));
  if(sm.production!==0||sm.foodUse!==0)add({key:'season',title:sm.label,value:seasonEffectDashboardText(sm).replace(sm.label+': ',''),kind:sm.production<0||sm.foodUse>0?'bad':'good',short:sm.desc,details:['Food production modifier: '+(sm.production>=0?'+':'')+Math.round(sm.production*100)+'%','Food use modifier: '+(sm.foodUse>=0?'+':'')+Math.round(sm.foodUse*100)+'%','Calendar: Year '+game.year+', Month '+game.month+', Day '+game.day],fixes:['Use seasonal upgrades and food storage before winter.']});
  const months=breakthroughMonthsLeft();if(months>0)add({key:'breakthrough',title:'Breakthrough',value:months+' mo',kind:'good',short:'New era momentum lowers costs temporarily.',details:['Building and upgrade costs are reduced for '+months+' more months.'],fixes:['Queue key infrastructure while the discount lasts.']});
  activeDisasterEntries().forEach(([k,t])=>add({key:'disaster:'+k,title:disasterDefs[k].name,value:t+'s',kind:'bad',short:disasterDefs[k].desc,details:[disasterCounterText(k),'Counter progress: '+Math.round(disasterCounterScore(k)*100)+'%'],fixes:['Use disaster response buttons or build dedicated counters.']}));
  Object.entries(game.edicts||{}).filter(([,v])=>v>0).forEach(([k,v])=>add({key:'edict:'+k,title:k.replace(/([A-Z])/g,' $1'),value:v+'s',kind:k==='festival'?'good':'bad',short:'Temporary edict is modifying society.',details:['Duration left: '+v+'s',policyOptionTip('law',k)||'Edicts alter production, happiness, fear, or food use.'],fixes:['Wait for the edict timer or offset its downside.']}));
  Object.entries(game.divineBuffs||{}).filter(([,v])=>v>0).forEach(([k,v])=>add({key:'divine:'+k,title:k.replace(/([A-Z])/g,' $1'),value:v+'s',kind:'good',short:'Divine power is modifying the settlement.',details:['Duration left: '+v+'s'],fixes:['Spend faith again after it expires.']}));
  Object.entries(game.rituals||{}).filter(([,v])=>v>0).forEach(([k,v])=>add({key:'ritual:'+k,title:k.replace(/([A-Z])/g,' $1'),value:v+'s',kind:'good',short:'Ritual is providing a stronger temporary modifier.',details:['Duration left: '+v+'s'],fixes:['Keep priests and faith income ready for future rituals.']}));
  if(game.policies.labor==='hard')add({key:'labor',title:'Hard Labor',value:'+10% output',kind:'bad',short:'+10% production, -8 happiness, +6 fear.',details:['Food, wood, stone, and building production are boosted.','Happiness falls and fear rises.'],fixes:['Switch to Balanced or Relaxed when stability drops.']});
  if(game.policies.labor==='relaxed')add({key:'labor',title:'Relaxed Labor',value:'-10% output',kind:'good',short:'Lower output, higher happiness.',details:['Food, wood, stone, and building production fall by 10%.','Happiness rises by 8.'],fixes:['Switch to Balanced or Hard Labor when output matters more.']});
  if(game.fatigue>0&&game.population>=25)add({key:'fatigue',title:'Fatigue',value:Math.round(game.fatigue)+'%',kind:game.fatigue>35?'bad':'',short:'Fatigue reduces clean labor output as the settlement grows.',details:['Current fatigue: '+Math.round(game.fatigue)+'%','Taverns and houses reduce fatigue pressure.'],fixes:['Build taverns or better homes.','Use relaxed labor if happiness can support it.']});
  const owned=ownedConquestCells().length;if(owned)add({key:'expansion',title:'Expansion Bonus',value:'+'+Math.round((getExpansionProductionMultiplier()-1)*100)+'%',kind:'good',short:'Held territories boost production.',details:['Held areas: '+owned,'Completed sectors: '+completedConquestSectors()],fixes:['Defend held areas during raids.']});
  return out;
}
