function showDashboardDetail(key){
  if(!key)return;
  if(key==='season'){showSeasonDetails();return}
  if(key==='panel:recentEvents'){renderEventLogModal();return}
  if(key==='panel:activeEffects'){renderActiveEffectsModal();return}
  if(key.startsWith('resource:')){showResourceDetails(key.slice(9));return}
  if(key.startsWith('worker:')){showJobDetails(key.slice(7));return}
  const d=dashboardDetailContent(key);
  showModal(d.title,d.html);
}
function bindDashboardDetails(root=document){
  root.querySelectorAll('[data-detail-key]').forEach(btn=>{btn.onclick=e=>{e.stopPropagation();showDashboardDetail(btn.dataset.detailKey)}});
  document.querySelectorAll('.resource-card').forEach(card=>{
    const title=card.querySelector('.resource-title');
    if(!title)return;
    const id=(card.id||'').replace('Card','').replace('Placeholder','');
    title.setAttribute('role','button');
    title.setAttribute('tabindex','0');
    title.onclick=e=>{e.stopPropagation();if(card.classList.contains('locked-resource'))showDashboardDetail('locked:'+id);else showDashboardDetail('resource:'+id)};
    title.onkeydown=e=>{if(e.key==='Enter'||e.key===' '){e.preventDefault();title.click()}};
  });
}
