function ensureBuilderStaffing(){if(!game.builderAutoReplace||game.jobs.builder>=1||game.raidIncoming)return false;syncPopulationAccounting();if(game.jobs.idle>0){assignWorkerRecords(game,{from:'idle',to:'builder',count:1});game.logs.unshift(eventStamp()+' A spare worker returned to builder duty.');refreshAll();return true}const fallback=['farmer','woodcutter','miner','priest','guard','scout','medic','archer','soldier'].find(j=>(game.jobs[j]||0)>0);if(fallback){assignWorkerRecords(game,{from:fallback,to:'builder',count:1});game.logs.unshift(eventStamp()+' A worker was reassigned from '+fallback+' to restore builder duty.');refreshAll();return true}if((game.ages.children||0)>0){moveExistingAdultToJob('builder','peasants');game.logs.unshift(eventStamp()+' A child was apprenticed early to restore builder duty.');refreshAll();return true}return false}
function processAging(){if(game.time%30!==0)return;const childRate=.04*(1+(game.modifiers.childGrowthBonus||0)),elderRate=.01;let grown=Math.min(game.ages.children||0,Math.random()<childRate?1:0);if(grown){const job=game.builderAutoReplace&&game.jobs.builder<1?'builder':takeQueuedChildJob();moveExistingAdultToJob(job,'peasants');game.logs.unshift(eventStamp()+' A child came of age as '+job+'.')}let retired=Math.min(game.ages.adults||0,Math.random()<elderRate?1:0);if(retired){ageWorkerRecords(game,{from:'adults',to:'elders',count:retired});rebalanceWorkforce();game.logs.unshift(eventStamp()+' An adult became an elder.')}if((game.ages.elders||0)>0&&Math.random()<.006){removeWorkerRecords(game,{age:'elders',count:1});game.logs.unshift(eventStamp()+' An elder passed away.')}}
function processPopulationChange(){if(!game.popProgress)game.popProgress={birth:0,migration:0,death:0};const m=getPopulationMetrics();game.popProgress.birth+=getBirthRate();game.popProgress.migration+=(m.migrationToTown-m.migrationFromTown)/100;game.popProgress.death+=getMortalityRate();while(game.popProgress.birth>=1){game.popProgress.birth--;addWorkerRecord(game,{age:'children',classType:'peasants',job:'idle'});queueChildJob(parentJobForChild());game.logs.unshift(eventStamp()+' A child was born.')}while(game.popProgress.migration>=1){game.popProgress.migration--;const job=game.builderAutoReplace&&game.jobs.builder<1?'builder':selectedHireJob();addAdultToJob(job,'peasants');game.logs.unshift(eventStamp()+' A migrant joined the hamlet as '+job+'.')}while(game.popProgress.migration<=-1&&game.population>0){game.popProgress.migration++;losePopulation(1);game.logs.unshift(eventStamp()+' A villager left the hamlet.')}while(game.popProgress.death>=1&&game.population>0){game.popProgress.death--;losePopulation(1);game.logs.unshift(eventStamp()+' Hardship claimed a villager.')}enforceChildAdultRatio()}
function processInjuries(){if(!game.injuryQueue)game.injuryQueue=[];const medicHeal=Math.ceil(game.jobs.medic*(.45+(game.modifiers.medicBonus||0)));if(medicHeal>0&&game.injuryQueue.length){let remaining=medicHeal;for(const q of game.injuryQueue){const heal=Math.min(q.count,remaining);q.count-=heal;remaining-=heal;game.injuries=Math.max(0,game.injuries-heal);if(remaining<=0)break}}game.injuryQueue.forEach(q=>q.timer--);game.injuryQueue=game.injuryQueue.filter(q=>{if(q.timer<=0){game.injuries=Math.max(0,game.injuries-q.count);return false}return q.count>0})}
function processSocialPressure(){const stage=getSocialStage();if(stage==='early'){game.crime=0;game.disorder=0;return}if(game.patrols>0)game.crime=clamp(game.crime-game.patrols*.05,0,100);const cd=getCrimeDisorderMetrics(),crimeRate=stage==='mid'?.025:.06,disorderRate=stage==='mid'?.018:.05;game.crime=clamp(game.crime+(cd.crimePressure-game.crime)*crimeRate,0,100);game.disorder=clamp(game.disorder+(cd.disorderPressure-game.disorder)*disorderRate,0,100)}
function processDissentFactions(){if(game.population<20||game.time%15!==0)return;const s=getSocietyMetrics(),risk=Math.max(0,(game.disorder-35)*.0008+(game.fear-55)*.00045-(s.loyalty-50)*.00035);if(Math.random()<risk){const split=Math.min(game.ages.adults||0,Math.max(2,Math.ceil(game.population*.04)));if(split>0){game.ages.adults=Math.max(0,(game.ages.adults||0)-split);game.population=Math.max(0,game.population-split);game.classes.peasants=Math.max(0,(game.classes.peasants||0)-split);game.world.hostileFactions=(game.world.hostileFactions||0)+1;game.threat=clamp(game.threat+12,0,100);rebalanceWorkforce();game.logs.unshift(eventStamp()+' Dissenters split off and formed a hostile faction. Raid threat increased.')}}}
function getFatigueDelta(){if(game.population<25)return -game.fatigue;const housingRelief=buildingCount('house')*.006,tavernRelief=buildingCount('tavern')*.01;return .05*(game.modifiers.fatigueReduction||1)-.02-housingRelief-tavernRelief}
