function processAdvisorEvents(){if(game.options.guidance===false)return;advisorEvent('thorp_start','Start by securing food and shelter. Mini goals help the thorp reach Hamlet safely.',game.population>=1);advisorEvent('first_winter','Winter is the first survival test. Keep food reserves above five per person or shift more workers to food.',game.year===1&&currentSeason()==='Winter');advisorEvent('hamlet_50','Hamlet reached. Workshop and housing pressure now matter more than raw clicking.',game.population>=50);advisorEvent('village_101','Small Village reached. Labor specialization, farms, and storage begin to define growth.',game.population>=101);advisorEvent('medium_village_500','Medium Village reached. Light social pressure starts soon; policies and health now matter more.',game.population>=500);advisorEvent('big_village_1500','Big Village reached. Prepare market infrastructure before the Town era wakes up crime and gold pressure.',game.population>=1500);advisorEvent('town_market','Town systems are awake: food should fade into the background unless disaster strikes.',progressionAtLeast('smallTown')&&game.hasMarket);advisorEvent('first_trade_route','First trade route opened. Gold can now fund building rushes, mercenaries, and disaster choices.',Object.values(game.trade?.routes||{}).some(Boolean));advisorEvent('first_disaster','Disasters are active problems, not just penalties. Use the response buttons or build counters.',activeDisasterEntries().length>0);advisorEvent('raid_awake','Your success is visible now. Named factions can raid, steal resources, or seize land.',game.raidAwakened);advisorEvent('fortified_ready','Fortified Town reached. Defense, scouts, and unit matchups now matter more than raw resources.',progressionAtLeast('fortifiedTown'));advisorEvent('conquest_ready','City expansion uses the world map: scout targets, then start conquest for land and production boosts.',progressionAtLeast('smallCity'));advisorEvent('first_conquest_win','First conquest secured. Each held area boosts production, but raids can steal territory back.',ownedConquestCells().length>0);advisorEvent('religion_ready','Governance and religion are late complexity systems. Choose laws carefully because faith is soft control.',progressionAtLeast('smallKingdom')||buildingCount('temple')>0)}
function gameTick(){syncPopulationAccounting();game.time++;processDisasters();updateThreat();updateTrade();game.calendarProgress+=DAYS_PER_SECOND;while(game.calendarProgress>=1){game.calendarProgress-=1;advanceCalendarDay()}Object.keys(game.edicts).forEach(k=>{if(game.edicts[k]>0)game.edicts[k]--});Object.keys(game.divineBuffs).forEach(k=>{if(game.divineBuffs[k]>0)game.divineBuffs[k]--});Object.keys(game.rituals).forEach(k=>{if(game.rituals[k]>0)game.rituals[k]--});updateReligion();processPopulationChange();processAging();processInjuries();checkProgressionBreakthrough();processAdvisorEvents();game.fatigue=clamp(game.fatigue+getFatigueDelta(),0,100);processSocialPressure();processDissentFactions();syncPopulationAccounting();applyBuildingEffects();rebalanceWorkforce();ensureBuilderStaffing();const p=getJobProduction();addResource('food',p.food-getFoodConsumption()-getFoodSpoilage());addResource('wood',p.wood);addResource('stone',p.stone);addResource('faith',p.faith);addResource('gold',getTradeGoldIncome());unlockedProgressionResources().forEach(r=>addResource(r,getProgressionResourceIncome(r)));processBuildQueue();if(game.time%20===0&&game.options.autosave)saveGame(false);syncPopulationAccounting();rebalanceWorkforce();ensureBuilderStaffing();updateAchievements();if(ensureActiveTabAllowed()){refreshAll();return}const dropdown=isDropdownActive(),plan=renderScheduler({activeTab,time:game.time,dropdownActive:dropdown});if(!dropdown&&plan.fullTab){if(activeTab==='Buildings')renderBuildingsTab();else if(activeTab==='Population')renderPopulationTab();else if(activeTab==='Deities')renderDeityTab();else if(activeTab==='Military')renderMilitaryTab();else if(activeTab==='Upgrades')renderUpgradesTab();else if(activeTab==='Trade')renderTradeTab();else if(activeTab==='Achievements')renderAchievementsTab();else if(activeTab==='Main')refreshAll()}renderResources();if(!dropdown)renderOverview();renderStorage();renderEvents();renderSeason();renderSettlementSummary();renderEffects();renderThreat();updateTabStates()}
window.WOODSTOCK_SYSTEMS=SYSTEM_MODULES;
